def _neurowraith_manual_import_timeout_seconds() -> float:
    raw_value = getattr(settings, "NEUROWRATH_MANUAL_IMPORT_TIMEOUT_SECONDS", 900)
    try:
        seconds = float(raw_value)
    except (TypeError, ValueError):
        seconds = 900.0
    return max(60.0, min(seconds, 5400.0))


def _neurowraith_manual_import_max_limit() -> int | None:
    raw_value = getattr(settings, "NEUROWRATH_MANUAL_IMPORT_MAX_LIMIT", 0)
    try:
        limit = int(raw_value)
    except (TypeError, ValueError):
        limit = 0
    if limit <= 0:
        return None
    return limit


def _normalize_neurowraith_limit(
    raw_value: Any,
    *,
    default: int | None = 10,
    allow_none: bool = False,
) -> tuple[int | None, bool]:
    if raw_value is None:
        normalized = None if allow_none else default
    else:
        try:
            normalized = int(raw_value)
        except (TypeError, ValueError):
            normalized = default

    if normalized is not None and normalized <= 0:
        normalized = None if allow_none else default

    if normalized is None:
        return None, False

    max_limit = _neurowraith_manual_import_max_limit()
    if max_limit is not None and normalized > max_limit:
        return max_limit, True
    return normalized, False


def _neurowraith_scheduler_enabled() -> bool:
    return bool(getattr(settings, "NEUROWRATH_SCHEDULER_ENABLED", True))


def _neurowraith_cron_token() -> str:
    return str(getattr(settings, "NEUROWRATH_CRON_TOKEN", "") or "").strip()


def _safe_neurowraith_timezone(value: str | None):
    candidate = str(value or "").strip() or NEUROWRATH_DEFAULT_TIMEZONE
    try:
        return ZoneInfo(candidate)
    except Exception:
        try:
            return ZoneInfo(NEUROWRATH_DEFAULT_TIMEZONE)
        except Exception:
            return timezone.utc


def _acquire_neurowraith_advisory_lock() -> tuple[bool, Any | None]:
    """Try to acquire a cross-process import lock using PostgreSQL advisory locks."""

    try:
        backend_name = engine.url.get_backend_name()
    except Exception:
        backend_name = ""
    if not str(backend_name).startswith("postgresql"):
        return True, None

    conn = engine.connect()
    try:
        acquired = bool(
            conn.execute(
                text("SELECT pg_try_advisory_lock(:key)").bindparams(
                    key=_NEUROWRATH_PG_ADVISORY_LOCK_KEY
                )
            ).scalar()
        )
    except Exception:
        try:
            conn.close()
        except Exception:
            pass
        raise

    if not acquired:
        try:
            conn.close()
        except Exception:
            pass
        return False, None

    return True, conn


def _release_neurowraith_advisory_lock(conn: Any | None) -> None:
    if conn is None:
        return
    try:
        conn.execute(
            text("SELECT pg_advisory_unlock(:key)").bindparams(
                key=_NEUROWRATH_PG_ADVISORY_LOCK_KEY
            )
        )
    except Exception:
        logger.exception("Failed to release NeuroWraith PostgreSQL advisory lock")
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _validate_neurowraith_cron_request(request: Request) -> None:
    expected = _neurowraith_cron_token()
    if not expected:
        raise HTTPException(
            status_code=503,
            detail="NeuroWraith cron token is not configured.",
        )
    provided = (
        request.headers.get(NEUROWRATH_CRON_HEADER)
        or request.query_params.get("token")
        or ""
    ).strip()
    if not provided or not hmac.compare_digest(provided, expected):
        raise HTTPException(status_code=401, detail="Invalid cron token.")


