def _slack_unknown_source_error(candidate: str) -> ValueError:
    return ValueError(
        f"Unknown source '{candidate}'. Supported sources: {_slack_supported_source_targets_text()}."
    )


def _slack_admin_base_url() -> str | None:
    host = str(getattr(settings, "ADMIN_CANONICAL_HOST", "") or "").strip()
    if not host:
        return None
    scheme = str(getattr(settings, "ADMIN_CANONICAL_SCHEME", "https") or "https").strip() or "https"
    return f"{scheme}://{host}"


def _slack_admin_links_text() -> str:
    base = _slack_admin_base_url()
    if not base:
        return ""
    return (
        f"<{base}/admin|Dashboard> | "
        f"<{base}/admin/neurowraith|NeuroWraith> | "
        f"<{base}/admin/facebook-marketplace|Facebook Marketplace>"
    )


