@functools.lru_cache(maxsize=1)
def _postgis_distance_enabled() -> bool:
    """Return ``True`` when PostGIS geography helpers are available."""

    try:
        dialect_name = getattr(engine.dialect, "name", "")
    except Exception:
        return False
    if not dialect_name or "postgresql" not in dialect_name:
        return False
    try:
        with engine.connect() as conn:
            conn.exec_driver_sql("SELECT postgis_version()")
    except Exception:
        return False
    return True
