@asynccontextmanager
async def lifespan(app: FastAPI):
    init_db()
    init_admin_db()
    ensure_comment_blocklist_defaults()
    try:
        backfilled = _backfill_facebook_marketplace_dealership_assignments()
    except Exception:
        logger.exception("Failed to backfill FBM dealership assignments")
        backfilled = 0
    if backfilled > 0:
        logger.info(
            "Backfilled %s FBM listing(s) with missing dealership assignment",
            backfilled,
        )
    async with anyio.create_task_group() as task_group:
        if _neurowraith_scheduler_enabled():
            task_group.start_soon(_neurowraith_scheduler_loop)
        else:
            logger.info(
                "NeuroWraith in-process scheduler disabled via NEUROWRATH_SCHEDULER_ENABLED"
            )
        try:
            yield
        finally:
            task_group.cancel_scope.cancel()


