def _normalize_admin_return_to(value: str | None, fallback: str) -> str:
    """Normalize admin return URLs to the expected lowercase routes."""

    if not value:
        return fallback

    try:
        parsed = urlsplit(value)
    except ValueError:
        return fallback

    if parsed.scheme or parsed.netloc:
        return fallback

    path = parsed.path or ""
    if not path.startswith("/"):
        return fallback

    segments = path.split("/")
    if (
        len(segments) >= 3
        and segments[1].casefold() == "admin"
        and segments[2].casefold() == "comments"
    ):
        segments[1] = "admin"
        segments[2] = "comments"
        path = "/".join(segments)

    normalized = urlunsplit(("", "", path, parsed.query, parsed.fragment))
    return normalized or fallback
def _normalize_comment_name(raw: str | None) -> str | None:
    if raw is None:
        return None
    cleaned = re.sub(r"\s+", " ", raw).strip()
    if not cleaned:
        return None
    return cleaned[:MAX_NAME_LENGTH]


def _normalize_comment_email(raw: str | None) -> str | None:
    if raw is None:
        return None
    cleaned = raw.strip()
    if not cleaned:
        return None
    if len(cleaned) > MAX_EMAIL_LENGTH:
        cleaned = cleaned[:MAX_EMAIL_LENGTH]
    return cleaned


def _normalize_comment_body(raw: str) -> str:
    text = raw.replace("\r\n", "\n").replace("\r", "\n")
    text = re.sub(r"\n{3,}", "\n\n", text)
    cleaned = text.strip()
    if len(cleaned) > MAX_COMMENT_LENGTH:
        cleaned = cleaned[:MAX_COMMENT_LENGTH].rstrip()
    return cleaned


def _generate_guest_identity() -> tuple[str, str]:
    number = secrets.randbelow(90000) + 10000
    guest_code = f"FREAK-{number}"
    display = f"FreakCommenter #{number}"
    return display, guest_code


def _normalize_for_blocklist(value: str) -> str:
    lowered = value.casefold()
    return re.sub(r"[^a-z0-9]+", " ", lowered)


def _match_blocked_terms(session: DBSession, body: str) -> list[str]:
    if CommentBlocklist is None:
        return []
    normalized_text = _normalize_for_blocklist(body)
    words = set(normalized_text.split())
    hits: list[str] = []
    for entry in session.exec(select(CommentBlocklist)).all():
        phrase = (entry.phrase or "").strip()
        if not phrase:
            continue
        normalized_phrase = _normalize_for_blocklist(phrase).strip()
        if not normalized_phrase:
            continue
        if " " in normalized_phrase:
            if normalized_phrase in normalized_text:
                hits.append(phrase)
        elif normalized_phrase in words:
            hits.append(phrase)
    return hits


def _comment_status_to_string(status: CommentStatus | str | None) -> str | None:
    if isinstance(status, CommentStatus):
        return status.value.lower()
    if isinstance(status, str):
        normalized = status.strip()
        return normalized.lower() or None
    return None


def _serialize_comment(
    comment: Comment,
    guest_code: str | None = None,
    reaction_summary: dict[str, Any] | None = None,
    replies: list[dict[str, Any]] | None = None,
    reply_count: int | None = None,
) -> dict[str, Any]:
    status_value = _comment_status_to_string(comment.status)
    summary = reaction_summary or {}
    counts = summary.get("counts") if isinstance(summary, dict) else None
    ordered_counts: dict[str, int] = {}
    total = 0
    if isinstance(counts, Mapping):
        for key in COMMENT_REACTION_CHOICES:
            value = counts.get(key)
            if value:
                coerced = int(value)
                ordered_counts[key] = coerced
                total += coerced
    elif isinstance(summary, Mapping):
        total = int(summary.get("total") or 0)
    if not ordered_counts and isinstance(summary, Mapping):
        raw_counts = summary.get("counts")
        if isinstance(raw_counts, Mapping):
            for key, value in raw_counts.items():
                try:
                    ordered_counts[str(key)] = int(value)
                except Exception:
                    continue
    if total == 0 and isinstance(summary, Mapping):
        try:
            total = int(summary.get("total") or 0)
        except Exception:
            total = 0
        if not total and ordered_counts:
            total = sum(ordered_counts.values())
    reply_total = reply_count
    if reply_total is None:
        stored = getattr(comment, "reply_count", None)
        reply_total = int(stored or 0)
    return {
        "id": comment.id,
        "car_id": comment.car_id,
        "display_name": comment.display_name,
        "email": comment.email,
        "body": comment.body,
        "status": status_value,
        "flagged": bool(comment.flagged),
        "flagged_reason": comment.flagged_reason,
        "created_at": comment.created_at,
        "updated_at": comment.updated_at,
        "parent_id": getattr(comment, "parent_id", None),
        "automation_source": getattr(comment, "automation_source", None),
        "guest_code": guest_code
        if guest_code is not None
        else getattr(comment, "guest_code", None),
        "reactions": {"total": total, "counts": ordered_counts},
        "reply_count": reply_total,
        "replies": replies or [],
    }


def _approved_comment_count(session: DBSession, car_id: int) -> int:
    stmt = select(func.count()).where(
        Comment.car_id == car_id,
        func.lower(Comment.status) == CommentStatus.APPROVED.value,
    )
    result = session.exec(stmt).one()
    return int(result or 0)


def _require_comment_car(session: DBSession, car_id: int) -> Car:
    car = session.get(Car, car_id)
    if not car or getattr(car, "deleted_at", None):
        raise HTTPException(status_code=404, detail="Not found")
    status = getattr(car, "auction_status", None)
    if isinstance(status, str) and status.upper() == REMOVED_STATUS:
        raise HTTPException(status_code=404, detail="Not found")
    return car


def _empty_comment_reaction_summary() -> dict[str, Any]:
    return {"total": 0, "counts": {}}


def _exec_comment_reaction_query(session: DBSession, stmt):
    try:
        return session.exec(stmt).all()
    except (ProgrammingError, OperationalError) as exc:
        comment_logger.warning(
            "Comment reactions query failed; ensuring schema", exc_info=exc
        )
        try:
            session.rollback()
        except Exception:
            pass
        try:
            init_db()
        except Exception as init_exc:
            comment_logger.error(
                "Unable to initialize comment reaction schema", exc_info=init_exc
            )
            return []
        try:
            return session.exec(stmt).all()
        except (ProgrammingError, OperationalError) as retry_exc:
            comment_logger.error(
                "Comment reactions query failed after schema initialization",
                exc_info=retry_exc,
            )
            try:
                session.rollback()
            except Exception:
                pass
            return []
    except Exception as unexpected:
        comment_logger.error("Unexpected comment reactions query failure", exc_info=unexpected)
        try:
            session.rollback()
        except Exception:
            pass
        return []


def _load_comment_reaction_summary(
    session: DBSession, comment_ids: Iterable[int]
) -> dict[int, dict[str, Any]]:
    if CommentReaction is None:
        return {}
    ids = [int(cid) for cid in comment_ids if isinstance(cid, int)]
    if not ids:
        return {}
    stmt = (
        select(
            CommentReaction.comment_id,
            CommentReaction.reaction,
            func.count().label("total"),
        )
        .where(CommentReaction.comment_id.in_(ids))
        .group_by(CommentReaction.comment_id, CommentReaction.reaction)
    )
    summary: dict[int, dict[str, Any]] = {}
    rows = _exec_comment_reaction_query(session, stmt)
    for comment_id, reaction, total in rows:
        cid = int(comment_id)
        bucket = summary.setdefault(cid, {"total": 0, "counts": {}})
        counts = bucket.setdefault("counts", {})
        reaction_key = str(reaction).strip().lower()
        try:
            coerced = int(total or 0)
        except Exception:
            coerced = 0
        if coerced <= 0:
            continue
        bucket["total"] = int(bucket.get("total", 0)) + coerced
        counts[reaction_key] = coerced
    return summary


def _load_comment_reaction_details(
    session: DBSession, comment_ids: Iterable[int]
) -> dict[int, list[dict[str, Any]]]:
    if CommentReaction is None:
        return {}
    ids = [int(cid) for cid in comment_ids if isinstance(cid, int)]
    if not ids:
        return {}
    stmt = (
        select(CommentReaction)
        .options(
            load_only(
                CommentReaction.id,
                CommentReaction.comment_id,
                CommentReaction.reaction,
                CommentReaction.ip_address,
                CommentReaction.created_at,
                CommentReaction.updated_at,
            )
        )
        .where(CommentReaction.comment_id.in_(ids))
        .order_by(CommentReaction.updated_at.desc())
    )
    details: dict[int, list[dict[str, Any]]] = {}
    rows = _exec_comment_reaction_query(session, stmt)
    for reaction in rows:
        cid = int(getattr(reaction, "comment_id", 0) or 0)
        if not cid:
            continue
        details.setdefault(cid, []).append(
            {
                "id": reaction.id,
                "reaction": getattr(reaction, "reaction", None),
                "ip_address": getattr(reaction, "ip_address", None),
                "created_at": getattr(reaction, "created_at", None),
                "updated_at": getattr(reaction, "updated_at", None),
            }
        )
    return details


def _load_comment_reply_counts(
    session: DBSession, parent_ids: Iterable[int]
) -> dict[int, int]:
    ids = [int(pid) for pid in parent_ids if isinstance(pid, int)]
    if not ids:
        return {}
    stmt = (
        select(Comment.parent_id, func.count().label("total"))
        .where(Comment.parent_id.in_(ids))
        .group_by(Comment.parent_id)
    )
    counts: dict[int, int] = {}
    for parent_id, total in session.exec(stmt).all():
        if parent_id is None:
            continue
        try:
            counts[int(parent_id)] = int(total or 0)
        except Exception:
            continue
    return counts


def _format_admin_timestamp(value: str | None) -> str:
    if not value:
        return "—"
    try:
        parsed = datetime.fromisoformat(value)
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=timezone.utc)
        return parsed.astimezone(timezone.utc).strftime("%Y-%m-%d %H:%M UTC")
    except Exception:
        return value


def _fetch_like_stats(
    session: DBSession,
    car_ids: Iterable[int | str],
    session_id: str | None,
) -> tuple[dict[int, int], set[int]]:
    if CarLike is None:
        return {}, set()
    normalized_ids: set[int] = set()
    for value in car_ids:
        if value is None:
            continue
        try:
            candidate = int(value)
        except (TypeError, ValueError):
            continue
        normalized_ids.add(candidate)
    if not normalized_ids:
        return {}, set()

    counts_result = (
        session.exec(
            select(CarLike.car_id, func.count(CarLike.id))
            .where(CarLike.car_id.in_(normalized_ids))
            .group_by(CarLike.car_id)
        )
        .mappings()
        .all()
    )
    count_map: dict[int, int] = {}
    for row in counts_result:
        car_id_value = row.get("car_id")
        if car_id_value is None:
            continue
        count_value = row.get("count_1")
        if count_value is None:
            # fallback for other SQL dialects naming the column "count"
            count_value = row.get("count")
        try:
            count_map[int(car_id_value)] = int(count_value or 0)
        except (TypeError, ValueError):
            count_map[int(car_id_value)] = 0

    liked_ids: set[int] = set()
    if session_id:
        liked_rows = session.exec(
            select(CarLike.car_id).where(
                CarLike.car_id.in_(normalized_ids), CarLike.session_id == session_id
            )
        ).all()
        for value in liked_rows:
            try:
                liked_ids.add(int(value))
            except (TypeError, ValueError):
                continue

    return count_map, liked_ids


