def _resolve_frontend_index() -> Path | None:
    frontend_base = Path(__file__).resolve().parent.parent / "frontend"
    dist_index = frontend_base / "dist" / "index.html"
    if dist_index.exists():
        return dist_index
    return None


@app.get("/robots.txt", response_class=PlainTextResponse, include_in_schema=False)
def robots_txt(request: Request) -> PlainTextResponse:
    base_url = _public_site_base_url(request)
    body = "\n".join(
        [
            "User-agent: *",
            "Allow: /",
            "Disallow: /admin",
            "Disallow: /agents",
            "Disallow: /dealer/",
            "Disallow: /dealer/login",
            "Disallow: /dealer/logout",
            "Disallow: /dealer/profile",
            "Disallow: /dealer/inventory",
            "Disallow: /api",
            "Disallow: /sqladmin",
            "Disallow: /internal",
            "",
            f"Sitemap: {base_url}/sitemap.xml",
            "",
        ]
    )
    return PlainTextResponse(body)


def _sitemap_lastmod(value: Any) -> str | None:
    parsed = _parse_iso_datetime(value)
    if parsed is None:
        return None
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
    return parsed.date().isoformat()


def _slugify_path_segment(value: Any) -> str:
    text = str(value or "").strip().lower()
    if not text:
        return ""
    slug = re.sub(r"[^a-z0-9]+", "-", text).strip("-")
    return slug


@app.get("/sitemap.xml", include_in_schema=False)
def sitemap_xml(request: Request) -> Response:
    base_url = _public_site_base_url(request)

    entries: list[tuple[str, str | None, str | None, str | None]] = [
        (f"{base_url}/", None, "daily", "1.0"),
        (f"{base_url}/dealership/apply", None, "weekly", "0.4"),
    ]

    seen_urls = {entry[0] for entry in entries}
    make_names: set[str] = set()
    if Car is not None:
        try:
            with DBSession(engine) as session:
                cars = session.exec(select(Car)).all()
        except Exception:
            cars = []

        for car in cars:
            car_id = getattr(car, "id", None)
            if car_id in (None, ""):
                continue
            deleted_at = getattr(car, "deleted_at", None)
            if deleted_at not in (None, ""):
                continue
            status_value = str(
                getattr(car, "status", None)
                or getattr(car, "auction_status", None)
                or ""
            ).strip().upper()
            if status_value == "REMOVED":
                continue
            make_name = str(getattr(car, "make", "") or "").strip()
            if make_name:
                make_names.add(make_name)
            loc = f"{base_url}/car/{car_id}"
            if loc in seen_urls:
                continue
            seen_urls.add(loc)
            lastmod = None
            for candidate in (
                getattr(car, "updated_at", None),
                getattr(car, "posted_at", None),
                getattr(car, "created_at", None),
            ):
                lastmod = _sitemap_lastmod(candidate)
                if lastmod:
                    break
            entries.append((loc, lastmod, "hourly", "0.8"))

    for make_name in sorted(make_names, key=lambda item: item.lower()):
        make_slug = _slugify_path_segment(make_name)
        if not make_slug:
            continue
        loc = f"{base_url}/make/{make_slug}"
        if loc in seen_urls:
            continue
        seen_urls.add(loc)
        entries.append((loc, None, "daily", "0.7"))

    lines = ['<?xml version="1.0" encoding="UTF-8"?>']
    lines.append('<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">')
    for loc, lastmod, changefreq, priority in entries:
        lines.append("  <url>")
        lines.append(f"    <loc>{escape(loc)}</loc>")
        if lastmod:
            lines.append(f"    <lastmod>{escape(lastmod)}</lastmod>")
        if changefreq:
            lines.append(f"    <changefreq>{escape(changefreq)}</changefreq>")
        if priority:
            lines.append(f"    <priority>{escape(priority)}</priority>")
        lines.append("  </url>")
    lines.append("</urlset>")
    return Response("\n".join(lines), media_type="application/xml")


