def _login_page(
    request: Request,
    *,
    template: str,
    title: str,
    error: str | None = None,
    status_code: int = 200,
):
    context = {"title": title, "error": error, "csrf": csrf_token(request)}
    response = templates.TemplateResponse(
        request,
        template,
        context,
        status_code=status_code,
    )
    response.set_cookie(
        "csrftoken",
        context["csrf"],
        samesite=getattr(settings, "SESSION_COOKIE_SAMESITE", "lax"),
        secure=bool(getattr(settings, "SESSION_COOKIE_SECURE", False)),
    )
    return response


async def _handle_login_submission(
    request: Request,
    *,
    template: str,
    title: str,
):
    form = dict(await request.form())
    token = _get_csrf_from_form(form)
    if token != request.session.get("csrf_token"):
        return _login_page(
            request,
            template=template,
            title=title,
            error="CSRF token invalid",
            status_code=400,
        )

    username = form.get("username", "")
    password = form.get("password", "")
    rate_key = _auth_rate_key(request, username if isinstance(username, str) else None)
    allowed, retry_after = AUTH_RATE_LIMITER.allow(rate_key)
    if not allowed:
        wait = int(retry_after or 0)
        message = (
            f"Too many login attempts. Try again in {wait}s."
            if wait
            else "Too many login attempts. Try again later."
        )
        return _login_page(
            request,
            template=template,
            title=title,
            error=message,
            status_code=429,
        )
    user = None
    if username and password and AdminUser is not None:
        with DBSession(engine) as s:
            user = s.exec(
                select(AdminUser).where(AdminUser.username == username)
            ).first()
            if (
                user
                and getattr(user, "is_active", True)
                and verify_password(password, user.password_hash)
            ):
                user.last_login_at = datetime.now(timezone.utc).isoformat()
                s.add(user)
                s.commit()
                s.refresh(user)
            else:
                user = None
    if (
        user is None
        and username
        and password
        and AdminUser is not None
        and username == settings.ADMIN_USER
        and password == settings.ADMIN_PASS
    ):
        with DBSession(engine) as s:
            existing = s.exec(
                select(AdminUser).where(AdminUser.username == username)
            ).first()
            if not existing:
                now = datetime.now(timezone.utc).isoformat()
                seeded = AdminUser(
                    username=username,
                    password_hash=hash_password(password),
                    is_active=True,
                    is_superuser=True,
                    can_add_cars=True,
                    created_at=now,
                    updated_at=now,
                    last_login_at=now,
                )
                s.add(seeded)
                s.commit()
                s.refresh(seeded)
                user = seeded
            elif verify_password(password, existing.password_hash):
                existing.last_login_at = datetime.now(timezone.utc).isoformat()
                s.add(existing)
                s.commit()
                s.refresh(existing)
                user = existing
    if user:
        AUTH_RATE_LIMITER.reset(rate_key)
        _set_admin_session(request, user)
        request.session["admin"] = True
        request.session["csrf_token"] = token_urlsafe(32)  # rotate token
        return RedirectResponse(url="/admin", status_code=303)

    AUTH_RATE_LIMITER.record_failure(rate_key)
    return _login_page(
        request,
        template=template,
        title=title,
        error="Invalid credentials",
        status_code=400,
    )


