                "LOWER(cars.description) LIKE :search ESCAPE '\\\' OR "
                "LOWER(cars.make) LIKE :search ESCAPE '\\\' OR "
                "LOWER(cars.model) LIKE :search ESCAPE '\\\' OR "
                "LOWER(cars.trim) LIKE :search ESCAPE '\\\' OR "
                "LOWER(cars.city) LIKE :search ESCAPE '\\\' OR "
                "LOWER(cars.state) LIKE :search ESCAPE '\\\' OR "
