def _facebook_marketplace_repair_image_candidates(
    *,
    primary_image_url: Any,
    images_json: Any,
) -> list[str]:
    return _facebook_marketplace_helpers_repair_image_candidates(
        primary_image_url=primary_image_url,
        images_json=images_json,
        parse_images=_parse_images,
    )


class _FacebookMarketplaceInMemoryUpload:
    def __init__(
        self,
        *,
        data: bytes,
        filename: str,
        content_type: str | None,
    ) -> None:
        self.filename = filename
        self.content_type = content_type or "application/octet-stream"
        self.file = BytesIO(data)


def _facebook_marketplace_is_storage_image_url(value: Any) -> bool:
    url_value = _facebook_text(value)
    if not url_value:
        return False
    if url_value.startswith("/uploads/"):
        return True
    assets_base_url = _facebook_text(getattr(settings, "ASSETS_BASE_URL", None))
    if assets_base_url:
        normalized_base = assets_base_url.rstrip("/")
        if url_value.startswith(f"{normalized_base}/"):
            return True
    r2_endpoint = _facebook_text(getattr(settings, "R2_ENDPOINT", None))
    r2_bucket = _facebook_text(getattr(settings, "R2_BUCKET", None))
    if r2_endpoint and r2_bucket:
        combined = f"{r2_endpoint.rstrip('/')}/{r2_bucket.strip('/')}"
        if url_value.startswith(f"{combined}/"):
            return True
    return False


def _facebook_marketplace_should_cache_image_to_cdn(value: Any) -> bool:
    url_value = _facebook_text(value)
    if not url_value or _facebook_marketplace_is_storage_image_url(url_value):
        return False
    parsed = urlparse(url_value)
    if parsed.scheme.lower() not in {"http", "https"}:
        return False
    host = (parsed.netloc or "").lower()
    return "fbcdn.net" in host or "facebook.com" in host


def _facebook_marketplace_image_filename_for_storage(
    *,
    image_url: str,
    listing_id: str | None,
    content_type: str | None,
) -> str:
    parsed = urlparse(image_url)
    suffix = (Path(parsed.path or "").suffix or "").strip().lower()
    if not re.fullmatch(r"\.[a-z0-9]{1,5}", suffix or ""):
        guessed = mimetypes.guess_extension(str(content_type or "").split(";")[0].strip())
        suffix = ".jpg" if guessed in {None, "", ".jpe"} else str(guessed).lower()
    if suffix not in {
        ".jpg",
        ".jpeg",
        ".png",
        ".webp",
        ".gif",
        ".bmp",
        ".avif",
        ".heic",
        ".heif",
    }:
        suffix = ".jpg"
    listing_key = re.sub(
        r"[^a-zA-Z0-9_-]+",
        "",
        _facebook_text(listing_id) or "",
    )
    if not listing_key:
        listing_key = token_urlsafe(8)
    return f"{listing_key}-{token_urlsafe(6)}{suffix}"


def _facebook_marketplace_download_image_for_storage(
    *,
    image_url: str,
    timeout_seconds: int,
) -> tuple[bytes, str | None] | None:
    request_timeout = max(2, int(timeout_seconds or 5))
    max_bytes = int(getattr(settings, "UPLOAD_MAX_BYTES", 0) or 0)
    if max_bytes <= 0:
        max_bytes = 10_485_760
    request_headers = {
        "User-Agent": _facebook_marketplace_user_agent(),
        "Accept": "image/avif,image/webp,image/apng,image/*,*/*;q=0.8",
        "Accept-Language": "en-US,en;q=0.9",
    }
    try:
        with requests.get(
            image_url,
            headers=request_headers,
            timeout=(2, request_timeout),
            allow_redirects=True,
            stream=True,
        ) as response:
            status_code = int(getattr(response, "status_code", 0) or 0)
            if status_code >= 400:
                return None
            content_type = str(response.headers.get("content-type") or "").strip().lower()
            if content_type and not content_type.startswith("image/"):
                return None
            chunks: list[bytes] = []
            size = 0
            for chunk in response.iter_content(chunk_size=64 * 1024):
                if not chunk:
                    continue
                size += len(chunk)
                if size > max_bytes:
                    return None
                chunks.append(chunk)
            if not chunks:
                return None
            return b"".join(chunks), content_type or None
    except requests.RequestException:
        return None


def _facebook_marketplace_cache_image_to_cdn(
    *,
    image_url: str,
    listing_id: str | None,
    timeout_seconds: int,
    category: str = "facebook-market",
) -> str | None:
    normalized_url = _facebook_text(image_url)
    if not normalized_url:
        return None
    if not _facebook_marketplace_should_cache_image_to_cdn(normalized_url):
        return normalized_url
    downloaded = _facebook_marketplace_download_image_for_storage(
        image_url=normalized_url,
        timeout_seconds=timeout_seconds,
    )
    if not downloaded:
        return None
    image_bytes, content_type = downloaded
    upload = _FacebookMarketplaceInMemoryUpload(
        data=image_bytes,
        filename=_facebook_marketplace_image_filename_for_storage(
            image_url=normalized_url,
            listing_id=listing_id,
            content_type=content_type,
        ),
        content_type=content_type,
    )
    return _save_upload(upload, category=category)


def _facebook_marketplace_repair_fetch_listing_images(
    *,
    listing_url: str,
    listing_id: str | None,
    request_headers: Mapping[str, str],
    timeout_seconds: int,
) -> dict[str, Any]:
    timeout_value = max(2, int(timeout_seconds or 5))

    def _fetch_once(
        *,
        candidate_url: str,
        candidate_headers: Mapping[str, str],
    ) -> dict[str, Any]:
        try:
            response = requests.get(
                candidate_url,
                headers=dict(candidate_headers),
                timeout=(2, timeout_value),
            )
        except requests.RequestException:
            return {"images": [], "status": "request_error"}
        status_code = int(getattr(response, "status_code", 0) or 0)
        if status_code >= 400:
            return {
                "images": [],
                "status": "http_error",
                "http_status": status_code,
            }
        payload = response.text or ""
        if _facebook_marketplace_html_is_temporarily_blocked(payload):
            return {
                "images": [],
                "status": "temporarily_blocked",
                "http_status": status_code,
            }
        detail = _facebook_marketplace_item_detail_from_html(
            payload,
            listing_id=listing_id,
            listing_url=candidate_url,
        )
        images = _facebook_extract_images(
            detail.get("images")
            or detail.get("pictures")
            or detail.get("photos")
            or detail.get("media")
            or detail.get("primary_listing_photo")
            or detail.get("primary_photo")
        )
        ordered = _facebook_marketplace_order_image_urls(images)
        if ordered:
            return {"images": ordered, "status": "ok", "http_status": status_code}
        if _facebook_marketplace_html_is_login_gate(payload):
            return {
                "images": [],
                "status": "login_gate",
                "http_status": status_code,
            }
        return {"images": [], "status": "no_images", "http_status": status_code}

    primary_result = _fetch_once(
        candidate_url=listing_url,
        candidate_headers=request_headers,
    )
    primary_status = _facebook_text(primary_result.get("status")) or ""
    if primary_status == "ok":
        return primary_result

    fallback_statuses = {"http_error", "request_error", "login_gate", "no_images"}
    if primary_status not in fallback_statuses:
        return primary_result
    mobile_listing_url = _facebook_marketplace_mobile_listing_url(
        listing_url=listing_url,
        listing_id=listing_id,
    )
    if not mobile_listing_url or _facebook_marketplace_urls_match(
        mobile_listing_url, listing_url
    ):
        return primary_result

    mobile_headers = dict(request_headers)
    mobile_headers["User-Agent"] = _FACEBOOK_MARKETPLACE_MOBILE_USER_AGENT
    mobile_headers.setdefault("Sec-Fetch-Site", "none")
    mobile_result = _fetch_once(
        candidate_url=mobile_listing_url,
        candidate_headers=mobile_headers,
    )
    mobile_status = _facebook_text(mobile_result.get("status")) or ""
    if mobile_status == "ok":
        merged = dict(mobile_result)
        merged["mobile_fallback_attempted"] = True
        merged["used_mobile_fallback"] = True
        return merged
    merged_primary = dict(primary_result)
    merged_primary["mobile_fallback_attempted"] = True
    merged_primary["mobile_fallback_status"] = mobile_status
    return merged_primary


def _facebook_marketplace_repair_existing_listing_images(
    *,
    enrich_from_listing_page: bool,
    timeout_seconds: int = 5,
    limit: int | None = None,
    target_car_ids: Iterable[int] | None = None,
    allow_cookie_retry: bool = True,
    cache_primary_to_cdn: bool = False,
    cdn_category: str = "facebook-market",
) -> dict[str, Any]:
    started_at = datetime.now(timezone.utc)
    started_perf = time.perf_counter()
    timeout_value = max(2, int(timeout_seconds or 5))
    limit_value = max(0, int(limit or 0))
    normalized_target_ids: list[int] = []
    if target_car_ids:
        target_seen: set[int] = set()
        for raw_id in target_car_ids:
            try:
                numeric_id = int(raw_id)
            except (TypeError, ValueError):
                continue
            if numeric_id <= 0 or numeric_id in target_seen:
                continue
            target_seen.add(numeric_id)
            normalized_target_ids.append(numeric_id)
    now_iso = datetime.now(timezone.utc).isoformat()

    base_headers = {
        "Accept": "application/json",
        "User-Agent": _facebook_marketplace_user_agent(),
        "Accept-Language": "en-US,en;q=0.9",
    }
    session_cookie = _facebook_marketplace_session_cookie()
    if session_cookie:
        base_headers["Cookie"] = session_cookie
    request_headers = _facebook_marketplace_item_request_headers(
        base_headers,
        allow_cookie=False,
    )
    request_headers_with_cookie = (
        _facebook_marketplace_item_request_headers(
            base_headers,
            allow_cookie=True,
        )
        if session_cookie and bool(allow_cookie_retry)
        else None
    )

    scanned = 0
    changed = 0
    canonicalized_url = 0
    primary_replaced = 0
    enriched_rows = 0
    unresolved_avatar = 0
    unsupported_primary_cleared = 0
    had_primary_before = 0
    had_any_image_candidates_before = 0
    no_primary_after = 0
    enrichment_attempted = 0
    enrichment_success = 0
    enrichment_no_images = 0
    enrichment_login_gate = 0
    enrichment_temporarily_blocked = 0
    enrichment_http_error = 0
    enrichment_request_error = 0
    skipped_missing_listing_url = 0
    creative_primary_before = 0
    enrichment_cookie_retry_attempted = 0
    enrichment_cookie_retry_success = 0
    enrichment_cookie_retry_temporarily_blocked = 0
    enrichment_mobile_fallback_attempted = 0
    enrichment_mobile_fallback_success = 0
    enrichment_skipped_after_temp_block = 0
    enrichment_aborted_due_temp_block = False
    consecutive_temp_blocked = 0
    cookie_retry_enabled = bool(request_headers_with_cookie)
    cookie_retry_disabled_due_temp_block = 0
    cdn_upload_attempted = 0
    cdn_upload_success = 0
    cdn_upload_failed = 0
    cdn_primary_replaced = 0
    cdn_cached_primary_by_source: dict[str, str | None] = {}
    cdn_cache_miss = object()
    sample_changes: list[str] = []

    source_expr = func.lower(func.coalesce(Car.source, ""))
    url_expr = func.lower(func.coalesce(Car.url, ""))
    image_expr = func.lower(func.coalesce(Car.image_url, ""))
    images_json_expr = func.lower(func.coalesce(Car.images_json, ""))
    source_filter = or_(
        source_expr.contains("facebook"),
        url_expr.contains("facebook.com/marketplace/item/"),
        image_expr.contains("fbcdn.net"),
        images_json_expr.contains("fbcdn.net"),
    )

    with DBSession(engine) as session:
        query = select(Car).where(source_filter).order_by(Car.id.asc())
        if normalized_target_ids:
            query = query.where(Car.id.in_(tuple(normalized_target_ids)))
        if limit_value > 0:
            query = query.limit(limit_value)
        rows = session.exec(query).all()

        for row in rows:
            scanned += 1
            old_url = _facebook_text(getattr(row, "url", None)) or None
            old_primary = _facebook_text(getattr(row, "image_url", None)) or None
            old_images_json = getattr(row, "images_json", None)
            old_extra_images = _parse_images(_facebook_text(old_images_json) or None)
            if old_primary:
                had_primary_before += 1
            if old_primary or old_extra_images:
                had_any_image_candidates_before += 1

            canonical_url = _facebook_marketplace_listing_url(
                {
                    "id": _facebook_text(getattr(row, "lot_number", None)),
                    "url": old_url,
                    "permalink": old_url,
                    "listing_url": old_url,
                }
            )
            listing_id = (
                _facebook_text(getattr(row, "lot_number", None))
                or _facebook_marketplace_listing_id_from_url(canonical_url or old_url)
            )

            ordered_images = _facebook_marketplace_repair_image_candidates(
                primary_image_url=old_primary,
                images_json=old_images_json,
            )
            top_candidate = ordered_images[0] if ordered_images else None
            top_candidate_is_avatar = _facebook_marketplace_is_profile_avatar_image_url(
                top_candidate
            )
            top_candidate_is_creative = _facebook_marketplace_is_creative_image_url(
                top_candidate
            )
            if top_candidate_is_creative:
                creative_primary_before += 1
            if (
                enrich_from_listing_page
                and (
                    not ordered_images
                    or top_candidate_is_avatar
                    or top_candidate_is_creative
                )
            ):
                if canonical_url:
                    if enrichment_aborted_due_temp_block:
                        enrichment_skipped_after_temp_block += 1
                        fetch_result = {"images": [], "status": "temporarily_blocked"}
                        fetch_status = "temporarily_blocked"
                    else:
                        enrichment_attempted += 1
                        fetch_result = _facebook_marketplace_repair_fetch_listing_images(
                            listing_url=canonical_url,
                            listing_id=listing_id,
                            request_headers=request_headers,
                            timeout_seconds=timeout_value,
                        )
                        if _coerce_truthy(fetch_result.get("mobile_fallback_attempted")):
                            enrichment_mobile_fallback_attempted += 1
                        if _coerce_truthy(fetch_result.get("used_mobile_fallback")):
                            enrichment_mobile_fallback_success += 1
                        fetch_status = _facebook_text(fetch_result.get("status")) or ""
                    if (
                        cookie_retry_enabled
                        and request_headers_with_cookie
                        and fetch_status in {"login_gate", "no_images"}
                    ):
                        enrichment_cookie_retry_attempted += 1
                        retry_result = _facebook_marketplace_repair_fetch_listing_images(
                            listing_url=canonical_url,
                            listing_id=listing_id,
                            request_headers=request_headers_with_cookie,
                            timeout_seconds=timeout_value,
                        )
                        if _coerce_truthy(retry_result.get("mobile_fallback_attempted")):
                            enrichment_mobile_fallback_attempted += 1
                        if _coerce_truthy(retry_result.get("used_mobile_fallback")):
                            enrichment_mobile_fallback_success += 1
                        retry_status = _facebook_text(retry_result.get("status")) or ""
                        if retry_status == "ok":
                            enrichment_cookie_retry_success += 1
                        elif retry_status == "temporarily_blocked":
                            enrichment_cookie_retry_temporarily_blocked += 1
                            cookie_retry_enabled = False
                            cookie_retry_disabled_due_temp_block += 1
                        fetch_result = retry_result
                        fetch_status = retry_status
                    if fetch_status == "ok":
                        enrichment_success += 1
                        consecutive_temp_blocked = 0
                    elif fetch_status == "no_images":
                        enrichment_no_images += 1
                        consecutive_temp_blocked = 0
                    elif fetch_status == "login_gate":
                        enrichment_login_gate += 1
                        consecutive_temp_blocked = 0
                    elif fetch_status == "temporarily_blocked":
                        enrichment_temporarily_blocked += 1
                        consecutive_temp_blocked += 1
                        if (
                            consecutive_temp_blocked
                            >= _FACEBOOK_MARKETPLACE_REPAIR_TEMP_BLOCK_CONSECUTIVE_LIMIT
                        ):
                            enrichment_aborted_due_temp_block = True
                    elif fetch_status == "http_error":
                        enrichment_http_error += 1
                        consecutive_temp_blocked = 0
                    elif fetch_status == "request_error":
                        enrichment_request_error += 1
                        consecutive_temp_blocked = 0
                    fetched_images = _facebook_extract_images(fetch_result.get("images"))
                    if fetched_images:
                        ordered_images = _facebook_marketplace_order_image_urls(
                            [*fetched_images, *ordered_images]
                        )
                        enriched_rows += 1
                else:
                    skipped_missing_listing_url += 1

            if ordered_images:
                new_primary = ordered_images[0]
                new_extra_images = ordered_images[1:]
                new_images_json = (
                    json.dumps(new_extra_images, ensure_ascii=False)
                    if new_extra_images
                    else None
                )
            elif _facebook_marketplace_is_profile_avatar_image_url(old_primary):
                new_primary = None
                new_images_json = None
            elif old_primary and not _facebook_marketplace_is_supported_image_url(old_primary):
                new_primary = None
                new_images_json = None
                unsupported_primary_cleared += 1
            else:
                new_primary = old_primary
                new_images_json = old_images_json

            if cache_primary_to_cdn and _facebook_text(new_primary):
                primary_source_url = _facebook_text(new_primary) or ""
                cached_primary = cdn_cached_primary_by_source.get(
                    primary_source_url,
                    cdn_cache_miss,
                )
                if cached_primary is cdn_cache_miss:
                    if _facebook_marketplace_should_cache_image_to_cdn(primary_source_url):
                        cdn_upload_attempted += 1
                        cached_primary = _facebook_marketplace_cache_image_to_cdn(
                            image_url=primary_source_url,
                            listing_id=listing_id,
                            timeout_seconds=timeout_value,
                            category=cdn_category,
                        )
                        if cached_primary and cached_primary != primary_source_url:
                            cdn_upload_success += 1
                        elif not cached_primary:
                            cdn_upload_failed += 1
                    else:
                        cached_primary = primary_source_url
                    cdn_cached_primary_by_source[primary_source_url] = (
                        str(cached_primary) if isinstance(cached_primary, str) else None
                    )
                cached_primary_text = (
                    str(cached_primary) if isinstance(cached_primary, str) else ""
                )
                if cached_primary_text and cached_primary_text != new_primary:
                    new_primary = cached_primary_text
                    cdn_primary_replaced += 1

            if _facebook_marketplace_is_profile_avatar_image_url(new_primary):
                unresolved_avatar += 1
            if not _facebook_text(new_primary):
                no_primary_after += 1

            row_changed = False
            if canonical_url and canonical_url != old_url:
                canonicalized_url += 1
                row_changed = True
            if new_primary != old_primary:
                primary_replaced += 1
                row_changed = True
            if _facebook_text(new_images_json) != _facebook_text(old_images_json):
                row_changed = True
            if not row_changed:
                continue

            changed += 1
            if len(sample_changes) < 20:
                old_primary_preview = (_facebook_text(old_primary) or "")[:72]
                new_primary_preview = (_facebook_text(new_primary) or "")[:72]
                sample_changes.append(
                    (
                        f"id={getattr(row, 'id', None)} "
                        f"primary: {old_primary_preview} -> {new_primary_preview}"
                    )
                )
            if canonical_url:
                row.url = canonical_url
            row.image_url = new_primary
            row.images_json = new_images_json
            row.updated_at = now_iso
            session.add(row)

        if changed:
            session.commit()

    finished_at = datetime.now(timezone.utc)
    duration_seconds = max(0.0, time.perf_counter() - started_perf)
    return {
        "started_at": started_at.isoformat(),
        "finished_at": finished_at.isoformat(),
        "duration_seconds": round(duration_seconds, 3),
        "target_ids_requested": len(normalized_target_ids),
        "target_ids_matched": scanned,
        "scanned": scanned,
        "changed": changed,
        "primary_replaced": primary_replaced,
        "canonicalized_url": canonicalized_url,
        "enriched_rows": enriched_rows,
        "still_avatar_primary": unresolved_avatar,
        "unsupported_primary_cleared": unsupported_primary_cleared,
        "had_primary_before": had_primary_before,
        "had_any_image_candidates_before": had_any_image_candidates_before,
        "no_primary_after": no_primary_after,
        "enrichment_attempted": enrichment_attempted,
        "enrichment_success": enrichment_success,
        "enrichment_no_images": enrichment_no_images,
        "enrichment_login_gate": enrichment_login_gate,
        "enrichment_temporarily_blocked": enrichment_temporarily_blocked,
        "enrichment_http_error": enrichment_http_error,
        "enrichment_request_error": enrichment_request_error,
        "skipped_missing_listing_url": skipped_missing_listing_url,
        "creative_primary_before": creative_primary_before,
        "enrichment_cookie_retry_attempted": enrichment_cookie_retry_attempted,
        "enrichment_cookie_retry_success": enrichment_cookie_retry_success,
        "enrichment_cookie_retry_temporarily_blocked": (
            enrichment_cookie_retry_temporarily_blocked
        ),
        "enrichment_mobile_fallback_attempted": (
            enrichment_mobile_fallback_attempted
        ),
        "enrichment_mobile_fallback_success": enrichment_mobile_fallback_success,
        "enrichment_skipped_after_temp_block": enrichment_skipped_after_temp_block,
        "enrichment_aborted_due_temp_block": enrichment_aborted_due_temp_block,
        "enrichment_cookie_retry_disabled_due_temp_block": (
            cookie_retry_disabled_due_temp_block
        ),
        "enrichment_cookie_retry_enabled": bool(
            request_headers_with_cookie and cookie_retry_enabled
        ),
        "cache_primary_to_cdn": bool(cache_primary_to_cdn),
        "cdn_category": str(cdn_category or "facebook-market"),
        "cdn_upload_attempted": cdn_upload_attempted,
        "cdn_upload_success": cdn_upload_success,
        "cdn_upload_failed": cdn_upload_failed,
        "cdn_primary_replaced": cdn_primary_replaced,
        "enrich_from_listing_page": bool(enrich_from_listing_page),
        "limit": limit_value,
        "sample_changes": sample_changes,
    }


def _facebook_marketplace_is_likely_vehicle_listing(
    payload: Mapping[str, Any],
    *,
    vehicle: Mapping[str, Any],
    title: str | None,
    description: str | None,
    year: int | None,
    mileage: int | None,
    explicit_make: str | None,
    explicit_model: str | None,
) -> bool:
    now_year = datetime.now(timezone.utc).year + 2
    year_signal = isinstance(year, int) and 1950 <= year <= now_year
    mileage_signal = isinstance(mileage, int) and 0 <= mileage <= 600_000
    explicit_make_model_signal = bool(_facebook_text(explicit_make) and _facebook_text(explicit_model))

    explicit_vehicle_fields = (
        "vehicle",
        "vehicle_make",
        "vehicle_model",
        "vehicle_year",
        "vin",
        "vehicle_vin",
        "mileage",
        "odometer",
        "transmission",
        "body_style",
        "fuel_type",
        "drivetrain",
    )
    explicit_vehicle_signal = any(
        _facebook_text(payload.get(field)) for field in explicit_vehicle_fields
    ) or any(_facebook_text(vehicle.get(field)) for field in explicit_vehicle_fields)

    title_text = _facebook_text(title) or ""
    description_text = _facebook_text(description) or ""
    combined_text = " ".join(part for part in (title_text, description_text) if part).lower()
    tokens = set(re.findall(r"[a-z0-9]+", combined_text))
    title_tokens = re.findall(r"[a-z0-9]+", title_text.lower())

    non_vehicle_signal = bool(tokens.intersection(_FACEBOOK_MARKETPLACE_NON_VEHICLE_HINT_TOKENS))
    size_pattern_signal = bool(
        re.search(r"\b(?:size|sz)\s*\d{1,2}(?:\.\d)?\b", combined_text)
    )
    vehicle_hint_signal = bool(tokens.intersection(_FACEBOOK_MARKETPLACE_VEHICLE_HINT_TOKENS))
    common_make_signal = bool(tokens.intersection(_FACEBOOK_MARKETPLACE_COMMON_MAKE_HINT_TOKENS))
    title_starts_with_make = bool(
        title_tokens and title_tokens[0] in _FACEBOOK_MARKETPLACE_COMMON_MAKE_HINT_TOKENS
    )

    strong_signal_count = sum(
        1
        for flag in (
            year_signal,
            mileage_signal,
            explicit_make_model_signal,
            explicit_vehicle_signal,
        )
        if flag
    )

    if non_vehicle_signal or size_pattern_signal:
        if strong_signal_count < 2 and not mileage_signal and not explicit_vehicle_signal:
            return False

    if strong_signal_count > 0:
        return True

    if title_starts_with_make and len(title_tokens) >= 2:
        return True
    if common_make_signal and vehicle_hint_signal:
        return True
    return False


def _facebook_synthetic_vin(
    explicit_vin: str | None,
    *,
    listing_id: str | None,
    url: str | None,
    title: str | None,
) -> str:
    normalized_vin = _normalize_vin(explicit_vin)
    if normalized_vin:
        return normalized_vin
    seed_source = listing_id or url or title
    seed = re.sub(r"[^A-Z0-9]", "", str(seed_source or "").upper())
    if not seed:
        return ""
    seed = (seed + ("0" * 14))[:14]
    return f"FBM{seed}"


def _normalize_facebook_marketplace_item(raw: Mapping[str, Any]) -> dict[str, Any] | None:
    if not isinstance(raw, Mapping):
        return None
    payload = dict(raw)
    vehicle = payload.get("vehicle")
    if not isinstance(vehicle, Mapping):
        vehicle = {}
    marketplace_seller = payload.get("marketplace_listing_seller")
    if not isinstance(marketplace_seller, Mapping):
        marketplace_seller = {}

    listing_id = _facebook_marketplace_listing_id(payload)
    title = _facebook_text(
        payload.get("title")
        or payload.get("name")
        or payload.get("marketplace_listing_title")
        or payload.get("custom_title")
    )
    url = _facebook_marketplace_listing_url(payload)
    explicit_vin = _facebook_text(
        payload.get("vin")
        or payload.get("vehicle_vin")
        or vehicle.get("vin")
        or vehicle.get("vehicle_vin")
    )
    vin = _facebook_synthetic_vin(
        explicit_vin,
        listing_id=listing_id,
        url=url,
        title=title,
    )
    if not vin:
        return None

    year = _facebook_coerce_int(
        payload.get("year")
        or payload.get("vehicle_year")
        or vehicle.get("year")
        or vehicle.get("vehicle_year")
    )
    if year is None and title:
        year_match = re.search(r"\b(19|20)\d{2}\b", title)
        if year_match:
            try:
                year = int(year_match.group(0))
            except ValueError:
                year = None

    explicit_make = _facebook_text(
        payload.get("make") or payload.get("vehicle_make") or vehicle.get("make")
    )
    explicit_model = _facebook_text(
        payload.get("model") or payload.get("vehicle_model") or vehicle.get("model")
    )
    make = explicit_make
    model = explicit_model
    if title and (not make or not model):
        tokens = [token for token in re.findall(r"[A-Za-z0-9]+", title) if token]
        if tokens and re.fullmatch(r"(19|20)\d{2}", tokens[0]):
            tokens = tokens[1:]
        if tokens and not make:
            make = tokens[0]
        if len(tokens) >= 2 and not model:
            model = tokens[1]

    price_payload = (
        payload.get("price")
        or payload.get("list_price")
        or payload.get("asking_price")
        or payload.get("listing_price")
        or vehicle.get("price")
    )
    currency = _facebook_text(payload.get("currency") or payload.get("currency_code"))
    price = _facebook_coerce_float(price_payload)
    if isinstance(price_payload, Mapping):
        if price is None:
            price = _facebook_coerce_float(
                price_payload.get("amount")
                or price_payload.get("value")
                or price_payload.get("price")
            )
        if not currency:
            currency = _facebook_text(
                price_payload.get("currency")
                or price_payload.get("currency_code")
            )

    subtitle_mileage = None
    subtitle_candidates = payload.get("custom_sub_titles_with_rendering_flags")
    if isinstance(subtitle_candidates, list):
        for entry in subtitle_candidates:
            if not isinstance(entry, Mapping):
                continue
            subtitle_mileage = _facebook_mileage_from_text(
                entry.get("subtitle") or entry.get("text")
            )
            if subtitle_mileage is not None:
                break

    mileage = _facebook_coerce_int(
        payload.get("mileage")
        or payload.get("odometer")
        or vehicle.get("mileage")
        or vehicle.get("odometer")
    )
    if mileage is None:
        mileage = subtitle_mileage
    if mileage is None:
        mileage = _facebook_mileage_from_text(
            payload.get("mileage_text")
            or payload.get("odometer_text")
            or payload.get("odometer_reading")
            or payload.get("subtitle")
        )
    if mileage is None and title:
        mileage = _facebook_mileage_from_text(title)
    raw_location = payload.get("location") or vehicle.get("location")
    city, state, address, latitude, longitude = _facebook_location_parts(raw_location, payload)
    description = _facebook_text(
        payload.get("description")
        or payload.get("details")
        or payload.get("marketplace_listing_description")
    )
    seller_name = _facebook_text(
        payload.get("seller_name")
        or payload.get("seller")
        or payload.get("page_name")
        or payload.get("owner_name")
        or marketplace_seller.get("name")
    )

    images = _facebook_extract_images(
        payload.get("images")
        or payload.get("pictures")
        or payload.get("photos")
        or payload.get("media")
        or payload.get("primary_listing_photo")
        or payload.get("primary_photo")
    )
    images = _facebook_marketplace_order_image_urls(images)
    image_url = images[0] if images else None
    images_json = json.dumps(images[1:], ensure_ascii=False) if len(images) > 1 else None
    posted_at = _facebook_marketplace_posted_at_iso(payload)

    if not title:
        title = f"Facebook Marketplace Listing {listing_id or vin}"
    if payload.get("is_hidden") is True or payload.get("is_pending") is True:
        return None
    if payload.get("is_sold") is True:
        return None
    is_live = payload.get("is_live")
    if isinstance(is_live, bool) and not is_live:
        return None
    if price is not None and price <= 0:
        return None
    if not _facebook_marketplace_is_likely_vehicle_listing(
        payload,
        vehicle=vehicle,
        title=title,
        description=description,
        year=year,
        mileage=mileage,
        explicit_make=explicit_make,
        explicit_model=explicit_model,
    ):
        return None

    return {
        "vin": vin,
        "make": make,
        "model": model,
        "year": year,
        "price": price,
        "currency": currency or "USD",
        "mileage": mileage,
        "city": city,
        "state": state,
        "latitude": latitude,
        "longitude": longitude,
        "location_address": address,
        "auction_status": "LIVE",
        "lot_number": listing_id,
        "description": description,
        "image_url": image_url,
        "images_json": images_json,
        "posted_at": posted_at,
        "source": _FACEBOOK_MARKETPLACE_SOURCE,
        "url": url,
        "title": title,
        "seller_name": seller_name,
    }


async def import_facebook_marketplace(
    payload: FacebookMarketplaceImportRequest,
    request: Request,
):
    if not _facebook_marketplace_import_enabled():
        raise HTTPException(status_code=404, detail="Facebook Marketplace import is disabled")

    raw_items: list[dict[str, Any]]
    inline_items = payload.listings if isinstance(payload.listings, list) else None
    request_options = (
        dict(payload.request_options)
        if isinstance(payload.request_options, Mapping)
        else None
    )
    if inline_items:
        raw_items = [item for item in inline_items if isinstance(item, dict)]
    else:
        feed_url = _facebook_text(payload.feed_url) or _facebook_text(
            getattr(settings, "FACEBOOK_MARKETPLACE_FEED_URL", None)
        )
        access_token = _facebook_text(payload.access_token) or _facebook_text(
            getattr(settings, "FACEBOOK_MARKETPLACE_ACCESS_TOKEN", None)
        )
        if not feed_url:
            if request_options:
                feed_url = _FACEBOOK_MARKETPLACE_GRAPHQL_ENDPOINT
            else:
                raise HTTPException(
                    status_code=400,
                    detail=(
                        "No Marketplace source was provided. Use the search form "
                        "or configure a backend feed URL."
                    ),
                )
        if not _facebook_marketplace_fetch_lock.acquire(blocking=False):
            raise HTTPException(
                status_code=429,
                detail=(
                    "Facebook Marketplace fetch is already running. "
                    "Wait for the current run to finish, then retry."
                ),
            )
        try:
            try:
                raw_items = await anyio.to_thread.run_sync(
                    _fetch_facebook_marketplace_items,
                    feed_url,
                    access_token,
                    int(payload.limit),
                    _facebook_marketplace_timeout_seconds(),
                    request_options,
                )
            except ValueError as exc:
                message = str(exc)
                lowered = message.lower()
                upstream_issue = (
                    "facebook returned html" in lowered
                    or "response was not valid json" in lowered
                    or "facebook graphql rejected the request" in lowered
                    or "facebook marketplace search returned an error" in lowered
                    or "facebook marketplace search endpoint failed" in lowered
                    or "facebook marketplace fetch timed out before listing data was returned" in lowered
                    or "expecting value" in lowered
                )
                raise HTTPException(
                    status_code=502 if upstream_issue else 400,
                    detail=message,
                )
            except requests.RequestException as exc:
                raise HTTPException(
                    status_code=502,
                    detail=f"Marketplace feed request failed: {exc}",
                )
        finally:
            _facebook_marketplace_fetch_lock.release()

    normalized: list[dict[str, Any]] = []
    normalize_skipped = 0
    skip_reasons: dict[str, int] = {}
    skip_details: list[dict[str, str]] = []
    limit = int(payload.limit)
    for raw in raw_items[:limit]:
        record = _normalize_facebook_marketplace_item(raw)
        if record:
            normalized.append(record)
        else:
            normalize_skipped += 1
            _increment_reason_counter(skip_reasons, "normalize_failed")
            _slack_record_skip_detail(skip_details, "normalize_failed", raw)
    query_filter = None
    if isinstance(request_options, Mapping):
        query_filter, _ = _facebook_request_options_query_category(request_options)
    normalized, query_filtered = _facebook_marketplace_filter_records_by_query(
        normalized,
        query_filter,
        skip_details=skip_details,
    )
    normalize_skipped += query_filtered
    _increment_reason_counter(skip_reasons, "query_filtered_out", query_filtered)

    if not normalized:
        return {
            "fetched": len(raw_items),
            "prepared": 0,
            "inserted": 0,
            "updated": 0,
            "skipped": normalize_skipped,
            "skip_reasons": skip_reasons,
            "skip_details": list(skip_details),
            "dealership_id": payload.dealership_id,
        }

    dealership_override = payload.dealership_id if payload.dealership_id is not None else None
    inserted, updated, import_skipped, resolved_dealership_id = _import_car_items(
        request,
        normalized,
        file_name="facebook_marketplace.json",
        name=(payload.import_name or "Facebook Marketplace Import"),
        dealership_hint=(
            str(dealership_override) if dealership_override is not None else None
        ),
        dealership_id_override=dealership_override,
        actor_override="facebook_integration",
        skip_reason_counts=skip_reasons,
        skip_details=skip_details,
    )
    return {
        "fetched": len(raw_items),
        "prepared": len(normalized),
        "inserted": inserted,
        "updated": updated,
        "skipped": normalize_skipped + import_skipped,
        "skip_reasons": skip_reasons,
        "skip_details": list(skip_details),
        "dealership_id": resolved_dealership_id,
    }

async def public_site_password_check(payload: SitePasswordSubmission) -> SitePasswordResult:
    with DBSession(admin_engine) as s:
        rows = s.exec(
            text(
                """
                SELECT key, value FROM settings
                WHERE key IN ('site_password_enabled','site_password_hash','site_password_version')
                """
            )
        ).mappings().all()
    data = {row["key"]: row["value"] for row in rows}
    enabled = (
        _coerce_truthy(data.get("site_password_enabled"))
        if "site_password_enabled" in data
        else False
    )
    version_value = str(
        data.get("site_password_version") or DEFAULT_SITE_PASSWORD_VERSION
    )
    if not enabled:
        return SitePasswordResult(ok=True, enabled=False, version=version_value)
    candidate = (payload.password or "").strip()
    stored_hash = data.get("site_password_hash") or ""
    if stored_hash and verify_password(candidate, stored_hash):
        return SitePasswordResult(ok=True, enabled=True, version=version_value)
    return SitePasswordResult(
        ok=False,
        enabled=True,
        version=version_value,
        error="Incorrect password",
    )


def public_settings():
    cache_key = build_cache_key("public:settings")
    cached = cache_get_json(cache_key)
    if cached is not None:
        return cached
    payload = _load_public_settings()
    cache_set_json(cache_key, payload, ttl_seconds=settings.CACHE_TTL_SECONDS)
    return payload


def _dashboard_int(value: Any) -> int:
    try:
        return int(value or 0)
    except (TypeError, ValueError):
        return 0


def _dashboard_source_key(value: Any) -> str:
    text = str(value or "").strip().lower()
    if not text:
        return "unknown"
    return re.sub(r"\s+", "_", text)


def _dashboard_source_label(source_key: str) -> str:
    labels = {
        "unknown": "Unknown",
        "bringatrailer": "Bring A Trailer",
        "carsandbids": "Cars & Bids",
        "pca": "PCA Mart",
        "facebook_marketplace": "Facebook Marketplace",
        "manual": "Manual",
    }
    return labels.get(source_key, source_key.replace("_", " ").title())


def _dashboard_status_key(value: Any) -> str:
    text = str(value or "").strip().upper()
    if not text:
        return "LIVE"
    return text.replace("-", "_").replace(" ", "_")


def _dashboard_status_label(status_key: str) -> str:
    if status_key == REMOVED_STATUS:
        return "Removed"
    return status_key.replace("_", " ").title()


def _dashboard_badge_for_status(status_key: str) -> str:
    if status_key == REMOVED_STATUS:
        return "error"
    if status_key in {"LIVE", AUCTION_STATUS_IN_PROGRESS}:
        return "success"
    return "info"


def _dashboard_timestamp_label(value: str | None, tz: ZoneInfo) -> str:
    dt = _parse_iso_datetime(value)
    if not dt:
        return "-"
    return dt.astimezone(tz).strftime("%b %d, %Y %I:%M %p %Z")


def _dashboard_default_snapshot(window_hours: int = 24) -> dict[str, Any]:
    base = {
        "window_hours": max(int(window_hours or 24), 1),
        "generated_at": "-",
        "kpis": {
            "total_listings": 0,
            "active_listings": 0,
            "new_24h": 0,
            "updated_24h": 0,
            "removed_24h": 0,
            "sources_active": 0,
        },
        "source_rows": [],
        "status_rows": [],
        "scraper_rows": [],
        "recent_imports": [],
        "alerts": [],
    }
    base["kpi_cards"] = _dashboard_kpi_cards(base["kpis"])
    return base


def _admin_dashboard_snapshot(window_hours: int = 24) -> dict[str, Any]:
    snapshot = _dashboard_default_snapshot(window_hours=window_hours)
    if Car is None:
        return snapshot

    hours = snapshot["window_hours"]
    cutoff = datetime.now(timezone.utc) - timedelta(hours=hours)
    cutoff_iso = _to_utc_iso(cutoff) or ""
    schedule_tz = _safe_neurowraith_timezone(None)
    snapshot["generated_at"] = datetime.now(schedule_tz).strftime("%b %d, %Y %I:%M %p %Z")

    try:
        with DBSession(engine) as session:
            schedule = _load_neurowraith_schedule(session)
            schedule_tz = _safe_neurowraith_timezone(schedule.get("timezone"))
            snapshot["generated_at"] = datetime.now(schedule_tz).strftime(
                "%b %d, %Y %I:%M %p %Z"
            )

            schedule_spiders = schedule.get("spiders") or {}
            enabled_spiders = {
                source["spider"]
                for source in NEUROWRATH_SOURCES
                if bool((schedule_spiders.get(source["spider"]) or {}).get("enabled"))
            }

            non_deleted_filters = [or_(Car.deleted_at.is_(None), Car.deleted_at == "")]
            active_filters = [
                *non_deleted_filters,
                func.upper(func.coalesce(Car.auction_status_column(), "")) != REMOVED_STATUS,
            ]

            snapshot["kpis"]["total_listings"] = _dashboard_int(
                session.exec(
                    select(func.count()).select_from(Car).where(*non_deleted_filters)
                ).one()
            )
            snapshot["kpis"]["active_listings"] = _dashboard_int(
                session.exec(select(func.count()).select_from(Car).where(*active_filters)).one()
            )
            snapshot["kpis"]["new_24h"] = _dashboard_int(
                session.exec(
                    select(func.count())
                    .select_from(Car)
                    .where(*active_filters)
                    .where(Car.created_at >= cutoff_iso)
                ).one()
            )
            snapshot["kpis"]["updated_24h"] = _dashboard_int(
                session.exec(
                    select(func.count())
                    .select_from(Car)
                    .where(*active_filters)
                    .where(Car.updated_at >= cutoff_iso)
                ).one()
            )
            snapshot["kpis"]["removed_24h"] = _dashboard_int(
                session.exec(
                    select(func.count())
                    .select_from(Car)
                    .where(*non_deleted_filters)
                    .where(func.upper(func.coalesce(Car.auction_status_column(), "")) == REMOVED_STATUS)
                    .where(Car.updated_at >= cutoff_iso)
                ).one()
            )

            source_expr = func.lower(func.trim(func.coalesce(Car.source, "")))
            source_rows_raw = session.exec(
                select(source_expr, func.count())
                .select_from(Car)
                .where(*active_filters)
                .group_by(source_expr)
                .order_by(func.count().desc(), source_expr.asc())
            ).all()
            active_total = max(snapshot["kpis"]["active_listings"], 0)
            for source_value, count_value in source_rows_raw:
                source_key = _dashboard_source_key(source_value)
                count_int = _dashboard_int(count_value)
                share = (count_int / active_total * 100.0) if active_total else 0.0
                snapshot["source_rows"].append(
                    {
                        "source_key": source_key,
                        "source_label": _dashboard_source_label(source_key),
                        "count": count_int,
                        "share": share,
                    }
                )
            snapshot["kpis"]["sources_active"] = len(snapshot["source_rows"])

            status_expr = func.upper(func.trim(func.coalesce(Car.auction_status_column(), "")))
            status_rows_raw = session.exec(
                select(status_expr, func.count())
                .select_from(Car)
                .where(*non_deleted_filters)
                .group_by(status_expr)
                .order_by(func.count().desc(), status_expr.asc())
            ).all()
            for status_value, count_value in status_rows_raw:
                status_key = _dashboard_status_key(status_value)
                snapshot["status_rows"].append(
                    {
                        "status_key": status_key,
                        "status_label": _dashboard_status_label(status_key),
                        "count": _dashboard_int(count_value),
                        "badge_class": _dashboard_badge_for_status(status_key),
                    }
                )

            if NeuroWraithRun is not None:
                window_rows = session.exec(
                    select(
                        NeuroWraithRun.spider,
                        func.count(),
                        func.sum(case((NeuroWraithRun.succeeded.is_(True), 1), else_=0)),
                        func.sum(func.coalesce(NeuroWraithRun.inserted, 0)),
                        func.sum(func.coalesce(NeuroWraithRun.updated, 0)),
                    )
                    .where(NeuroWraithRun.started_at >= cutoff_iso)
                    .where(NeuroWraithRun.run_type.in_(NEUROWRATH_IMPORT_RUN_TYPES))
                    .group_by(NeuroWraithRun.spider)
                ).all()

                window_stats: dict[str, dict[str, int]] = {}
                for spider, run_count, success_count, inserted_count, updated_count in window_rows:
                    spider_key = str(spider or "").strip()
                    if not spider_key:
                        continue
                    window_stats[spider_key] = {
                        "run_count": _dashboard_int(run_count),
                        "success_count": _dashboard_int(success_count),
                        "inserted_count": _dashboard_int(inserted_count),
                        "updated_count": _dashboard_int(updated_count),
                    }

                source_rows: list[dict[str, str]] = list(NEUROWRATH_SOURCES)

                for source in source_rows:
                    spider = source["spider"]
                    stats = window_stats.get(
                        spider,
                        {
                            "run_count": 0,
                            "success_count": 0,
                            "inserted_count": 0,
                            "updated_count": 0,
                        },
                    )
                    run_count = stats["run_count"]
                    success_count = stats["success_count"]

                    latest_run = session.exec(
                        select(NeuroWraithRun)
                        .where(NeuroWraithRun.spider == spider)
                        .where(NeuroWraithRun.run_type.in_(NEUROWRATH_IMPORT_RUN_TYPES))
                        .order_by(NeuroWraithRun.started_at.desc())
                    ).first()
                    latest_failed = session.exec(
                        select(NeuroWraithRun)
                        .where(NeuroWraithRun.spider == spider)
                        .where(NeuroWraithRun.run_type.in_(NEUROWRATH_IMPORT_RUN_TYPES))
                        .where(NeuroWraithRun.started_at >= cutoff_iso)
                        .where(NeuroWraithRun.succeeded.is_(False))
                        .order_by(NeuroWraithRun.started_at.desc())
                    ).first()
                    latest_health_check = session.exec(
                        select(NeuroWraithRun)
                        .where(NeuroWraithRun.spider == spider)
                        .where(NeuroWraithRun.run_type == NEUROWRATH_HEALTHCHECK_RUN_TYPE)
                        .order_by(NeuroWraithRun.started_at.desc())
                    ).first()

                    if run_count <= 0:
                        health_label = "Idle"
                        health_badge = "info"
                        success_pct = None
                    else:
                        success_pct = int(round((success_count / max(run_count, 1)) * 100))
                        if success_count == run_count:
                            health_label = "Healthy"
                            health_badge = "success"
                        elif success_count == 0:
                            health_label = "Failing"
                            health_badge = "error"
                        else:
                            health_label = "Degraded"
                            health_badge = "info"

                    last_run_value = None
                    if latest_run is not None:
                        last_run_value = latest_run.finished_at or latest_run.started_at
                    last_error = ""
                    if latest_failed and isinstance(latest_failed.error, str):
                        last_error = latest_failed.error.strip()
                    if not last_error:
                        last_error = "None"

                    health_check_label = "Not checked"
                    health_check_badge = "info"
                    health_check_last_run = "-"
                    health_check_error = "None"
                    health_check_items = 0
                    if latest_health_check is not None:
                        health_check_value = (
                            latest_health_check.finished_at or latest_health_check.started_at
                        )
                        health_check_last_run = _dashboard_timestamp_label(
                            health_check_value, schedule_tz
                        )
                        health_check_items = max(
                            _dashboard_int(getattr(latest_health_check, "inserted", 0)), 0
                        )
                        if latest_health_check.succeeded:
                            health_check_label = "Pass"
                            health_check_badge = "success"
                        else:
                            health_check_label = "Fail"
                            health_check_badge = "error"
                            if isinstance(latest_health_check.error, str):
                                error_value = latest_health_check.error.strip()
                                if error_value:
                                    health_check_error = error_value

                    enabled = spider in enabled_spiders
                    snapshot["scraper_rows"].append(
                        {
                            "source_label": source.get("label", spider),
                            "spider": spider,
                            "enabled": enabled,
                            "run_count": run_count,
                            "success_count": success_count,
                            "success_pct": success_pct,
                            "inserted_count": stats["inserted_count"],
                            "updated_count": stats["updated_count"],
                            "last_run": _dashboard_timestamp_label(last_run_value, schedule_tz),
                            "last_error": last_error,
                            "health_label": health_label,
                            "health_badge": health_badge,
                            "health_check_label": health_check_label,
                            "health_check_badge": health_check_badge,
                            "health_check_last_run": health_check_last_run,
                            "health_check_error": health_check_error,
                            "health_check_items": health_check_items,
                        }
                    )

                    if enabled and run_count == 0:
                        snapshot["alerts"].append(
                            {
                                "level": "error",
                                "message": (
                                    f"{source.get('label', spider)} has no runs in the last {hours} hours."
                                ),
                            }
                        )
                    elif enabled and run_count > 0 and success_count == 0:
                        snapshot["alerts"].append(
                            {
                                "level": "error",
                                "message": (
                                    f"{source.get('label', spider)} has 0% success in the last {hours} hours."
                                ),
                            }
                        )

            if CarImport is not None:
                import_rows = session.exec(
                    select(CarImport)
                    .order_by(CarImport.uploaded_at.desc())
                    .limit(8)
                ).all()
                for imp in import_rows:
                    uploaded_value = getattr(imp, "uploaded_at", None)
                    uploaded_display = _dashboard_timestamp_label(uploaded_value, schedule_tz)
                    if uploaded_display == "-" and isinstance(uploaded_value, str):
                        uploaded_display = uploaded_value.strip() or "-"
                    name_value = (
                        getattr(imp, "name", None)
                        or getattr(imp, "file_name", None)
                        or f"Import #{getattr(imp, 'id', '')}"
                    )
                    snapshot["recent_imports"].append(
                        {
                            "id": getattr(imp, "id", None),
                            "name": str(name_value),
                            "car_count": _dashboard_int(getattr(imp, "car_count", 0)),
                            "uploaded_at": uploaded_display,
                        }
                    )
    except (OperationalError, ProgrammingError, NoInspectionAvailable) as exc:
        logger.warning("Admin dashboard snapshot query failed", exc_info=exc)

    if not snapshot["source_rows"] and snapshot["kpis"]["active_listings"] > 0:
        snapshot["alerts"].append(
            {
                "level": "info",
                "message": "Active listings exist, but no source labels were found.",
            }
        )

    if snapshot["kpis"]["active_listings"] == 0:
        snapshot["alerts"].append(
            {
                "level": "info",
                "message": "No active listings are currently available.",
            }
        )

    snapshot["kpi_cards"] = _dashboard_kpi_cards(snapshot["kpis"])
    return snapshot


def _dashboard_kpi_cards(kpis: Mapping[str, int]) -> list[dict[str, Any]]:
    return [
        {
            "label": "Listings (non-deleted)",
            "value": _dashboard_int(kpis.get("total_listings")),
            "hint": "Current inventory rows excluding soft-deleted items.",
        },
        {
            "label": "Active listings",
            "value": _dashboard_int(kpis.get("active_listings")),
            "hint": "Listings not marked REMOVED.",
        },
        {
            "label": "New in 24h",
            "value": _dashboard_int(kpis.get("new_24h")),
            "hint": "Listings created in the last 24 hours.",
        },
        {
            "label": "Updated in 24h",
            "value": _dashboard_int(kpis.get("updated_24h")),
            "hint": "Listings touched in the last 24 hours.",
        },
        {
            "label": "Removed in 24h",
            "value": _dashboard_int(kpis.get("removed_24h")),
            "hint": "Listings set to REMOVED in the last 24 hours.",
        },
        {
            "label": "Active sources",
            "value": _dashboard_int(kpis.get("sources_active")),
            "hint": "Distinct sources with active listings.",
        },
    ]


def _format_dashboard_job_elapsed(created_at_value: Any) -> str:
    try:
        created_at = float(created_at_value or 0.0)
    except (TypeError, ValueError):
        created_at = 0.0
    if created_at <= 0:
        return "-"
    return f"{max(0, int(time.time() - created_at))}s"


def _format_dashboard_job_timestamp(value: Any) -> str:
    try:
        ts = float(value or 0.0)
    except (TypeError, ValueError):
        ts = 0.0
    if ts <= 0:
        return "-"
    return datetime.fromtimestamp(ts, tz=timezone.utc).strftime("%Y-%m-%d %H:%M:%S UTC")


def _admin_safe_next_url(next_value: Any, *, fallback: str = "/admin") -> str:
    target = str(next_value or "").strip()
    if not target:
        return fallback
    if not target.startswith("/"):
        return fallback
    if not target.startswith("/admin"):
        return fallback
    return target


def _freakops_job_result_summary(system: str, job: Mapping[str, Any]) -> str:
    def _to_int(value: Any) -> int:
        try:
            return int(value)
        except (TypeError, ValueError):
            return 0

    if system == "NeuroWraith":
        result_raw = job.get("result")
        result = dict(result_raw) if isinstance(result_raw, Mapping) else {}
        if result:
            inserted = _to_int(result.get("inserted"))
            updated = _to_int(result.get("updated"))
            skipped = _to_int(result.get("skipped"))
            return f"Inserted {inserted}, updated {updated}, skipped {skipped}"
    if system == "Facebook Marketplace":
        job_kind = _facebook_marketplace_job_kind(job)
        result_raw = job.get("result")
        result = dict(result_raw) if isinstance(result_raw, Mapping) else {}
        if result:
            if job_kind == "picture_fix":
                scanned = _to_int(result.get("scanned"))
                changed = _to_int(result.get("changed"))
                primary_replaced = _to_int(result.get("primary_replaced"))
                no_primary_after = _to_int(result.get("no_primary_after"))
                return (
                    f"Scanned {scanned}, changed {changed}, primary replaced "
                    f"{primary_replaced}, no primary after fix {no_primary_after}"
                )
            fetched = _to_int(result.get("fetched"))
            prepared = _to_int(result.get("prepared"))
            inserted = _to_int(result.get("inserted"))
            updated = _to_int(result.get("updated"))
            skipped = _to_int(result.get("skipped"))
            return (
                f"Fetched {fetched}, prepared {prepared}, "
                f"inserted {inserted}, updated {updated}, skipped {skipped}"
            )
        summary_raw = job.get("preview_summary")
        summary = dict(summary_raw) if isinstance(summary_raw, Mapping) else {}
        if summary:
            fetched = _to_int(summary.get("fetched"))
            prepared = _to_int(summary.get("prepared"))
            normalize_skipped = _to_int(summary.get("normalize_skipped"))
            return (
                f"Fetched {fetched}, prepared {prepared}, "
                f"normalize skipped {normalize_skipped}"
            )
    if bool(job.get("stop_forced")):
        return "Force-stopped by admin"
    return "-"


def _freakops_job_rows(
    *,
    include_done: bool,
    limit: int = 200,
) -> list[dict[str, Any]]:
    def _created_ts(record: Mapping[str, Any]) -> float:
        try:
            return float(record.get("created_at") or 0.0)
        except (TypeError, ValueError):
            return 0.0

    statuses = None if include_done else {"pending", "running"}
    rows: list[dict[str, Any]] = []

    for neurowraith_job in _neurowraith_job_list(statuses=statuses, limit=limit):
        job_id = str(neurowraith_job.get("job_id") or "").strip()
        payload = neurowraith_job.get("payload")
        payload_map = dict(payload) if isinstance(payload, Mapping) else {}
        spider = str(payload_map.get("spider") or "").strip() or "-"
        status_value = str(neurowraith_job.get("status") or "running").lower()
        rows.append(
            {
                "job_id": job_id,
                "system": "NeuroWraith",
                "section": "neurowraith",
                "status": status_value,
                "is_done": status_value in {"succeeded", "failed"},
                "message": str(neurowraith_job.get("message") or "").strip()
                or "NeuroWraith import is running...",
                "subject": spider,
                "elapsed": _format_dashboard_job_elapsed(neurowraith_job.get("created_at")),
                "started_at": _format_dashboard_job_timestamp(neurowraith_job.get("created_at")),
                "updated_at": _format_dashboard_job_timestamp(neurowraith_job.get("updated_at")),
                "stop_url": f"/admin/neurowraith/jobs/{job_id}/stop" if job_id else "",
                "stop_requested": bool(neurowraith_job.get("stop_requested")),
                "stop_forced": bool(neurowraith_job.get("stop_forced")),
                "result_summary": _freakops_job_result_summary("NeuroWraith", neurowraith_job),
                "open_url": f"/admin/neurowraith?tab={spider}" if spider and spider != "-" else "/admin/neurowraith",
                "open_label": "Open NeuroWraith",
                "sort_ts": _created_ts(neurowraith_job),
            }
        )

    for marketplace_job in _facebook_marketplace_job_list(statuses=statuses, limit=limit):
        job_id = _facebook_text(marketplace_job.get("job_id"))
        payload = marketplace_job.get("payload")
        payload_map = dict(payload) if isinstance(payload, Mapping) else {}
        job_kind = _facebook_marketplace_job_kind(marketplace_job)
        query = _facebook_text(payload_map.get("query")) or "-"
        if job_kind == "picture_fix":
            query = "Fix Pictures"
        status_value = str(marketplace_job.get("status") or "running").lower()
        preview_token = _facebook_text(marketplace_job.get("preview_token"))
        rows.append(
            {
                "job_id": job_id,
                "system": "Facebook Marketplace",
                "section": "imports",
                "status": status_value,
                "is_done": status_value in {"succeeded", "failed"},
                "message": _facebook_text(marketplace_job.get("message"))
                or (
                    "Facebook Marketplace picture repair is running..."
                    if job_kind == "picture_fix"
                    else "Facebook Marketplace fetch is running..."
                ),
                "subject": query,
                "elapsed": _format_dashboard_job_elapsed(marketplace_job.get("created_at")),
                "started_at": _format_dashboard_job_timestamp(marketplace_job.get("created_at")),
                "updated_at": _format_dashboard_job_timestamp(marketplace_job.get("updated_at")),
                "stop_url": (
                    f"/admin/facebook-marketplace/jobs/{job_id}/stop" if job_id else ""
                ),
                "stop_requested": bool(marketplace_job.get("stop_requested")),
                "stop_forced": bool(marketplace_job.get("stop_forced")),
                "result_summary": _freakops_job_result_summary(
                    "Facebook Marketplace",
                    marketplace_job,
                ),
                "open_url": (
                    "/admin/facebook-marketplace"
                    if job_kind == "picture_fix"
                    else (
                        f"/admin/facebook-marketplace/jobs/{job_id}/open"
                        if preview_token and status_value == "succeeded"
                        else "/admin/facebook-marketplace"
                    )
                ),
                "open_label": (
                    "Open Marketplace"
                    if job_kind == "picture_fix"
                    else (
                        "Open Preview"
                        if preview_token and status_value == "succeeded"
                        else "Open Marketplace"
                    )
                ),
                "sort_ts": _created_ts(marketplace_job),
            }
        )

    rows.sort(key=lambda item: float(item.get("sort_ts") or 0.0), reverse=True)
    try:
        limit_int = int(limit)
    except (TypeError, ValueError):
        limit_int = 200
    if limit_int <= 0:
        return []
    return rows[:limit_int]


def _freakops_active_jobs() -> list[dict[str, Any]]:
    return _freakops_job_rows(include_done=False, limit=200)


def _clear_background_job_cache_entries() -> tuple[int, bool]:
    deleted_keys = 0
    redis_available = False
    client = cache_get_client()
    if client is not None:
        redis_available = True
        cache_prefixes = (
            _NEUROWRATH_JOB_CACHE_PREFIX,
            _NEUROWRATH_JOB_ACTIVE_CACHE_PREFIX,
            _FACEBOOK_MARKETPLACE_PREVIEW_CACHE_PREFIX,
            _FACEBOOK_MARKETPLACE_JOB_CACHE_PREFIX,
            _FACEBOOK_MARKETPLACE_JOB_ACTIVE_CACHE_PREFIX,
        )
        for cache_prefix in cache_prefixes:
            key_prefix = build_cache_key(cache_prefix)
            pattern = f"{key_prefix}*"
            batch: list[str] = []
            try:
                for cache_key in client.scan_iter(match=pattern, count=200):
                    cache_key_text = str(cache_key or "").strip()
                    if not cache_key_text:
                        continue
                    batch.append(cache_key_text)
                    if len(batch) >= 200:
                        deleted_keys += int(client.delete(*batch) or 0)
                        batch = []
                if batch:
                    deleted_keys += int(client.delete(*batch) or 0)
            except Exception:
                logger.warning(
                    "Failed clearing Redis cache keys for pattern '%s'",
                    pattern,
                    exc_info=True,
                )
    with _neurowraith_jobs_lock:
        _neurowraith_jobs.clear()
    with _facebook_marketplace_jobs_lock:
        _facebook_marketplace_jobs.clear()
    with _facebook_marketplace_preview_fallback_lock:
        _facebook_marketplace_preview_fallback_store.clear()
    return deleted_keys, redis_available


