@app.post("/admin/jobs/cache/clear")
def admin_jobs_clear_cache(
    request: Request,
    csrf: str = Form(...),
    next: str | None = Form(None),
    _=Depends(admin_section_required("dashboard")),
):
    require_csrf(request, csrf)
    if not bool(request.session.get("is_superadmin")):
        raise HTTPException(status_code=403, detail="Super admin access required")
    redirect_target = _admin_safe_next_url(next, fallback="/admin/jobs")
    deleted_keys, redis_available = _clear_background_job_cache_entries()
    if deleted_keys > 0:
        flash(
            request,
            f"Cleared {deleted_keys} background-job Redis cache key(s).",
            "success",
        )
    elif redis_available:
        flash(
            request,
            "No background-job Redis cache keys were found. In-memory job cache was reset.",
            "info",
        )
    else:
        flash(
            request,
            "Redis cache is unavailable. In-memory job cache was reset.",
            "warning",
        )
    flash(
        request,
        "Celery queue entries were not purged by this action.",
        "info",
    )
    return RedirectResponse(redirect_target, status_code=303)


@app.post("/admin/scraper-health/check")
async def admin_scraper_health_check(
    request: Request,
    csrf: str = Form(...),
    spider: str = Form(...),
    _=Depends(admin_section_required("neurowraith")),
):
    require_csrf(request, csrf)
    spider_key = str(spider or "").strip()
    if not spider_key:
        flash(request, "Cannot run a scraper health check without a spider.", "error")
        return RedirectResponse("/admin#scraper-health", status_code=303)

    source = NEUROWRATH_SOURCE_BY_SPIDER.get(spider_key, {})
    label = source.get("label") or spider_key.replace("_", " ").title()
    succeeded, item_count, error_message = await _execute_neurowraith_health_check(spider_key)
    if succeeded:
        flash(
            request,
            f"Health check passed for {label} (fetched {item_count} item(s)).",
            "success",
        )
    else:
        flash(
            request,
            f"Health check failed for {label}: {error_message or 'Unknown error'}",
            "error",
        )
    return RedirectResponse("/admin#scraper-health", status_code=303)


@app.post("/admin/scraper-health/check-all")
async def admin_scraper_health_check_all(
    request: Request,
    csrf: str = Form(...),
    _=Depends(admin_section_required("neurowraith")),
):
    require_csrf(request, csrf)

    spiders = [source["spider"] for source in NEUROWRATH_SOURCES]
    if NeuroWraithRun is not None:
        with DBSession(engine) as session:
            spider_rows = session.exec(
                select(NeuroWraithRun.spider)
                .group_by(NeuroWraithRun.spider)
                .order_by(NeuroWraithRun.spider.asc())
            ).all()
        for spider_row in spider_rows:
            spider_key = str(spider_row or "").strip()
            if spider_key and spider_key not in spiders:
                spiders.append(spider_key)

    if not spiders:
        flash(request, "No scrapers found to health check.", "error")
        return RedirectResponse("/admin#scraper-health", status_code=303)

    passed = 0
    failed_details: list[str] = []
    for spider_key in spiders:
        source = NEUROWRATH_SOURCE_BY_SPIDER.get(spider_key, {})
        label = source.get("label") or spider_key.replace("_", " ").title()
        succeeded, _item_count, error_message = await _execute_neurowraith_health_check(spider_key)
        if succeeded:
            passed += 1
            continue
        failed_details.append(f"{label}: {error_message or 'Unknown error'}")

    failed = len(failed_details)
    if failed:
        preview = "; ".join(failed_details[:2])
        if len(failed_details) > 2:
            preview = f"{preview}; ..."
        flash(
            request,
            f"Health checks finished: {passed} passed, {failed} failed. {preview}",
            "error",
        )
    else:
        flash(request, f"Health checks passed for all {passed} scraper(s).", "success")
    return RedirectResponse("/admin#scraper-health", status_code=303)


def allowed_sorts():
    return {"posted_at","updated_at","id","price","year","mileage","make","model"}


def _maybe_int(val: Optional[str]) -> Optional[int]:
    try:
        return int(val) if val not in (None, "") else None
    except ValueError:
        return None


_STATUS_SPLIT_PATTERN = re.compile(r"[\n,]+")

_ORDERED_LIST_PATTERN = re.compile(r"^(\d+)[\.)]\s+(.*)$")
_MARKDOWN_BOLD_RE = re.compile(r"(\*\*|__)(.+?)\1")
_MARKDOWN_CODE_RE = re.compile(r"`([^`]+)`")


def _normalize_status_value(value: str | None) -> str:
    if value is None:
        return ""
    text = str(value).strip()
    if not text:
        return ""
    return text.replace("-", "_").replace(" ", "_").upper()


def _sanitize_statuses(value: str | None) -> list[str]:
    if not value:
        return []
    statuses: list[str] = []
    for part in _STATUS_SPLIT_PATTERN.split(value):
        normalized = _normalize_status_value(part)
        if normalized and normalized not in statuses:
            statuses.append(normalized)
    return statuses


def _format_inline_markdown(text: str) -> str:
    placeholder_values: list[str] = []

    def _store_code(match: re.Match[str]) -> str:
        placeholder_values.append(str(escape(match.group(1))))
        return f"@@CODE_BLOCK_{len(placeholder_values) - 1}@@"

    escaped = str(escape(text))
    without_code = _MARKDOWN_CODE_RE.sub(_store_code, escaped)
    formatted = _MARKDOWN_BOLD_RE.sub(lambda m: f"<strong>{m.group(2)}</strong>", without_code)

    for idx, value in enumerate(placeholder_values):
        formatted = formatted.replace(f"@@CODE_BLOCK_{idx}@@", f"<code>{value}</code>")
    return formatted


def _render_markdown(text: str) -> str:
    if not text:
        return ""

    normalized = text.replace("\r\n", "\n").replace("\r", "\n")
    lines = normalized.split("\n")
    html_parts: list[str] = []
    paragraph_buffer: list[str] = []
    list_type: str | None = None
    in_code_block = False
    code_lines: list[str] = []

    def flush_paragraph() -> None:
        nonlocal paragraph_buffer
        if paragraph_buffer:
            paragraph_text = " ".join(part.strip() for part in paragraph_buffer if part.strip())
            if paragraph_text:
                html_parts.append(f"<p>{_format_inline_markdown(paragraph_text)}</p>")
            paragraph_buffer = []

    def close_list() -> None:
        nonlocal list_type
        if list_type == "ul":
            html_parts.append("</ul>")
        elif list_type == "ol":
            html_parts.append("</ol>")
        list_type = None

    for raw_line in lines:
        stripped_line = raw_line.strip()

        if in_code_block:
            if stripped_line.startswith("```"):
                html_parts.append("<pre><code>")
                html_parts.append(str(escape("\n".join(code_lines))))
                html_parts.append("</code></pre>")
                code_lines = []
                in_code_block = False
            else:
                code_lines.append(raw_line)
            continue

        if stripped_line.startswith("```"):
            flush_paragraph()
            close_list()
            in_code_block = True
            code_lines = []
            continue

        if not stripped_line:
            flush_paragraph()
            close_list()
            continue

        if stripped_line.startswith("#"):
            flush_paragraph()
            close_list()
            level = len(stripped_line) - len(stripped_line.lstrip("#"))
            level = max(1, min(6, level))
            heading_text = stripped_line[level:].strip()
            if heading_text:
                html_parts.append(
                    f"<h{level}>{_format_inline_markdown(heading_text)}</h{level}>"
                )
            continue

        if stripped_line[0] in {"-", "*", "+"} and stripped_line[1:2] == " ":
            flush_paragraph()
            if list_type != "ul":
                close_list()
                html_parts.append("<ul>")
                list_type = "ul"
            html_parts.append(
                f"<li>{_format_inline_markdown(stripped_line[2:].strip())}</li>"
            )
            continue

        ordered_match = _ORDERED_LIST_PATTERN.match(stripped_line)
        if ordered_match:
            flush_paragraph()
            if list_type != "ol":
                close_list()
                html_parts.append("<ol>")
                list_type = "ol"
            html_parts.append(
                f"<li>{_format_inline_markdown(ordered_match.group(2).strip())}</li>"
            )
            continue

        if list_type:
            close_list()
        paragraph_buffer.append(stripped_line)

    flush_paragraph()
    close_list()
    if in_code_block and code_lines:
        html_parts.append("<pre><code>")
        html_parts.append(str(escape("\n".join(code_lines))))
        html_parts.append("</code></pre>")

    return "".join(part for part in html_parts if part)


def _resolve_preview_url(car: dict[str, Any]) -> str:
    candidates = (
        "url",
        "listing_url",
        "source_url",
        "permalink",
        "href",
        "web_url",
    )
    for key in candidates:
        value = car.get(key)
        if value:
            return str(value)
    return "https://example.com/listing-preview"


def _parse_car_reference(reference: str) -> dict[str, Any]:
    cleaned = (reference or "").strip()
    if not cleaned:
        raise HTTPException(status_code=400, detail="Provide a car ID or JSON payload.")

    try:
        parsed = json.loads(cleaned)
    except json.JSONDecodeError:
        parsed = None

    if isinstance(parsed, dict):
        return parsed
    if isinstance(parsed, list) and parsed and isinstance(parsed[0], dict):
        return parsed[0]
    if isinstance(parsed, (int, float)):
        cleaned = str(int(parsed))
    elif isinstance(parsed, str) and parsed.strip():
        cleaned = parsed.strip()

    with DBSession(engine) as session:
        car = None
        if cleaned.isdigit():
            car = session.get(Car, int(cleaned))
        if not car:
            car = session.exec(select(Car).where(Car.vin == cleaned)).first()
        if not car:
            car = session.exec(select(Car).where(Car.lot_number == cleaned)).first()
        if not car or getattr(car, "deleted_at", None):
            raise HTTPException(status_code=404, detail="Car not found.")

        dealership = None
        if getattr(car, "dealership_id", None):
            dealership = session.get(Dealership, getattr(car, "dealership_id"))
        make = None
        if Make is not None and getattr(car, "make_id", None):
            make = session.get(Make, getattr(car, "make_id"))
        return _public_car_dict(car, dealership, make) or {}


def _select_preview_variant(
    car: dict[str, Any],
    retail_statuses: Iterable[str],
    auction_statuses: Iterable[str],
) -> str:
    retail_values = {val for val in retail_statuses if val}
    auction_values = {val for val in auction_statuses if val}

    def _first(*keys: str) -> str:
        for key in keys:
            candidate = car.get(key)
            if candidate not in (None, ""):
                return str(candidate)
        return ""

    primary = _normalize_status_value(_first("__status", "status"))
    if primary:
        if primary in auction_values:
            return "auction"
        if primary in retail_values:
            return "retail"

    secondary = _normalize_status_value(_first("__auction_status", "auction_status"))
    if secondary:
        if secondary in auction_values:
            return "auction"
        if secondary in retail_values:
            return "retail"

    return "retail"


def _data_url_from_upload(upload: UploadFile | None) -> Optional[str]:
    """Return a data: URI for ``upload`` or ``None`` when no file was sent."""

    if not upload or not getattr(upload, "filename", ""):
        return None
    allowed_types = {
        str(item).strip().lower()
        for item in settings.upload_allowed_mime_types
        if str(item).strip()
    }
    mime = (
        upload.content_type
        or mimetypes.guess_type(upload.filename)[0]
        or "application/octet-stream"
    )
    if allowed_types and (not mime or mime.lower() not in allowed_types):
        return None
    max_bytes = int(getattr(settings, "UPLOAD_MAX_BYTES", 0) or 0)
    if max_bytes <= 0:
        max_bytes = 10_485_760
    content = upload.file.read(max_bytes + 1)
    if not isinstance(content, (bytes, bytearray)) or len(content) > max_bytes:
        return None
    b64 = base64.b64encode(content).decode("ascii")
    return f"data:{mime};base64,{b64}"
