@app.post("/admin/car-logos/new")
def admin_car_logo_create(
    request: Request,
    csrf: str = Form(...),
    name: str = Form(...),
    logo: UploadFile | None = File(None),
    _=Depends(admin_section_required("car_logos")),
):
    require_csrf(request, csrf)
    name_clean = (name or "").strip()
    canonical_name = canonicalize_make_name(name_clean)
    if canonical_name:
        name_clean = canonical_name
    if not name_clean:
        flash(request, "Brand name is required", "error")
        return RedirectResponse("/admin/car-logos", status_code=303)
    new_logo = _save_upload(logo, category="logos") if logo else None
    actor = request.session.get("admin_user", "admin")
    ip = get_ip(request)
    with DBSession(engine) as s:
        existing = s.exec(
            select(Make).where(func.lower(Make.name) == name_clean.lower())
        ).first()
        if existing:
            before = _model_to_dict(existing)
            changed = False
            if existing.name != name_clean:
                existing.name = name_clean
                changed = True
            if new_logo is not None:
                _delete_uploaded_file(existing.logo_url)
                existing.logo_url = new_logo
                changed = True
            s.add(existing)
            s.flush()
            linked = _refresh_car_make_assignments(s, actor, ip)
            s.commit()
            if changed:
                audit(
                    actor,
                    "update",
                    "makes",
                    existing.id,
                    before,
                    {"name": existing.name, "logo_url": existing.logo_url},
                    ip,
                )
            action = "Updated" if changed else "Checked"
            flash(
                request,
                f"{action} logo for {existing.name}. Linked to {linked} car(s).",
                "success",
            )
        else:
            make = Make(name=name_clean, logo_url=new_logo)
            s.add(make)
            s.flush()
            linked = _refresh_car_make_assignments(s, actor, ip)
            make_id = make.id
            make_name = make.name
            make_logo = make.logo_url
            s.commit()
            audit(
                actor,
                "create",
                "makes",
                make_id,
                None,
                {"name": make_name, "logo_url": make_logo},
                ip,
            )
            flash(
                request,
                f"Added logo for {make_name}. Linked to {linked} car(s).",
                "success",
            )
    return RedirectResponse("/admin/car-logos", status_code=303)


