@app.get("/admin/car-logos/{make_id}/delete")
def admin_car_logo_delete(request: Request, make_id: int, _=Depends(admin_section_required("car_logos"))):
    actor = request.session.get("admin_user", "admin")
    ip = get_ip(request)
    with DBSession(engine) as s:
        make = s.get(Make, make_id)
        if not make:
            flash(request, "Brand not found", "error")
            return RedirectResponse("/admin/car-logos", status_code=303)
        before = _model_to_dict(make)
        cars = s.exec(select(Car).where(Car.make_id == make_id)).all()
        for car in cars:
            prev = {"make_id": car.make_id, "make": car.make}
            car.make_id = None
            s.add(car)
            audit(
                actor,
                "update",
                "cars",
                car.id,
                prev,
                {"make_id": None, "make": car.make},
                ip,
            )
        _delete_uploaded_file(make.logo_url)
        s.delete(make)
        s.commit()
        audit(actor, "delete", "makes", make_id, before, None, ip)
    flash(
        request,
        f"Deleted logo and cleared {len(cars)} linked car(s).",
        "success",
    )
    return RedirectResponse("/admin/car-logos", status_code=303)


