@app.get("/admin/dealers", response_class=HTMLResponse)
def admin_dealer_profiles(request: Request, current=Depends(admin_section_required("dealerships"))):
    if DealerProfile is None:
        raise HTTPException(status_code=500, detail="Dealer profile model unavailable")
    with DBSession(engine) as session:
        profiles = session.exec(
            select(DealerProfile).order_by(DealerProfile.created_at.desc())
        ).all()
        profile_ids = [p.id for p in profiles if getattr(p, "id", None) is not None]
        owner_ids = [p.owner_user_id for p in profiles if p.owner_user_id]
        users = (
            session.exec(select(User).where(User.id.in_(owner_ids))).all()
            if owner_ids and User is not None
            else []
        )
        user_map = {u.id: u for u in users if getattr(u, "id", None) is not None}
        assigned_map: dict[int, Dealership] = {}
        if profile_ids:
            assigned = session.exec(
                select(Dealership).where(Dealership.dealer_profile_id.in_(profile_ids))
            ).all()
            assigned_map = {
                d.dealer_profile_id: d
                for d in assigned
                if getattr(d, "dealer_profile_id", None) is not None
            }
        requested_ids = [
            p.requested_dealership_id
            for p in profiles
            if getattr(p, "requested_dealership_id", None)
        ]
        requested_map: dict[int, Dealership] = {}
        if requested_ids:
            requested = session.exec(
                select(Dealership).where(Dealership.id.in_(requested_ids))
            ).all()
            requested_map = {d.id: d for d in requested if getattr(d, "id", None) is not None}

    return templates.TemplateResponse(
        request,
        "admin_dealer_profiles.html",
        {
            "title": "Dealer Profiles",
            "profiles": profiles,
            "user_map": user_map,
            "assigned_map": assigned_map,
            "requested_map": requested_map,
            "status_choices": DEALER_STATUS_CHOICES,
            "flash": pop_flash(request),
            "current_user": current,
        },
    )


