@app.post("/dealer/inventory/new")
async def dealer_inventory_create(
    request: Request,
    csrf: str = Form(...),
    title: str = Form(""),
    year: str = Form(""),
    vin: str = Form(""),
    make_name: str = Form(""),
    model: str = Form(""),
    transmission: str = Form(""),
    price: str = Form(""),
    mileage: str = Form(""),
    auction_status: str = Form("LIVE"),
    dealership_id: str = Form(""),
    location_address: str = Form(""),
    image_url: str = Form(""),
    image_file: UploadFile | None = File(None),
    description: str = Form(""),
    current=Depends(dealer_session_required),
):
    if Car is None:
        raise HTTPException(status_code=500, detail="Car model unavailable")
    require_csrf(request, csrf)
    errors: list[str] = []
    title_clean = (title or "").strip()
    if not title_clean:
        errors.append("Title is required.")
    vin_clean = re.sub(r"[^A-HJ-NPR-Z0-9]", "", (vin or "").upper())
    if not vin_clean:
        errors.append("VIN is required.")
    elif len(vin_clean) < 11:
        errors.append("VIN must be at least 11 characters.")
    make_clean = (make_name or "").strip()
    if not make_clean:
        errors.append("Make is required.")
    model_clean = (model or "").strip()
    if not model_clean:
        errors.append("Model is required.")
    status_clean = (auction_status or "").strip().upper() or "LIVE"
    allowed_statuses = {value for value, _ in DEALER_LISTING_STATUS_CHOICES}
    if status_clean not in allowed_statuses:
        errors.append("Select a valid status.")
        status_clean = "LIVE"

    def _parse_float(value: str, label: str) -> float | None:
        if not value:
            return None
        try:
            return float(str(value).replace(",", "").strip())
        except ValueError:
            errors.append(f"{label} must be a number.")
            return None

    def _parse_int(value: str, label: str) -> int | None:
        if not value:
            return None
        try:
            return int(str(value).replace(",", "").strip())
        except ValueError:
            errors.append(f"{label} must be a whole number.")
            return None

    price_value = _parse_float(price, "Price")
    mileage_value = _parse_int(mileage, "Mileage")
    year_value = _parse_int(year, "Year")
    dealership_id_value = _to_int(dealership_id)

    with DBSession(engine) as session:
        dealerships = _dealer_dealerships(session, current.profile.id)
        dealership_ids = {d.id for d in dealerships if getattr(d, "id", None) is not None}
        if not dealership_id_value or dealership_id_value not in dealership_ids:
            errors.append("Choose a valid dealership.")
        if errors:
            return templates.TemplateResponse(
                request,
                "dealer_inventory_form.html",
                _dealer_context(
                    request,
                    title="Create Listing",
                    dealerships=dealerships,
                    status_choices=DEALER_LISTING_STATUS_CHOICES,
                    action=_dealer_url(request, "inventory/new"),
                    csrf=request.session.get("csrf_token"),
                    errors=errors,
                    form_data={
                        "title": title_clean,
                        "year": year,
                        "vin": vin_clean,
                        "make_name": make_clean,
                        "model": model_clean,
                        "transmission": transmission,
                        "price": price,
                        "mileage": mileage,
                        "auction_status": status_clean,
                        "dealership_id": dealership_id,
                        "location_address": location_address,
                        "image_url": image_url,
                        "description": description,
                    },
                ),
                status_code=400,
            )

        dealership = session.get(Dealership, dealership_id_value)
        if not dealership:
            errors.append("Selected dealership could not be found.")
        canonical_make = canonicalize_make_name(make_clean) if make_clean else None
        make_id = None
        if canonical_make:
            make_obj = session.exec(
                select(Make).where(func.lower(Make.name) == canonical_make.lower())
            ).first()
            if not make_obj:
                make_obj = Make(name=canonical_make)
                session.add(make_obj)
                session.commit()
                session.refresh(make_obj)
            make_id = make_obj.id

        image_url_clean = (image_url or "").strip()
        if image_file and getattr(image_file, "filename", ""):
            saved = _save_upload(image_file, category="cars")
            if saved:
                image_url_clean = saved
        if not image_url_clean:
            errors.append("Provide an image URL or upload a file.")

        if errors:
            return templates.TemplateResponse(
                request,
                "dealer_inventory_form.html",
                _dealer_context(
                    request,
                    title="Create Listing",
                    dealerships=dealerships,
                    status_choices=DEALER_LISTING_STATUS_CHOICES,
                    action=_dealer_url(request, "inventory/new"),
                    csrf=request.session.get("csrf_token"),
                    errors=errors,
                    form_data={
                        "title": title_clean,
                        "year": year,
                        "vin": vin_clean,
                        "make_name": make_clean,
                        "model": model_clean,
                        "transmission": transmission,
                        "price": price,
                        "mileage": mileage,
                        "auction_status": status_clean,
                        "dealership_id": dealership_id,
                        "location_address": location_address,
                        "image_url": image_url,
                        "description": description,
                    },
                ),
                status_code=400,
            )

        location_value = (location_address or "").strip()
        if not location_value and dealership and dealership.location:
            location_value = dealership.location.strip()
        location_clean = strip_zip(location_value) if location_value else None
        if location_clean is not None:
            location_clean = location_clean.strip() or None

        def _city_state_from(address: str | None) -> tuple[str | None, str | None]:
            if not address:
                return None, None
            parts = [p.strip() for p in re.split(r"[,\n]", address) if p.strip()]
            if not parts:
                return None, None
            city_val = parts[0] or None
            state_val = parts[-1] if len(parts) > 1 else None
            return city_val, state_val

        city, state = _city_state_from(location_clean or (dealership.location.strip() if dealership and dealership.location else None))
        now = datetime.now(timezone.utc)
        car_payload = {
            "title": title_clean,
            "price": price_value,
            "mileage": mileage_value,
            "year": year_value,
            "make": canonical_make,
            "make_id": make_id,
            "model": model_clean,
            "vin": vin_clean,
            "transmission": (transmission or "").strip() or None,
            "dealership_id": dealership_id_value,
            "dealer_profile_id": current.profile.id,
            "image_url": image_url_clean,
            "city": city,
            "state": state,
            "auction_status": status_clean,
            "source": "dealer_portal",
            "seller_type": "dealer",
            "seller_name": dealership.name if dealership else None,
            "description": (description or "").strip() or None,
            "location_address": location_clean,
            "posted_at": now.isoformat(),
            "created_at": now.isoformat(),
            "updated_at": now.isoformat(),
        }
        _enrich_payload_coordinates(car_payload)
        car = Car(**car_payload)
        session.add(car)
        session.flush()
        current_lat = coerce_coordinate(getattr(car, "latitude", None))
        current_lng = coerce_coordinate(getattr(car, "longitude", None))
        _update_geo_point(session, car.id, current_lat, current_lng)
        session.commit()

    flash(request, "Listing created.", "success")
    return RedirectResponse(_dealer_url(request), status_code=303)


