@app.post("/dealer/profile")
async def dealer_profile_update(
    request: Request,
    csrf: str = Form(...),
    display_name: str = Form(""),
    contact_email: str = Form(""),
    phone: str = Form(""),
    website: str = Form(""),
    location: str = Form(""),
    dealership_id: str = Form(""),
    dealership_name: str = Form(""),
    dealership_location: str = Form(""),
    logo: UploadFile | None = File(None),
    current=Depends(dealer_session_required),
):
    require_csrf(request, csrf)
    errors: list[str] = []
    dealership_id_value = _to_int(dealership_id)
    with DBSession(engine) as session:
        profile = session.get(DealerProfile, current.profile.id)
        if not profile:
            flash(request, "Profile not found.", "error")
            return RedirectResponse(_dealer_url(request), status_code=303)
        dealerships = _dealer_dealerships(session, current.profile.id)
        dealership_ids = {d.id for d in dealerships if getattr(d, "id", None) is not None}
        selected = (
            session.get(Dealership, dealership_id_value)
            if dealership_id_value in dealership_ids
            else (dealerships[0] if dealerships else None)
        )
        if dealership_id_value and dealership_id_value not in dealership_ids:
            errors.append("Choose a valid dealership.")
        if errors:
            return templates.TemplateResponse(
                request,
                "dealer_profile.html",
                _dealer_context(
                    request,
                    title="Dealer Profile",
                    profile=profile,
                    dealerships=dealerships,
                    selected_dealership=selected,
                    csrf=request.session.get("csrf_token"),
                    errors=errors,
                    flash=pop_flash(request),
                ),
                status_code=400,
            )

        profile.display_name = display_name.strip() or profile.display_name
        profile.contact_email = contact_email.strip() or None
        profile.phone = phone.strip() or None
        profile.website = website.strip() or None
        profile.location = location.strip() or None
        profile.updated_at = datetime.now(timezone.utc).isoformat()
        session.add(profile)

        if selected:
            name_value = dealership_name.strip() if dealership_name else selected.name
            location_value = dealership_location.strip() if dealership_location else selected.location
            if name_value:
                selected.name = name_value
            selected.location = location_value or None
            if logo and getattr(logo, "filename", ""):
                new_logo = _save_upload(logo, category="dealerships")
                if new_logo:
                    _delete_uploaded_file(selected.logo_url)
                    selected.logo_url = new_logo
            session.add(selected)

        session.commit()

    flash(request, "Profile updated.", "success")
    return RedirectResponse(_dealer_url(request, "profile"), status_code=303)


def _load_agents():
    with DBSession(engine) as s:
        agents = s.exec(select(AdminUser).order_by(AdminUser.username)).all()
    return agents


@app.get("/admin/agents", response_class=HTMLResponse)
def admin_agents(request: Request, current=Depends(super_admin_required)):
    agents = _load_agents()
    sections_map = {agent.id: _user_sections_list(agent) for agent in agents}
    login_map: dict[int, dict[str, Any]] = {}
    for agent in agents:
        last_login_raw = getattr(agent, "last_login_at", None)
        formatted = _format_datetime(last_login_raw)
        relative = _format_timesince(last_login_raw)
        days_inactive = _days_since(last_login_raw)
        is_never = not bool(formatted)
        is_stale = is_never or (days_inactive is not None and days_inactive >= 30)
        login_map[agent.id] = {
            "formatted": formatted or "",
            "relative": relative or "",
            "days_inactive": days_inactive,
            "is_stale": is_stale,
            "is_never": is_never,
        }
    return templates.TemplateResponse(
        request,
        "admin_agents.html",
        {
            "title": "Agent Access",
            "agents": agents,
            "flash": pop_flash(request),
            "current_user": current,
            "form_data": {"sections": list(DEFAULT_AGENT_SECTIONS)},
            "section_choices": SECTION_CHOICES,
            "section_labels": SECTION_LABELS,
            "agent_sections": sections_map,
            "agent_logins": login_map,
        },
    )


@app.get("/admin/agents/{user_id}", response_class=HTMLResponse)
def admin_agent_detail(request: Request, user_id: int, current=Depends(super_admin_required)):
    csrf_token(request)
    with DBSession(engine) as admin_session:
        agent = admin_session.get(AdminUser, user_id)
        if not agent:
            raise HTTPException(status_code=404, detail="Agent not found")

    username = (getattr(agent, "username", "") or "").strip()

    total_actions = 0
    created_total = 0
    action_breakdown: list[dict[str, Any]] = []
    with DBSession(admin_engine) as audit_session:
        if username:
            actor_filter = func.lower(AdminAudit.actor) == username.lower()
            total_result = audit_session.exec(
                select(func.count()).select_from(AdminAudit).where(actor_filter)
            ).one()
            if isinstance(total_result, tuple):
                total_result = total_result[0]
            elif hasattr(total_result, "_mapping"):
                total_result = next(iter(total_result._mapping.values()))
            total_actions = total_result or 0
            created_result = audit_session.exec(
                select(func.count())
                .select_from(AdminAudit)
                .where(
                    actor_filter,
                    AdminAudit.action == "create",
                    AdminAudit.table_name == "cars",
                )
            ).one()
            if isinstance(created_result, tuple):
                created_result = created_result[0]
            elif hasattr(created_result, "_mapping"):
                created_result = next(iter(created_result._mapping.values()))
            created_total = created_result or 0
            breakdown_rows = audit_session.exec(
                select(AdminAudit.action, func.count().label("count"))
                .where(actor_filter)
                .group_by(AdminAudit.action)
                .order_by(func.count().desc())
            ).all()
            for action_key, count_value in breakdown_rows:
                count_value = (count_value or 0)
                action_breakdown.append(
                    {
                        "action": action_key or "",
                        "label": _humanize_label(action_key or ""),
                        "count": count_value,
                        "percent": (count_value / total_actions * 100) if total_actions else 0,
                    }
                )
            query = (
                select(AdminAudit)
                .where(actor_filter)
                .order_by(AdminAudit.created_at.desc())
                .limit(200)
            )
            audit_rows = audit_session.exec(query).all()
        else:
            audit_rows = []

    car_ids = []
    for entry in audit_rows:
        if entry.table_name != "cars":
            continue
        row_id = _coerce_int(entry.row_id)
        if row_id is None:
            continue
        car_ids.append(row_id)
    car_map: dict[int, Any] = {}
    if car_ids:
        with DBSession(engine) as car_session:
            cars = car_session.exec(select(Car).where(Car.id.in_(list(set(car_ids))))).all()
            car_map = {getattr(car, "id"): car for car in cars if getattr(car, "id", None) is not None}

    created_lookup: dict[Any, dict[str, Any]] = {}
    activity_items: list[dict[str, Any]] = []
    for row in audit_rows:
        after_data = _safe_json_dict(getattr(row, "after_json", None))
        before_data = _safe_json_dict(getattr(row, "before_json", None))
        row_id = _coerce_int(getattr(row, "row_id", None))
        car_context = None
        if row.table_name == "cars":
            car_context = _build_car_context(car_map.get(row_id), after_data, before_data, row_id)
            if row.action == "create" and car_context:
                key = row_id if row_id is not None else f"audit-{row.id}"
                created_lookup.setdefault(key, car_context)

        badge_class = ""
        if row.action == "create":
            badge_class = "success"
        elif row.action == "delete":
            badge_class = "error"

        activity_items.append(
            {
                "id": row.id,
                "action": row.action or "",
                "action_label": _humanize_label(row.action or ""),
                "badge_class": badge_class,
                "table": row.table_name or "",
                "table_label": _humanize_label(row.table_name or ""),
                "timestamp": _format_datetime(getattr(row, "created_at", None)),
                "raw_timestamp": getattr(row, "created_at", None),
                "car": car_context,
                "changes": _summarize_changes(before_data, after_data) if row.action == "update" else [],
            }
        )

    sections = _user_sections_list(agent)
    created_listings = list(created_lookup.values())
    created_shown = len(created_listings)

    stats = {
        "created_count": created_total,
        "created_shown": created_shown,
        "total_actions": total_actions,
        "last_activity": activity_items[0]["timestamp"] if activity_items else "",
        "section_count": len(sections),
    }

    agent_last_login = _format_datetime(getattr(agent, "last_login_at", None))
    agent_last_login_relative = _format_timesince(getattr(agent, "last_login_at", None))
    login_days = _days_since(getattr(agent, "last_login_at", None))
    login_status = {
        "relative": agent_last_login_relative,
        "is_stale": (not agent_last_login) or (login_days is not None and login_days >= 30),
        "days_inactive": login_days,
        "is_never": not bool(agent_last_login),
    }

    context = {
        "title": f"{agent.username} • Agent",
        "agent": agent,
        "flash": pop_flash(request),
        "current_user": current,
        "sections": sections,
        "section_labels": SECTION_LABELS,
        "created_listings": created_listings,
        "created_total": created_total,
        "activity": activity_items,
        "activity_breakdown": action_breakdown,
        "stats": stats,
        "agent_created": _format_datetime(getattr(agent, "created_at", None), "%b %d, %Y"),
        "agent_updated": _format_datetime(getattr(agent, "updated_at", None)),
        "agent_last_login": agent_last_login,
        "agent_last_login_relative": agent_last_login_relative,
        "login_status": login_status,
        "activity_limit": 200,
    }
    return templates.TemplateResponse(
        request,
        "admin_agent_detail.html",
        context,
    )


@app.post("/admin/agents")
def admin_agents_create(
    request: Request,
    csrf: str = Form(...),
    username: str = Form(...),
    password: str = Form(...),
    confirm_password: str = Form(...),
    sections: list[str] = Form([]),
    current=Depends(super_admin_required),
):
    require_csrf(request, csrf)
    username = (username or "").strip()
    selected_sections = normalize_sections(sections)
    errors: list[str] = []
    if len(username) < 3:
        errors.append("Username must be at least 3 characters long.")
    if len(password) < 8:
        errors.append("Password must be at least 8 characters long.")
    if password != confirm_password:
        errors.append("Passwords do not match.")
    if not selected_sections:
        errors.append("Select at least one admin section to grant access.")
    actor = request.session.get("admin_user", "admin")
    request_ip = get_ip(request)
    with DBSession(engine) as s:
        existing = None
        if username:
            existing = s.exec(
                select(AdminUser).where(func.lower(AdminUser.username) == username.lower())
            ).first()
        if existing:
            errors.append("Username is already in use.")
        if errors:
            agents = _load_agents()
            sections_map = {agent.id: _user_sections_list(agent) for agent in agents}
            return templates.TemplateResponse(
                request,
                "admin_agents.html",
                {
                    "title": "Agent Access",
                    "agents": agents,
                    "create_errors": errors,
                    "form_data": {"username": username, "sections": selected_sections},
                    "section_choices": SECTION_CHOICES,
                    "section_labels": SECTION_LABELS,
                    "agent_sections": sections_map,
                    "current_user": current,
                },
                status_code=400,
            )
        now = datetime.now(timezone.utc).isoformat()
        can_add = "manual" in selected_sections
        new_user = AdminUser(
            username=username,
            password_hash=hash_password(password),
            is_active=True,
            is_superuser=False,
            can_add_cars=can_add,
            permissions=serialize_sections(selected_sections),
            created_at=now,
            updated_at=now,
        )
        s.add(new_user)
        s.commit()
        s.refresh(new_user)

    audit(
        actor,
        "create",
        "admin_users",
        new_user.id,
        None,
        _sanitize_admin_user_snapshot(new_user),
        request_ip,
    )

    flash(request, "Agent account created", "success")
    return RedirectResponse("/admin/agents", status_code=303)


@app.post("/admin/agents/{user_id}/update")
def admin_agents_update(
    request: Request,
    user_id: int,
    csrf: str = Form(...),
    sections: list[str] = Form([]),
    is_active: str | None = Form(None),
    current=Depends(super_admin_required),
):
    require_csrf(request, csrf)
    selected_sections = normalize_sections(sections)
    active = _as_bool(is_active)
    actor = request.session.get("admin_user", "admin")
    request_ip = get_ip(request)
    with DBSession(engine) as s:
        agent = s.get(AdminUser, user_id)
        if not agent:
            raise HTTPException(status_code=404, detail="User not found")
        if agent.is_superuser and not active:
            flash(request, "Super admin cannot be deactivated.", "error")
            return RedirectResponse("/admin/agents", status_code=303)
        if not selected_sections:
            flash(request, "Select at least one admin section.", "error")
            return RedirectResponse("/admin/agents", status_code=303)
        before_state = _sanitize_admin_user_snapshot(agent)
        agent.permissions = serialize_sections(selected_sections)
        agent.can_add_cars = "manual" in selected_sections
        agent.is_active = active or agent.is_superuser
        agent.updated_at = datetime.now(timezone.utc).isoformat()
        s.add(agent)
        s.commit()
        s.refresh(agent)
        after_state = _sanitize_admin_user_snapshot(agent)

    audit(
        actor,
        "update",
        "admin_users",
        user_id,
        before_state,
        after_state,
        request_ip,
    )

    flash(request, "Agent permissions updated", "success")
    return RedirectResponse("/admin/agents", status_code=303)


