@app.get("/admin/cars", response_class=HTMLResponse)
def admin_cars(
    request: Request,
    page: int = 1,
    per: int = 25,
    q: Optional[str] = None,
    source: Optional[str] = None,
    make_id: Optional[str] = None,
    car_model_id: Optional[str] = Query(None, alias="model_id"),
    category_id: Optional[str] = None,
    status: Optional[str] = None,
    year_min: Optional[str] = None,
    year_max: Optional[str] = None,
    dealership_id: Optional[str] = None,
    sort: str = "posted_at",
    current=Depends(admin_section_required("cars")),
    _: object | None = None,
):
    make_id = _maybe_int(make_id)
    model_id = _maybe_int(car_model_id)
    category_id = _maybe_int(category_id)
    year_min = _maybe_int(year_min)
    year_max = _maybe_int(year_max)
    raw_dealership_scope = str(dealership_id or "").strip().lower()
    dealership_scope = "all"
    filter_unassigned_dealership = raw_dealership_scope in {
        "unassigned",
        "none",
        "null",
    }
    if filter_unassigned_dealership:
        dealership_id = None
        dealership_scope = "unassigned"
    else:
        dealership_id = _maybe_int(dealership_id)
        if dealership_id is not None:
            dealership_scope = str(dealership_id)

    per = max(1, min(per, 100))
    off = (max(1,page)-1)*per
    sort_col = sort if sort in allowed_sorts() else "posted_at"

    where = ["(deleted_at IS NULL OR deleted_at='')"]
    args = {}
    if q:
        where.append(
            "(vin LIKE :q OR make LIKE :q OR model LIKE :q OR title LIKE :q OR source LIKE :q)"
        )
        args["q"] = f"%{q}%"
    if source:
        where.append("LOWER(source) LIKE :source")
        args["source"] = f"%{source.lower()}%"
    if make_id is not None:
        where.append("make_id = :make_id"); args["make_id"] = make_id
    if model_id is not None:
        where.append("model_id = :model_id"); args["model_id"] = model_id
    if category_id is not None:
        where.append("category_id = :category_id"); args["category_id"] = category_id
    if dealership_id is not None:
        where.append("dealership_id = :dealership_id"); args["dealership_id"] = dealership_id
    elif filter_unassigned_dealership:
        where.append("dealership_id IS NULL")
    if status:
        where.append("auction_status = :status"); args["status"] = status
    if year_min is not None:
        where.append("year >= :ymin"); args["ymin"] = year_min
    if year_max is not None:
        where.append("year <= :ymax"); args["ymax"] = year_max
    where_sql = " AND ".join(where)

    with DBSession(engine) as s:
        makes = _models_to_simple_namespaces(
            s.exec(select(Make).order_by(Make.name)).all()
        )
        models = _models_to_simple_namespaces(
            s.exec(select(Model).order_by(Model.name)).all()
        )
        categories = _models_to_simple_namespaces(
            s.exec(select(Category).order_by(Category.name)).all()
        )
        dealerships = _models_to_simple_namespaces(
            s.exec(select(Dealership).order_by(Dealership.name)).all()
        )

        reload_attempted = False
        while True:
            total = s.exec(
                text(f"SELECT COUNT(*) AS c FROM cars WHERE {where_sql}").bindparams(**args)
            ).first()[0]
            raw_rows = s.exec(
                text(
                    f"SELECT cars.*, dealerships.name AS dealership_name FROM cars "
                    f"LEFT JOIN dealerships ON dealerships.id = cars.dealership_id "
                    f"WHERE {where_sql} ORDER BY {sort_col} DESC LIMIT :per OFFSET :off"
                ).bindparams(**(dict(args, per=per, off=off)))
            ).mappings().all()
            updated = False
            canonical_updates: list[tuple[int, str | None]] = []
            status_mismatch = False
            filter_mismatch = False
            rows = []
            for row in raw_rows:
                row_dict = dict(row)
                original_status = row_dict.get("auction_status")
                canonical_make_value = canonicalize_make_name(row_dict.get("make"))
                if canonical_make_value != row_dict.get("make"):
                    row_dict["make"] = canonical_make_value
                    if row_dict.get("id") is not None:
                        canonical_updates.append((row_dict["id"], canonical_make_value))
                listing_url = row_dict.get("url")
                allow_site_probe = (
                    isinstance(listing_url, str)
                    and listing_url.strip().lower().startswith("http://")
                )
                if _mark_sold_if_expired(row_dict, s) or (
                    allow_site_probe
                    and _update_status_from_url(
                        row_dict, s, require_countdown=False
                    )
                ):
                    updated = True
                current_status = row_dict.get("auction_status")
                if status and current_status != status:
                    if current_status != (original_status or ""):
                        status_mismatch = True
                    filter_mismatch = True
                    continue
                rows.append(row_dict)
            if canonical_updates:
                for cid, name in canonical_updates:
                    s.exec(
                        text("UPDATE cars SET make=:make WHERE id=:id").bindparams(
                            make=name, id=cid
                        )
                    )
                updated = True
            if updated:
                s.commit()
                if status and status_mismatch and not reload_attempted:
                    reload_attempted = True
                    try:
                        s.expire_all()
                    except Exception:
                        pass
                    continue
            if status and filter_mismatch and not reload_attempted:
                reload_attempted = True
                try:
                    s.expire_all()
                except Exception:
                    pass
                continue
            break
    last_page = max(1, (total + per - 1)//per)
    t = csrf_token(request)
    resp = templates.TemplateResponse(
        request,
        "admin_cars.html",
        {
            "cars": rows,
            "q": q or "",
            "source": source or "",
            "make_id": make_id,
            "model_id": model_id,
            "category_id": category_id,
            "status": status or "",
            "year_min": year_min,
            "year_max": year_max,
            "dealership_id": dealership_id,
            "dealership_scope": dealership_scope,
            "sort": sort_col,
            "per": per,
            "makes": makes,
            "models": models,
            "categories": categories,
            "dealerships": dealerships,
            "page": page,
            "last_page": last_page,
            "total": total,
            "title": "Cars",
            "flash": pop_flash(request),
            "current_user": current,
        },
    )
    return resp

