@app.post("/admin/cars/new")
def admin_car_create(
    request: Request,
    csrf: str = Form(...),
    vin: str = Form(None), year: int = Form(None), make_id: str | None = Form(None), car_model_id: str | None = Form(None, alias="model_id"), category_id: str | None = Form(None), trim: str = Form(None),
    price: str | None = Form(None), mileage: int = Form(None), currency: str = Form("USD"),
    city: str = Form(None), state: str = Form(None), location_address: str = Form(None),
    auction_status: str = Form(None), lot_number: str = Form(None), source: str = Form(None),
    url: str = Form(None), title: str = Form(None), image_url: str = Form(None), images_input: str = Form(None, alias="images_json"),
    highlights: str = Form(None), description: str = Form(None), seller_name: str = Form(None), seller_rating: str = Form(None), seller_reviews: str = Form(None),
    posted_at: str = Form(None), end_time: str = Form(None), time_left: str = Form(None), dealership_id: str | None = Form(None),
    image_file: UploadFile | None = File(None),
    image_files: list[UploadFile] | None = File(None),
    _=Depends(admin_section_required("cars")),
):
    require_csrf(request, csrf)
    allowed = set(Car.model_fields.keys())
    raw_payload = _normalize_fastapi_form_mapping(
        {
            "vin": vin,
            "year": year,
            "make_id": make_id,
            "car_model_id": car_model_id,
            "category_id": category_id,
            "trim": trim,
            "price": price,
            "mileage": mileage,
            "currency": currency,
            "city": city,
            "state": state,
            "location_address": location_address,
            "auction_status": auction_status,
            "lot_number": lot_number,
            "source": source,
            "url": url,
            "title": title,
            "image_url": image_url,
            "images_input": images_input,
            "highlights": highlights,
            "description": description,
            "seller_name": seller_name,
            "seller_rating": seller_rating,
            "seller_reviews": seller_reviews,
            "posted_at": posted_at,
            "end_time": end_time,
            "time_left": time_left,
            "dealership_id": dealership_id,
        }
    )
    vin = raw_payload["vin"]
    year = raw_payload["year"]
    make_id = raw_payload["make_id"]
    car_model_id = raw_payload["car_model_id"]
    category_id = raw_payload["category_id"]
    trim = raw_payload["trim"]
    price = raw_payload["price"]
    mileage = raw_payload["mileage"]
    currency = raw_payload["currency"]
    city = raw_payload["city"]
    state = raw_payload["state"]
    location_address = raw_payload["location_address"]
    auction_status = raw_payload["auction_status"]
    lot_number = raw_payload["lot_number"]
    source = raw_payload["source"]
    url = raw_payload["url"]
    title = raw_payload["title"]
    image_url = raw_payload["image_url"]
    images_input = raw_payload["images_input"]
    highlights = raw_payload["highlights"]
    description = raw_payload["description"]
    seller_name = raw_payload["seller_name"]
    seller_rating = raw_payload["seller_rating"]
    seller_reviews = raw_payload["seller_reviews"]
    posted_at = raw_payload["posted_at"]
    end_time = raw_payload["end_time"]
    time_left = raw_payload["time_left"]
    dealership_id = raw_payload["dealership_id"]
    with DBSession(engine) as s:
        make_id_i = _to_int(make_id)
        model_id_i = _to_int(car_model_id)
        category_id_i = _to_int(category_id)
        dealership_id_i = _to_int(dealership_id)
        if make_id_i:
            mk = s.get(Make, make_id_i)
            make_name = mk.name if mk else None
        else:
            inferred_id, make_name = resolve_make(None, title, session=s)
            if inferred_id:
                make_id_i = inferred_id
        model_name = s.get(Model, model_id_i).name if model_id_i else None
        imgs = _parse_images(images_input if isinstance(images_input, str) else None)
        if image_file and getattr(image_file, "filename", ""):
            up = _save_upload(image_file, category="cars")
            if up:
                image_url = up
        if isinstance(image_files, list):
            for f in image_files:
                up = _save_upload(f, category="cars")
                if up:
                    imgs.append(up)
        images_json = json.dumps(imgs) if imgs else None
        if not isinstance(highlights, str):
            highlights = None
        price_value = _to_float(price)
        payload = {k: v for k, v in dict(
            vin=vin,
            year=year,
            make=make_name,
            make_id=make_id_i,
            model=model_name,
            model_id=model_id_i,
            category_id=category_id_i,
            trim=trim,
            price=price_value,
            mileage=mileage,
            currency=currency,
            city=city,
            state=state,
            location_address=location_address,
            auction_status=auction_status,
            lot_number=lot_number,
            source=source,
            url=url,
            title=title,
            image_url=image_url,
            images_json=images_json,
            highlights=highlights,
            description=description,
            seller_name=seller_name,
            seller_rating=seller_rating,
            seller_reviews=seller_reviews,
            posted_at=posted_at,
            end_time=end_time,
            time_left=time_left,
            dealership_id=dealership_id_i,
        ).items() if k in allowed}
        for key in ("end_time", "time_left"):
            if key in payload:
                raw_value = payload[key]
                if hasattr(raw_value, "default"):
                    raw_value = raw_value.default
                cleaned = _clean_countdown_value(raw_value)
                payload[key] = cleaned if cleaned is not None else None
        payload["auction_status"] = _normalize_auction_status(
            payload,
            None,
            allow_manual_override=True,
        )
        if payload.get("make"):
            payload["make"] = canonicalize_make_name(payload["make"])
        _enrich_payload_coordinates(payload)
        c = Car(**payload)
        s.add(c)
        s.flush()
        current_lat = coerce_coordinate(getattr(c, "latitude", None))
        current_lng = coerce_coordinate(getattr(c, "longitude", None))
        _update_geo_point(s, c.id, current_lat, current_lng)
        after = _model_to_dict(c)
        audit(
            request.session.get("admin_user", "admin"),
            "create",
            "cars",
            c.id,
            None,
            after,
            get_ip(request),
        )
        s.commit()
    flash(request, "Car created", "success")
    return RedirectResponse("/admin/cars", status_code=303)

# Import/Export
@app.get("/admin/cars/export")
def admin_cars_export(fmt: str = "csv", _=Depends(admin_section_required("cars"))):
    with DBSession(engine) as s:
        rows = s.exec(
            text(
                "SELECT * FROM cars WHERE deleted_at IS NULL "
                "AND UPPER(COALESCE(auction_status,'')) != :removed_status "
                "ORDER BY COALESCE(posted_at,'') DESC, id DESC"
            ).bindparams(removed_status=REMOVED_STATUS)
        ).mappings().all()
    if fmt == "json":
        data = json.dumps([dict(r) for r in rows], ensure_ascii=False).encode("utf-8")
        return StreamingResponse(
            io.BytesIO(data),
            media_type="application/json",
            headers={"Content-Disposition": "attachment; filename=cars.json"},
        )
    # CSV
    buf = io.StringIO()
    if rows:
        fieldnames = list(rows[0].keys())
        w = csv.DictWriter(buf, fieldnames=fieldnames)
        w.writeheader()
        for r in rows:
            w.writerow(dict(r))
    return StreamingResponse(
        io.BytesIO(buf.getvalue().encode("utf-8")),
        media_type="text/csv",
        headers={"Content-Disposition": "attachment; filename=cars.csv"},
    )

# Bulk actions
@app.post("/admin/cars/bulk")
def admin_cars_bulk(
    request: Request,
    csrf: str = Form(...),
    ids: str = Form(...),
    action: str = Form(...),
    dealership_id: str | None = Form(None),
    _=Depends(admin_section_required("cars")),
):
    require_csrf(request, csrf)
    id_list = [int(x) for x in ids.split(",") if x.strip().isdigit()]
    dealership_id_i = _to_int(dealership_id)
    with DBSession(engine) as s:
        if action == "delete":
            ts = datetime.now(timezone.utc).isoformat()
            for cid in id_list:
                    car = s.get(Car, cid)
                    if car:
                        before = _model_to_dict(car)
                        car.deleted_at = ts
                        audit(
                            request.session.get("admin_user", "admin"),
                            "delete",
                            "cars",
                            cid,
                            before,
                            {"deleted_at": ts},
                            get_ip(request),
                        )
            flash(request, f"Deleted {len(id_list)} car(s)", "success")
        elif action in ADMIN_AUCTION_STATUS_CHOICES:
            for cid in id_list:
                    car = s.get(Car, cid)
                    if car:
                        normalized_status = _normalize_auction_status(
                            {"auction_status": action},
                            car,
                            allow_manual_override=True,
                        )
                        before = {"auction_status": car.auction_status}
                        car.auction_status = normalized_status
                        audit(
                            request.session.get("admin_user", "admin"),
                            "update",
                            "cars",
                            cid,
                            before,
                            {"auction_status": normalized_status},
                            get_ip(request),
                        )
            flash(request, f"Updated status for {len(id_list)} car(s)", "success")
        elif action == "set_dealership" and dealership_id_i:
            dealership_obj = (
                s.get(Dealership, dealership_id_i) if Dealership is not None else None
            )
            for cid in id_list:
                    car = s.get(Car, cid)
                    if car:
                        before = {
                            "dealership_id": car.dealership_id,
                            "location_address": car.location_address,
                            "city": car.city,
                            "state": car.state,
                        }
                        car.dealership_id = dealership_id_i
                        payload = {"dealership_id": dealership_id_i}
                        if dealership_obj:
                            _apply_dealership_location_fallback(
                                s,
                                payload,
                                car,
                                force=True,
                                respect_exclusions=False,
                            )
                        for field in ("location_address", "city", "state"):
                            if field in payload:
                                setattr(car, field, payload.get(field))
                        after = {
                            "dealership_id": car.dealership_id,
                            "location_address": car.location_address,
                            "city": car.city,
                            "state": car.state,
                        }
                        audit(
                            request.session.get("admin_user", "admin"),
                            "update",
                            "cars",
                            cid,
                            before,
                            after,
                            get_ip(request),
                        )
            flash(request, f"Assigned {len(id_list)} car(s)", "success")
        s.commit()
    return RedirectResponse("/admin/cars", status_code=303)

@app.get("/admin/cars/{car_id}", response_class=HTMLResponse)
def admin_car_edit(
    request: Request,
    car_id: int,
    current=Depends(admin_section_required("cars")),
    _: object | None = None,
):
    def _ensure_relations(sess, car_obj):
        changed = False
        if car_obj.make and not car_obj.make_id:
            mk = sess.exec(select(Make).where(Make.name == car_obj.make)).first()
            if not mk:
                mk = Make(name=car_obj.make)
                sess.add(mk)
                sess.commit()
            car_obj.make_id = mk.id
            changed = True
        if car_obj.model and not car_obj.model_id:
            q = select(Model).where(Model.name == car_obj.model)
            if car_obj.make_id:
                q = q.where(Model.make_id == car_obj.make_id)
            mdl = sess.exec(q).first()
            if not mdl:
                mdl = Model(name=car_obj.model, make_id=car_obj.make_id)
                sess.add(mdl)
                sess.commit()
            car_obj.model_id = mdl.id
            changed = True
        if changed:
            sess.add(car_obj)
            sess.commit()
            sess.refresh(car_obj)

    with DBSession(engine) as s:
        car = s.get(Car, car_id)
        updated = False
        if car:
            _ensure_relations(s, car)
            if _mark_sold_if_expired(car, s) or _update_status_from_url(
                car, s, require_countdown=False
            ):
                updated = True
                s.commit()
                s.refresh(car)
        makes = s.exec(select(Make).order_by(Make.name)).all()
        models = s.exec(select(Model).order_by(Model.name)).all()
        categories = s.exec(select(Category).order_by(Category.name)).all()
        dealerships = s.exec(select(Dealership).order_by(Dealership.name)).all()
    images_text = ""
    available_images: list[str] = []
    if car and getattr(car, "images_json", None):
        try:
            images_text = "\n".join(json.loads(car.images_json))
        except Exception:
            images_text = car.images_json
    if car:
        available_images = _admin_collect_car_images(car)
    t = csrf_token(request)
    resp = templates.TemplateResponse(
        request,
        "admin_car_edit.html",
        {
            "car": car,
            "action": f"/admin/cars/{car_id}",
            "title": f"Edit Car {car_id}",
            "csrf": csrf_token(request),
            "makes": makes,
            "models": models,
            "categories": categories,
            "dealerships": dealerships,
            "images_text": images_text,
            "available_images": available_images,
            "flash": pop_flash(request),
            "current_user": current,
        },
    )
    return resp

