@app.get("/admin/imports", response_class=HTMLResponse)
def admin_imports(request: Request, current=Depends(admin_section_required("imports"))):
    with DBSession(engine) as s:

        imports = s.exec(select(CarImport).order_by(CarImport.uploaded_at.desc())).all()
        recent_deletions: list[SimpleNamespace] = []
        if CarImportUndo is not None:
            undo_rows = (
                s.exec(
                    select(CarImportUndo)
                    .order_by(CarImportUndo.created_at.desc())
                    .limit(5)
                ).all()
            )
            for row in undo_rows:
                label = row.import_name or (
                    f"Import #{row.import_id}" if row.import_id is not None else "Import"
                )
                recent_deletions.append(
                    SimpleNamespace(
                        token=row.token,
                        name=label,
                        deleted_count=row.deleted_count or 0,
                        created_at=row.created_at,
                    )
                )
    return templates.TemplateResponse(
        request,
        "admin_imports.html",
        {

            "imports": imports,
            "recent_deletions": recent_deletions,
            "title": "Car Imports",
            "csrf": csrf_token(request),
            "flash": pop_flash(request),
            "current_user": current,
        },
    )


