@app.post("/admin/pca-mart")
def admin_pca_mart_import(
    request: Request,
    csrf: str = Form(...),
    listing_url: str = Form(""),
    current=Depends(admin_section_required("imports")),
):
    _ = current
    require_csrf(request, csrf)
    raw_url = str(listing_url or "").strip()
    if not raw_url:
        flash(
            request,
            "Please provide a PCA listing URL or ad number. Example: 80636",
            "error",
        )
        return RedirectResponse("/admin/pca-mart", status_code=303)

    try:
        normalized_url = normalize_pca_mart_listing_url(raw_url)
    except PCAMartListingError as exc:
        flash(request, f"PCA listing URL is invalid: {exc}", "error")
        return RedirectResponse("/admin/pca-mart", status_code=303)

    try:
        listing_record = fetch_pca_mart_listing(normalized_url)
    except PCAMartListingError as exc:
        flash(request, f"PCA listing scrape failed: {exc}", "error")
        return RedirectResponse("/admin/pca-mart", status_code=303)
    except Exception as exc:  # pragma: no cover - defensive network/runtime fallback
        flash(request, f"PCA listing scrape failed: {exc}", "error")
        return RedirectResponse("/admin/pca-mart", status_code=303)

    if not isinstance(listing_record, Mapping):
        flash(
            request,
            "PCA listing scrape failed: parsed payload was not a dictionary.",
            "error",
        )
        return RedirectResponse("/admin/pca-mart", status_code=303)

    payload = dict(listing_record)
    payload.setdefault("source", "pca")
    payload.setdefault("url", normalized_url)

    with DBSession(engine) as session:
        dealership_id = _resolve_pca_mart_dealership_id(session)
    if dealership_id is None:
        flash(
            request,
            "PCA dealership was not found. Create a dealership named 'PCA' or 'PCA Mart' "
            "in admin, or set PCA_MART_DEALERSHIP_ID.",
            "error",
        )
        return RedirectResponse("/admin/pca-mart", status_code=303)

    skip_reasons: dict[str, int] = {}
    try:
        inserted, updated, skipped, _ = _import_car_items(
            request,
            [payload],
            file_name="pca_mart.json",
            name="PCA Mart Admin Import",
            dealership_hint=None,
            dealership_id_override=dealership_id,
            skip_reason_counts=skip_reasons,
        )
    except Exception as exc:  # pragma: no cover - database/runtime guard
        flash(request, f"PCA listing import failed: {exc}", "error")
        return RedirectResponse("/admin/pca-mart", status_code=303)

    if inserted or updated:
        flash(
            request,
            f"PCA listing import finished: {inserted} inserted, {updated} updated, {skipped} skipped.",
            "success",
        )
    else:
        flash(
            request,
            f"PCA listing import finished: {inserted} inserted, {updated} updated, {skipped} skipped.",
            "warning",
        )
    if skip_reasons:
        details = ", ".join(
            f"{_slack_skip_reason_label(reason_key)}={count}"
            for reason_key, count in sorted(skip_reasons.items())
        )
        flash(request, f"Skip details: {details}", "warning")
    return RedirectResponse("/admin/pca-mart", status_code=303)


_FACEBOOK_MARKETPLACE_QUERY_PRESETS_SETTING_KEY = (
    getattr(Setting, "FACEBOOK_MARKETPLACE_QUERY_PRESETS", "facebook_marketplace_query_presets")
    if Setting is not None
    else "facebook_marketplace_query_presets"
)
_FACEBOOK_MARKETPLACE_SLACK_CHECKPOINT_SETTING_KEY = (
    getattr(
        Setting,
        "FACEBOOK_MARKETPLACE_SLACK_CHECKPOINT",
        "facebook_marketplace_slack_checkpoint",
    )
    if Setting is not None
    else "facebook_marketplace_slack_checkpoint"
)
_FACEBOOK_MARKETPLACE_QUERY_PRESETS_FILE = (
    _backend_dir / "data" / "facebook_marketplace_make_model_presets.tsv"
)


def _facebook_marketplace_preset_query_key(value: Any) -> str:
    query_text = _facebook_text(value)
    if not query_text:
        return ""
    return re.sub(r"\s+", " ", query_text.lower()).strip()


def _facebook_marketplace_normalize_query_preset_entry(
    make: Any = None,
    model: Any = None,
    *,
    query: Any = None,
) -> dict[str, str] | None:
    make_text = _facebook_text(make) or ""
    model_text = _facebook_text(model) or ""
    query_text = _facebook_text(query) or ""
    if not query_text:
        query_text = " ".join(part for part in (make_text, model_text) if part).strip()
    query_text = re.sub(r"\s+", " ", query_text).strip()
    if not query_text:
        return None
    return {
        "make": make_text,
        "model": model_text,
        "query": query_text,
    }


def _facebook_marketplace_parse_query_presets_text(raw_text: Any) -> list[dict[str, str]]:
    text = str(raw_text or "").replace("\r", "")
    if not text.strip():
        return []

    entries: list[dict[str, str]] = []
    seen_keys: set[str] = set()
    for raw_line in text.split("\n"):
        line = str(raw_line or "").strip()
        if not line:
            continue
        line_normalized = re.sub(r"\s+", " ", line.lower()).strip()
        if line_normalized in {"brand model", "make model"}:
            continue

        make_text = ""
        model_text = ""
        query_text = ""
        if "\t" in line:
            left, right = line.split("\t", 1)
            make_text = left.strip()
            model_text = right.strip()
        elif "|" in line:
            left, right = line.split("|", 1)
            make_text = left.strip()
            model_text = right.strip()
        elif "," in line:
            left, right = line.split(",", 1)
            make_text = left.strip()
            model_text = right.strip()
        else:
            split_parts = re.split(r"\s{2,}", line, maxsplit=1)
            if len(split_parts) == 2:
                make_text = split_parts[0].strip()
                model_text = split_parts[1].strip()
            else:
                query_text = line

        normalized = _facebook_marketplace_normalize_query_preset_entry(
            make_text,
            model_text,
            query=query_text,
        )
        if not normalized:
            continue
        query_key = _facebook_marketplace_preset_query_key(normalized.get("query"))
        if not query_key or query_key in seen_keys:
            continue
        seen_keys.add(query_key)
        entries.append(normalized)
    return entries


def _facebook_marketplace_merge_query_presets(
    *preset_groups: Iterable[Mapping[str, Any]] | None,
) -> list[dict[str, str]]:
    merged: list[dict[str, str]] = []
    seen_keys: set[str] = set()
    for group in preset_groups:
        if not group:
            continue
        for item in group:
            if not isinstance(item, Mapping):
                continue
            normalized = _facebook_marketplace_normalize_query_preset_entry(
                item.get("make"),
                item.get("model"),
                query=item.get("query"),
            )
            if not normalized:
                continue
            query_key = _facebook_marketplace_preset_query_key(normalized.get("query"))
            if not query_key or query_key in seen_keys:
                continue
            seen_keys.add(query_key)
            merged.append(normalized)
    return merged


def _facebook_marketplace_serialize_query_presets(
    presets: Iterable[Mapping[str, Any]] | None,
) -> str:
    lines: list[str] = []
    for item in presets or []:
        if not isinstance(item, Mapping):
            continue
        normalized = _facebook_marketplace_normalize_query_preset_entry(
            item.get("make"),
            item.get("model"),
            query=item.get("query"),
        )
        if not normalized:
            continue
        make_value = normalized.get("make") or ""
        model_value = normalized.get("model") or ""
        query_value = normalized.get("query") or ""
        if make_value and model_value:
            lines.append(f"{make_value}\t{model_value}")
        elif query_value:
            lines.append(query_value)
    return "\n".join(lines)


@functools.lru_cache(maxsize=1)
def _facebook_marketplace_builtin_query_presets() -> list[dict[str, str]]:
    try:
        raw_text = _FACEBOOK_MARKETPLACE_QUERY_PRESETS_FILE.read_text(encoding="utf-8")
    except OSError:
        return []
    return _facebook_marketplace_parse_query_presets_text(raw_text)


def _facebook_marketplace_load_custom_query_presets() -> list[dict[str, str]]:
    if Setting is None:
        return []
    try:
        with DBSession(admin_engine) as session:
            row = session.exec(
                text("SELECT value FROM settings WHERE key=:key").bindparams(
                    key=_FACEBOOK_MARKETPLACE_QUERY_PRESETS_SETTING_KEY
                )
            ).mappings().first()
    except Exception:
        return []
    raw_text = str((row or {}).get("value") or "")
    return _facebook_marketplace_parse_query_presets_text(raw_text)


def _facebook_marketplace_save_custom_query_presets(
    presets: Iterable[Mapping[str, Any]] | None,
) -> None:
    value_text = _facebook_marketplace_serialize_query_presets(presets)
    if Setting is None:
        return
    with DBSession(admin_engine) as session:
        session.exec(
            text(
                "INSERT INTO settings(key,value) VALUES(:k,:v) "
                "ON CONFLICT(key) DO UPDATE SET value=:v"
            ).bindparams(
                k=_FACEBOOK_MARKETPLACE_QUERY_PRESETS_SETTING_KEY,
                v=value_text,
            )
        )
        session.commit()


def _facebook_marketplace_query_presets() -> list[dict[str, str]]:
    return _facebook_marketplace_merge_query_presets(
        _facebook_marketplace_builtin_query_presets(),
        _facebook_marketplace_load_custom_query_presets(),
    )


def _facebook_marketplace_load_slack_checkpoint() -> dict[str, int]:
    checkpoint = {"preset_index": 0, "state_index": 0}
    if Setting is None:
        return checkpoint
    try:
        with DBSession(admin_engine) as session:
            row = session.exec(
                text("SELECT value FROM settings WHERE key=:key").bindparams(
                    key=_FACEBOOK_MARKETPLACE_SLACK_CHECKPOINT_SETTING_KEY
                )
            ).mappings().first()
    except Exception:
        return checkpoint
    raw_text = str((row or {}).get("value") or "").strip()
    if not raw_text:
        return checkpoint
    try:
        parsed = json.loads(raw_text)
    except Exception:
        return checkpoint
    if not isinstance(parsed, Mapping):
        return checkpoint
    try:
        preset_index = int(parsed.get("preset_index") or 0)
    except (TypeError, ValueError):
        preset_index = 0
    try:
        state_index = int(parsed.get("state_index") or 0)
    except (TypeError, ValueError):
        state_index = 0
    return {
        "preset_index": max(0, preset_index),
        "state_index": max(0, state_index),
    }


def _facebook_marketplace_save_slack_checkpoint(
    *,
    preset_index: int,
    state_index: int,
) -> None:
    if Setting is None:
        return
    payload = json.dumps(
        {
            "preset_index": max(0, int(preset_index)),
            "state_index": max(0, int(state_index)),
        },
        separators=(",", ":"),
    )
    with DBSession(admin_engine) as session:
        session.exec(
            text(
                "INSERT INTO settings(key,value) VALUES(:k,:v) "
                "ON CONFLICT(key) DO UPDATE SET value=:v"
            ).bindparams(
                k=_FACEBOOK_MARKETPLACE_SLACK_CHECKPOINT_SETTING_KEY,
                v=payload,
            )
        )
        session.commit()


def _facebook_marketplace_resolve_query_input(
    query: Any,
    preset_query: Any = None,
) -> str:
    explicit_query = _facebook_text(query)
    if explicit_query:
        return explicit_query
    preset_value = _facebook_text(preset_query)
    if preset_value:
        return preset_value
    return _facebook_marketplace_default_query()


def _facebook_marketplace_default_form_state() -> dict[str, str]:
    return {
        "query": _facebook_marketplace_default_query(),
        "preset_query": "",
        "category_id": _facebook_marketplace_default_category_id(),
        "location_state": _facebook_marketplace_default_state_code(),
        "location_city": "",
        "latitude": str(_facebook_marketplace_default_latitude()),
        "longitude": str(_facebook_marketplace_default_longitude()),
        "radius_km": str(_facebook_marketplace_default_radius_km()),
        "cursor": "",
        "dealership_id": "",
        "import_name": "Facebook Marketplace Import",
        "limit": "50",
    }


_FACEBOOK_MARKETPLACE_PREVIEW_SESSION_KEY = "facebook_marketplace_preview"
_FACEBOOK_MARKETPLACE_PREVIEW_CACHE_PREFIX = "admin:facebook_marketplace_preview"
_FACEBOOK_MARKETPLACE_PREVIEW_TTL_SECONDS = 1800
_FACEBOOK_MARKETPLACE_JOB_OWNER_SESSION_KEY = "facebook_marketplace_job_owner"
_FACEBOOK_MARKETPLACE_ACTIVE_JOB_SESSION_KEY = "facebook_marketplace_active_job_id"
_FACEBOOK_MARKETPLACE_ACTIVE_PICTURE_FIX_JOB_SESSION_KEY = (
    "facebook_marketplace_active_picture_fix_job_id"
)
_FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS = 1800
_FACEBOOK_MARKETPLACE_JOB_CACHE_PREFIX = "admin:facebook_marketplace_job"
_FACEBOOK_MARKETPLACE_JOB_ACTIVE_CACHE_PREFIX = "admin:facebook_marketplace_job_active"
_FACEBOOK_MARKETPLACE_JOB_HEARTBEAT_SECONDS = 30.0
_FACEBOOK_MARKETPLACE_JOB_QUEUE_RETRY_SECONDS = 2.0
_facebook_marketplace_fetch_lock = threading.Lock()
_facebook_marketplace_preview_fallback_store: dict[str, tuple[float, dict[str, Any]]] = {}
_facebook_marketplace_preview_fallback_lock = threading.Lock()
_facebook_marketplace_jobs: dict[str, dict[str, Any]] = {}
_facebook_marketplace_jobs_lock = threading.Lock()


def _facebook_marketplace_preview_cache_key(token: str) -> str:
    return build_cache_key(
        _FACEBOOK_MARKETPLACE_PREVIEW_CACHE_PREFIX,
        {"token": token},
    )


def _facebook_marketplace_preview_cleanup_fallback() -> None:
    now = time.time()
    with _facebook_marketplace_preview_fallback_lock:
        expired = [
            key
            for key, (expires_at, _) in _facebook_marketplace_preview_fallback_store.items()
            if expires_at <= now
        ]
        for key in expired:
            _facebook_marketplace_preview_fallback_store.pop(key, None)


def _facebook_marketplace_preview_store(payload: Mapping[str, Any]) -> str:
    token = token_urlsafe(24)
    cache_key = _facebook_marketplace_preview_cache_key(token)
    normalized_payload = dict(payload)
    cache_set_json(
        cache_key,
        normalized_payload,
        ttl_seconds=_FACEBOOK_MARKETPLACE_PREVIEW_TTL_SECONDS,
    )
    expires_at = time.time() + _FACEBOOK_MARKETPLACE_PREVIEW_TTL_SECONDS
    _facebook_marketplace_preview_cleanup_fallback()
    with _facebook_marketplace_preview_fallback_lock:
        _facebook_marketplace_preview_fallback_store[cache_key] = (
            expires_at,
            normalized_payload,
        )
    return token


def _facebook_marketplace_preview_load(token: str | None) -> dict[str, Any] | None:
    token_value = _facebook_text(token)
    if not token_value:
        return None
    cache_key = _facebook_marketplace_preview_cache_key(token_value)
    cached = cache_get_json(cache_key)
    if isinstance(cached, Mapping):
        return dict(cached)
    _facebook_marketplace_preview_cleanup_fallback()
    with _facebook_marketplace_preview_fallback_lock:
        entry = _facebook_marketplace_preview_fallback_store.get(cache_key)
    if not entry:
        return None
    expires_at, payload = entry
    if expires_at <= time.time():
        with _facebook_marketplace_preview_fallback_lock:
            _facebook_marketplace_preview_fallback_store.pop(cache_key, None)
        return None
    return dict(payload)


def _facebook_marketplace_preview_delete(token: str | None) -> None:
    token_value = _facebook_text(token)
    if not token_value:
        return
    cache_key = _facebook_marketplace_preview_cache_key(token_value)
    # cache module has no delete helper; overwrite with a tiny short-lived value.
    cache_set_json(cache_key, {"deleted": True}, ttl_seconds=1)
    with _facebook_marketplace_preview_fallback_lock:
        _facebook_marketplace_preview_fallback_store.pop(cache_key, None)


def _facebook_marketplace_preview_token(request: Request) -> str | None:
    raw = request.session.get(_FACEBOOK_MARKETPLACE_PREVIEW_SESSION_KEY)
    if isinstance(raw, str):
        value = raw.strip()
        return value or None
    return None


def _facebook_marketplace_normalize_preview_payload(
    raw: Mapping[str, Any] | None,
) -> dict[str, Any] | None:
    if not isinstance(raw, Mapping):
        return None
    items_raw = raw.get("items")
    if not isinstance(items_raw, list):
        return None
    items: list[dict[str, Any]] = []
    for item in items_raw:
        if isinstance(item, Mapping):
            items.append(dict(item))
    if not items:
        return None

    def _to_int(value: Any, default: int = 0) -> int:
        try:
            return int(value)
        except (TypeError, ValueError):
            return default

    payload: dict[str, Any] = {
        "items": items,
        "fetched": _to_int(raw.get("fetched"), len(items)),
        "prepared": _to_int(raw.get("prepared"), len(items)),
        "normalize_skipped": _to_int(raw.get("normalize_skipped"), 0),
        "import_name": str(raw.get("import_name") or "Facebook Marketplace Import"),
    }
    dealership_id = raw.get("dealership_id")
    try:
        payload["dealership_id"] = int(dealership_id) if dealership_id is not None else None
    except (TypeError, ValueError):
        payload["dealership_id"] = None
    return payload


def _facebook_marketplace_preview_payload(
    request: Request,
) -> dict[str, Any] | None:
    raw = request.session.get(_FACEBOOK_MARKETPLACE_PREVIEW_SESSION_KEY)
    # Backward-compatible support for older cookie-backed preview payloads.
    if isinstance(raw, Mapping):
        normalized = _facebook_marketplace_normalize_preview_payload(raw)
        if normalized:
            token = _facebook_marketplace_preview_store(normalized)
            request.session[_FACEBOOK_MARKETPLACE_PREVIEW_SESSION_KEY] = token
        return normalized
    token = _facebook_marketplace_preview_token(request)
    stored = _facebook_marketplace_preview_load(token)
    return _facebook_marketplace_normalize_preview_payload(stored)


def _facebook_marketplace_normalize_admin_form_inputs(
    *,
    query: str,
    preset_query: str,
    category_id: str,
    location_state: str,
    location_city: str,
    latitude: str,
    longitude: str,
    radius_km: str,
    cursor: str,
    facebook_payload_json: str,
    feed_url: str,
    access_token: str,
    request_options_json: str,
    dealership_id: str,
    import_name: str,
    limit: str,
    listings_json: str,
) -> dict[str, str]:
    normalized_inputs = _normalize_fastapi_form_mapping(
        {
            "query": query,
            "preset_query": preset_query,
            "category_id": category_id,
            "location_state": location_state,
            "location_city": location_city,
            "latitude": latitude,
            "longitude": longitude,
            "radius_km": radius_km,
            "cursor": cursor,
            "facebook_payload_json": facebook_payload_json,
            "feed_url": feed_url,
            "access_token": access_token,
            "request_options_json": request_options_json,
            "dealership_id": dealership_id,
            "import_name": import_name,
            "limit": limit,
            "listings_json": listings_json,
        }
    )
    return {
        "query": normalized_inputs["query"] or "",
        "preset_query": normalized_inputs["preset_query"] or "",
        "category_id": normalized_inputs["category_id"] or "",
        "location_state": normalized_inputs["location_state"] or "",
        "location_city": normalized_inputs["location_city"] or "",
        "latitude": normalized_inputs["latitude"] or "",
        "longitude": normalized_inputs["longitude"] or "",
        "radius_km": normalized_inputs["radius_km"] or "",
        "cursor": normalized_inputs["cursor"] or "",
        "facebook_payload_json": normalized_inputs["facebook_payload_json"] or "",
        "feed_url": normalized_inputs["feed_url"] or "",
        "access_token": normalized_inputs["access_token"] or "",
        "request_options_json": normalized_inputs["request_options_json"] or "",
        "dealership_id": normalized_inputs["dealership_id"] or "",
        "import_name": normalized_inputs["import_name"] or "",
        "limit": normalized_inputs["limit"] or "50",
        "listings_json": normalized_inputs["listings_json"] or "",
    }


def _facebook_marketplace_job_owner_key(request: Request) -> str:
    raw = request.session.get(_FACEBOOK_MARKETPLACE_JOB_OWNER_SESSION_KEY)
    if isinstance(raw, str):
        value = raw.strip()
        if value:
            return value
    owner_key = token_urlsafe(18)
    request.session[_FACEBOOK_MARKETPLACE_JOB_OWNER_SESSION_KEY] = owner_key
    return owner_key


def _facebook_marketplace_job_stale_seconds() -> int:
    timeout_hint = _facebook_marketplace_timeout_seconds()
    dynamic_value = max(240, timeout_hint * 12)
    max_allowed = max(300, _FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS - 30)
    return max(120, min(dynamic_value, max_allowed))


def _facebook_marketplace_job_last_touch(job: Mapping[str, Any]) -> float:
    for key in ("updated_at", "created_at"):
        try:
            value = float(job.get(key) or 0.0)
        except (TypeError, ValueError):
            value = 0.0
        if value > 0:
            return value
    return 0.0


def _facebook_marketplace_job_is_stale(
    job: Mapping[str, Any],
    *,
    now: float | None = None,
) -> bool:
    status = str(job.get("status") or "").lower()
    if status not in {"pending", "running"}:
        return False
    touched_at = _facebook_marketplace_job_last_touch(job)
    if touched_at <= 0:
        return True
    current_time = time.time() if now is None else now
    return (current_time - touched_at) > _facebook_marketplace_job_stale_seconds()


def _facebook_marketplace_job_stale_message(
    *,
    age_seconds: int,
    stale_after_seconds: int,
) -> str:
    return (
        "Facebook Marketplace background job expired because the worker stopped before "
        f"finishing (no update for {age_seconds}s; stale after {stale_after_seconds}s). "
        "Start the job again."
    )


def _facebook_marketplace_job_expire_if_stale(
    job: Mapping[str, Any] | None,
    *,
    now: float | None = None,
) -> dict[str, Any] | None:
    if not isinstance(job, Mapping):
        return None
    current_time = time.time() if now is None else now
    record = dict(job)
    if not _facebook_marketplace_job_is_stale(record, now=current_time):
        return record
    job_id = _facebook_text(record.get("job_id"))
    if not job_id:
        return record
    touched_at = _facebook_marketplace_job_last_touch(record)
    age_seconds = max(0, int(current_time - touched_at)) if touched_at > 0 else 0
    stale_after_seconds = _facebook_marketplace_job_stale_seconds()
    updated = _facebook_marketplace_job_update(
        job_id,
        status="failed",
        message=_facebook_marketplace_job_stale_message(
            age_seconds=age_seconds,
            stale_after_seconds=stale_after_seconds,
        ),
    )
    if isinstance(updated, Mapping):
        return dict(updated)
    return record


def _facebook_marketplace_jobs_cleanup_locked(now: float) -> None:
    stale_before = now - _FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS
    stale_job_ids = []
    for job_id, job in _facebook_marketplace_jobs.items():
        try:
            updated_at = float(job.get("updated_at") or 0.0)
        except (TypeError, ValueError):
            updated_at = 0.0
        if updated_at <= stale_before:
            stale_job_ids.append(job_id)
    for job_id in stale_job_ids:
        _facebook_marketplace_jobs.pop(job_id, None)


def _facebook_marketplace_job_cache_key(job_id: str) -> str:
    return build_cache_key(
        _FACEBOOK_MARKETPLACE_JOB_CACHE_PREFIX,
        {"job_id": job_id},
    )


def _facebook_marketplace_job_active_cache_key() -> str:
    return build_cache_key(_FACEBOOK_MARKETPLACE_JOB_ACTIVE_CACHE_PREFIX)


def _facebook_marketplace_job_load_fallback(job_id: str) -> dict[str, Any] | None:
    with _facebook_marketplace_jobs_lock:
        _facebook_marketplace_jobs_cleanup_locked(time.time())
        record = _facebook_marketplace_jobs.get(job_id)
        if not isinstance(record, Mapping):
            return None
        return dict(record)


def _facebook_marketplace_job_store_fallback(record: Mapping[str, Any]) -> None:
    job_id = _facebook_text(record.get("job_id"))
    if not job_id:
        return
    with _facebook_marketplace_jobs_lock:
        _facebook_marketplace_jobs_cleanup_locked(time.time())
        _facebook_marketplace_jobs[job_id] = dict(record)


def _facebook_marketplace_job_release_active_cache(job_id: str | None) -> None:
    active_job_id = _facebook_text(job_id)
    active_key = _facebook_marketplace_job_active_cache_key()
    active_payload = cache_get_json(active_key)
    if isinstance(active_payload, Mapping):
        locked_job_id = _facebook_text(active_payload.get("job_id"))
        if active_job_id and locked_job_id and locked_job_id != active_job_id:
            return
    # cache module has no delete helper; overwrite with a tiny short-lived value.
    cache_set_json(active_key, {"released": True}, ttl_seconds=1)


def _facebook_marketplace_job_get(job_id: str) -> dict[str, Any] | None:
    job_key = _facebook_text(job_id)
    if not job_key:
        return None
    cached = cache_get_json(_facebook_marketplace_job_cache_key(job_key))
    if isinstance(cached, Mapping) and _facebook_text(cached.get("job_id")) == job_key:
        record = dict(cached)
        _facebook_marketplace_job_store_fallback(record)
        return record
    return _facebook_marketplace_job_load_fallback(job_key)


def _facebook_marketplace_job_ensure_shared_cache(job_id: str) -> bool:
    job_key = _facebook_text(job_id)
    if not job_key:
        return False
    cache_key = _facebook_marketplace_job_cache_key(job_key)
    cached = cache_get_json(cache_key)
    if isinstance(cached, Mapping) and _facebook_text(cached.get("job_id")) == job_key:
        return True

    record = _facebook_marketplace_job_get(job_key)
    if not isinstance(record, Mapping):
        return False
    if cache_get_client() is None:
        return False

    cache_set_json(
        cache_key,
        dict(record),
        ttl_seconds=_FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS,
    )
    status = str(record.get("status") or "").strip().lower()
    owner = _facebook_text(record.get("owner_key"))
    if status in {"pending", "running"} and owner:
        cache_set_json(
            _facebook_marketplace_job_active_cache_key(),
            {
                "job_id": job_key,
                "owner_key": owner,
                "updated_at": float(record.get("updated_at") or time.time()),
            },
            ttl_seconds=_FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS,
        )

    cached = cache_get_json(cache_key)
    return bool(
        isinstance(cached, Mapping)
        and _facebook_text(cached.get("job_id")) == job_key
    )


def _facebook_marketplace_job_list_fallback(
    *,
    owner_key: str | None = None,
    statuses: set[str] | None = None,
    limit: int = 200,
) -> list[dict[str, Any]]:
    owner = _facebook_text(owner_key)
    desired_statuses = {
        str(item).strip().lower() for item in (statuses or set()) if str(item).strip()
    }
    with _facebook_marketplace_jobs_lock:
        _facebook_marketplace_jobs_cleanup_locked(time.time())
        rows: list[dict[str, Any]] = []
        for job in _facebook_marketplace_jobs.values():
            if not isinstance(job, Mapping):
                continue
            record = dict(job)
            if owner and _facebook_text(record.get("owner_key")) != owner:
                continue
            status_value = str(record.get("status") or "").strip().lower()
            if desired_statuses and status_value not in desired_statuses:
                continue
            rows.append(record)
    def _sort_ts(item: Mapping[str, Any]) -> float:
        try:
            return float(item.get("created_at") or 0.0)
        except (TypeError, ValueError):
            return 0.0

    rows.sort(key=_sort_ts, reverse=True)
    try:
        limit_int = int(limit)
    except (TypeError, ValueError):
        limit_int = 200
    if limit_int <= 0:
        return []
    return rows[:limit_int]


def _facebook_marketplace_job_list(
    *,
    owner_key: str | None = None,
    statuses: set[str] | None = None,
    limit: int = 200,
) -> list[dict[str, Any]]:
    try:
        limit_int = int(limit)
    except (TypeError, ValueError):
        limit_int = 200
    if limit_int <= 0:
        return []
    desired_statuses = {
        str(item).strip().lower() for item in (statuses or set()) if str(item).strip()
    }
    rows = _facebook_marketplace_job_list_fallback(
        owner_key=owner_key,
        statuses=None,
        limit=max(limit_int * 2, 200),
    )
    normalized: list[dict[str, Any]] = []
    for row in rows:
        record = _facebook_marketplace_job_expire_if_stale(row) or row
        status_value = str(record.get("status") or "").strip().lower()
        if desired_statuses and status_value not in desired_statuses:
            continue
        normalized.append(record)
        if len(normalized) >= limit_int:
            break
    return normalized


def _facebook_marketplace_job_find_active_fallback(
    *,
    owner_key: str | None = None,
) -> dict[str, Any] | None:
    owner = _facebook_text(owner_key)
    now = time.time()
    stale_jobs: list[tuple[str, int]] = []
    active: dict[str, Any] | None = None
    with _facebook_marketplace_jobs_lock:
        _facebook_marketplace_jobs_cleanup_locked(now)
        for job in _facebook_marketplace_jobs.values():
            if not isinstance(job, Mapping):
                continue
            record = dict(job)
            status = str(record.get("status") or "").lower()
            if status not in {"pending", "running"}:
                continue
            if owner and _facebook_text(record.get("owner_key")) != owner:
                continue
            if _facebook_marketplace_job_is_stale(record, now=now):
                stale_job_id = _facebook_text(record.get("job_id"))
                if stale_job_id:
                    touched_at = _facebook_marketplace_job_last_touch(record)
                    age_seconds = max(0, int(now - touched_at)) if touched_at > 0 else 0
                    stale_jobs.append((stale_job_id, age_seconds))
                continue
            active = record
            break
    if stale_jobs:
        stale_after_seconds = _facebook_marketplace_job_stale_seconds()
        for stale_job_id, age_seconds in stale_jobs:
            _facebook_marketplace_job_update(
                stale_job_id,
                status="failed",
                message=_facebook_marketplace_job_stale_message(
                    age_seconds=age_seconds,
                    stale_after_seconds=stale_after_seconds,
                ),
            )
    return active


def _facebook_marketplace_job_find_active(
    *,
    owner_key: str | None = None,
) -> dict[str, Any] | None:
    owner = _facebook_text(owner_key)
    active_payload = cache_get_json(_facebook_marketplace_job_active_cache_key())
    if isinstance(active_payload, Mapping):
        active_job_id = _facebook_text(active_payload.get("job_id"))
        if active_job_id:
            active_job = _facebook_marketplace_job_get(active_job_id)
            if isinstance(active_job, Mapping):
                active_job = _facebook_marketplace_job_expire_if_stale(active_job)
                status = str(active_job.get("status") or "").lower()
                if status in {"pending", "running"}:
                    if owner and _facebook_text(active_job.get("owner_key")) != owner:
                        return None
                    return dict(active_job)
        _facebook_marketplace_job_release_active_cache(active_job_id)
    return _facebook_marketplace_job_find_active_fallback(owner_key=owner)


def _facebook_marketplace_job_mark_active(
    *,
    job_id: str,
    owner_key: str,
) -> bool:
    job_key = _facebook_text(job_id)
    owner = _facebook_text(owner_key)
    if not job_key or not owner:
        return False
    active_key = _facebook_marketplace_job_active_cache_key()
    active_payload = {
        "job_id": job_key,
        "owner_key": owner,
        "updated_at": time.time(),
    }
    client = cache_get_client()
    if client is not None:
        try:
            encoded = json.dumps(active_payload)
            acquired = bool(
                client.set(
                    active_key,
                    encoded,
                    nx=True,
                    ex=_FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS,
                )
            )
            if acquired:
                return True
        except Exception:
            active_record = cache_get_json(active_key)
            if not isinstance(active_record, Mapping) or not _facebook_text(
                active_record.get("job_id")
            ):
                cache_set_json(
                    active_key,
                    active_payload,
                    ttl_seconds=_FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS,
                )
                return True
            return False
        active_record = cache_get_json(active_key)
        if not isinstance(active_record, Mapping) or not _facebook_text(
            active_record.get("job_id")
        ):
            cache_set_json(
                active_key,
                active_payload,
                ttl_seconds=_FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS,
            )
            return True
        return False
    return True


def _facebook_marketplace_job_kind(job: Mapping[str, Any] | None) -> str:
    if not isinstance(job, Mapping):
        return "fetch"
    kind_value = _facebook_text(job.get("kind")) or ""
    if not kind_value:
        payload = job.get("payload")
        if isinstance(payload, Mapping):
            kind_value = _facebook_text(payload.get("job_kind")) or ""
    normalized = kind_value.strip().lower()
    if normalized in {"picture_fix", "fix_pictures", "fix-pictures"}:
        return "picture_fix"
    return "fetch"


def _facebook_marketplace_job_create(
    *,
    owner_key: str,
    payload: Mapping[str, Any],
    kind: str = "fetch",
) -> str:
    now = time.time()
    job_id = token_urlsafe(18)
    kind_value = str(kind or "").strip().lower()
    if kind_value not in {"fetch", "picture_fix"}:
        kind_value = "fetch"
    pending_message = (
        "Queued Facebook Marketplace picture repair job."
        if kind_value == "picture_fix"
        else "Queued Facebook Marketplace fetch job."
    )
    record = {
        "job_id": job_id,
        "owner_key": owner_key,
        "kind": kind_value,
        "status": "pending",
        "message": pending_message,
        "created_at": now,
        "updated_at": now,
        "payload": dict(payload),
        "preview_token": None,
        "preview_summary": None,
        "flash_messages": [],
        "stop_requested": False,
        "stop_forced": False,
        "applied_to_session": False,
    }
    _facebook_marketplace_job_store_fallback(record)
    cache_set_json(
        _facebook_marketplace_job_cache_key(job_id),
        record,
        ttl_seconds=_FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS,
    )
    return job_id


def _facebook_marketplace_job_stop_requested(job_id: str) -> bool:
    job = _facebook_marketplace_job_get(job_id)
    if not isinstance(job, Mapping):
        return False
    return bool(job.get("stop_requested"))


def _facebook_marketplace_job_update(
    job_id: str,
    **updates: Any,
) -> dict[str, Any] | None:
    job_key = _facebook_text(job_id)
    if not job_key:
        return None
    existing = _facebook_marketplace_job_get(job_key)
    if not isinstance(existing, Mapping):
        return None
    update_values = dict(updates)
    if bool(existing.get("stop_forced")):
        # Force-stopped jobs remain terminal even if worker threads continue.
        for key in (
            "status",
            "message",
            "preview_token",
            "preview_summary",
            "flash_messages",
        ):
            update_values.pop(key, None)
    job = dict(existing)
    job.update(update_values)
    job["updated_at"] = time.time()
    _facebook_marketplace_job_store_fallback(job)
    cache_set_json(
        _facebook_marketplace_job_cache_key(job_key),
        job,
        ttl_seconds=_FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS,
    )
    status = str(job.get("status") or "").lower()
    owner = _facebook_text(job.get("owner_key"))
    if status in {"pending", "running"} and owner:
        cache_set_json(
            _facebook_marketplace_job_active_cache_key(),
            {
                "job_id": job_key,
                "owner_key": owner,
                "updated_at": job["updated_at"],
            },
            ttl_seconds=_FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS,
        )
    elif status in {"succeeded", "failed"}:
        _facebook_marketplace_job_release_active_cache(job_key)
    return dict(job)


def _facebook_marketplace_flash_messages_from_response(response: Any) -> list[dict[str, str]]:
    context = getattr(response, "context", None)
    if not isinstance(context, Mapping):
        return []
    flash_items = context.get("flash")
    if not isinstance(flash_items, list):
        return []
    messages: list[dict[str, str]] = []
    for item in flash_items:
        if not isinstance(item, Mapping):
            continue
        msg = _facebook_text(item.get("msg"))
        if not msg:
            continue
        level = (
            _facebook_text(item.get("level"))
            or _facebook_text(item.get("cat"))
            or "info"
        ).strip().lower() or "info"
        messages.append({"msg": msg, "level": level})
    return messages


def _facebook_marketplace_job_is_fetch_lock_conflict(
    status_code: int,
    flash_messages: list[dict[str, str]],
) -> bool:
    if int(status_code) != 429:
        return False
    for item in flash_messages:
        message = str(item.get("msg") or "").strip().lower()
        if "already running" in message:
            return True
    return False


def _facebook_marketplace_picture_fix_completion_message(
    result: Mapping[str, Any],
) -> str:
    target_requested = int(result.get("target_ids_requested", 0) or 0)
    target_matched = int(result.get("target_ids_matched", 0) or 0)
    target_segment = (
        f"targeted {target_matched}/{target_requested}, "
        if target_requested > 0
        else ""
    )
    return (
        "Fix Pictures at FBM complete: "
        f"{target_segment}"
        f"scanned {result.get('scanned', 0)}, "
        f"changed {result.get('changed', 0)}, "
        f"primary replaced {result.get('primary_replaced', 0)}, "
        f"canonicalized URLs {result.get('canonicalized_url', 0)}, "
        f"enrichment attempts {result.get('enrichment_attempted', 0)}, "
        f"enrichment success {result.get('enrichment_success', 0)}, "
        f"mobile fallback {result.get('enrichment_mobile_fallback_success', 0)}/"
        f"{result.get('enrichment_mobile_fallback_attempted', 0)}, "
        f"cookie retries {result.get('enrichment_cookie_retry_success', 0)}/"
        f"{result.get('enrichment_cookie_retry_attempted', 0)}, "
        f"cdn cached {result.get('cdn_upload_success', 0)}/"
        f"{result.get('cdn_upload_attempted', 0)}, "
        f"unsupported cleared {result.get('unsupported_primary_cleared', 0)}, "
        f"no primary after fix {result.get('no_primary_after', 0)}, "
        f"duration {result.get('duration_seconds', 0)}s."
    )


def _facebook_marketplace_picture_fix_no_change_warning_message(
    result: Mapping[str, Any],
) -> str | None:
    changed_count = int(result.get("changed", 0) or 0)
    if changed_count > 0:
        return None
    return (
        "No rows were changed. "
        f"Login-gated pages {result.get('enrichment_login_gate', 0)}, "
        f"temporarily blocked pages {result.get('enrichment_temporarily_blocked', 0)}, "
        f"no-image listing pages {result.get('enrichment_no_images', 0)}, "
        f"HTTP errors {result.get('enrichment_http_error', 0)}, "
        f"request errors {result.get('enrichment_request_error', 0)}, "
        f"cookie retries {result.get('enrichment_cookie_retry_success', 0)}/"
        f"{result.get('enrichment_cookie_retry_attempted', 0)}, "
        f"missing listing URL {result.get('skipped_missing_listing_url', 0)}."
    )


def _facebook_marketplace_picture_fix_avatar_warning_message(
    result: Mapping[str, Any],
) -> str | None:
    still_avatar = int(result.get("still_avatar_primary", 0) or 0)
    if still_avatar <= 0:
        return None
    return (
        f"{still_avatar} row(s) still have an avatar-like primary image. "
        "Run again with listing-page enrichment enabled or refresh those listings."
    )


def _facebook_marketplace_picture_fix_apply_result_to_session(
    request: Request,
    result: Mapping[str, Any],
) -> None:
    normalized_result = dict(result)
    request.session["facebook_marketplace_last_picture_fix_result"] = normalized_result
    flash(
        request,
        _facebook_marketplace_picture_fix_completion_message(normalized_result),
        "success",
    )
    no_change_warning = _facebook_marketplace_picture_fix_no_change_warning_message(
        normalized_result
    )
    if no_change_warning:
        flash(request, no_change_warning, "warning")
    avatar_warning = _facebook_marketplace_picture_fix_avatar_warning_message(
        normalized_result
    )
    if avatar_warning:
        flash(request, avatar_warning, "warning")


def _facebook_marketplace_picture_fix_job_worker(
    job_id: str,
    payload: Mapping[str, Any],
) -> None:
    running_message = "Fixing Facebook Marketplace listing pictures in the background..."
    _facebook_marketplace_job_update(
        job_id,
        status="running",
        message=running_message,
    )
    if _facebook_marketplace_job_stop_requested(job_id):
        _facebook_marketplace_job_update(
            job_id,
            status="failed",
            message="Facebook Marketplace picture repair was stopped before execution.",
        )
        return

    enrich_value = bool(_coerce_truthy(payload.get("enrich_from_listing_page")))
    limit_raw = _facebook_text(payload.get("limit")) or "0"
    try:
        limit_value = int(limit_raw)
    except (TypeError, ValueError):
        limit_value = 0
    limit_value = max(0, limit_value)
    target_ids_value, target_ids_error = _facebook_marketplace_parse_target_car_ids(
        payload.get("target_ids"),
        max_ids=10_000,
    )
    if target_ids_error:
        _facebook_marketplace_job_update(
            job_id,
            status="failed",
            message=f"Fix Pictures at FBM failed: {target_ids_error}",
        )
        return

    heartbeat_stop = threading.Event()

    def _heartbeat() -> None:
        interval_seconds = max(1.0, float(_FACEBOOK_MARKETPLACE_JOB_HEARTBEAT_SECONDS))
        while not heartbeat_stop.wait(interval_seconds):
            current = _facebook_marketplace_job_get(job_id)
            if not isinstance(current, Mapping):
                return
            status = str(current.get("status") or "").lower()
            if status not in {"pending", "running"}:
                return
            _facebook_marketplace_job_update(
                job_id,
                status="running",
                message=running_message,
            )

    heartbeat_thread = threading.Thread(
        target=_heartbeat,
        daemon=True,
        name=f"fb-marketplace-picture-fix-heartbeat-{job_id[:8]}",
    )
    heartbeat_thread.start()
    try:
        result = _facebook_marketplace_repair_existing_listing_images(
            enrich_from_listing_page=enrich_value,
            timeout_seconds=5,
            limit=limit_value,
            target_car_ids=target_ids_value or None,
            allow_cookie_retry=False,
            cache_primary_to_cdn=True,
            cdn_category="facebook-market",
        )
    except Exception as exc:
        _facebook_marketplace_job_update(
            job_id,
            status="failed",
            message=f"Fix Pictures at FBM failed: {exc}",
        )
        return
    finally:
        heartbeat_stop.set()
        heartbeat_thread.join(
            timeout=max(1.0, float(_FACEBOOK_MARKETPLACE_JOB_HEARTBEAT_SECONDS))
        )

    if _facebook_marketplace_job_stop_requested(job_id):
        _facebook_marketplace_job_update(
            job_id,
            status="failed",
            message="Facebook Marketplace picture repair was stopped by an admin.",
        )
        return

    summary_message = _facebook_marketplace_picture_fix_completion_message(result)
    _facebook_marketplace_job_update(
        job_id,
        status="succeeded",
        message=summary_message,
        result=dict(result),
        preview_token=None,
        preview_summary=None,
        flash_messages=[],
    )


def _facebook_marketplace_job_worker(job_id: str) -> None:
    job = _facebook_marketplace_job_get(job_id)
    if not isinstance(job, Mapping):
        return
    job_kind = _facebook_marketplace_job_kind(job)
    running_message = (
        "Fixing Facebook Marketplace listing pictures in the background..."
        if job_kind == "picture_fix"
        else "Fetching Facebook Marketplace listings in the background..."
    )
    job = _facebook_marketplace_job_update(
        job_id,
        status="running",
        message=running_message,
    )
    if not isinstance(job, Mapping):
        return
    if _facebook_marketplace_job_stop_requested(job_id):
        stop_message = (
            "Facebook Marketplace picture repair was stopped before execution."
            if job_kind == "picture_fix"
            else "Facebook Marketplace fetch was stopped before execution."
        )
        _facebook_marketplace_job_update(
            job_id,
            status="failed",
            message=stop_message,
        )
        return
    payload_raw = job.get("payload")
    if not isinstance(payload_raw, Mapping):
        _facebook_marketplace_job_update(
            job_id,
            status="failed",
            message="Facebook Marketplace job payload was invalid.",
        )
        return

    payload = dict(payload_raw)
    if job_kind == "picture_fix":
        _facebook_marketplace_picture_fix_job_worker(job_id, payload)
        return

    run_source = str(payload.get("run_source") or "").strip().lower()
    if run_source == "slack":
        heartbeat_stop = threading.Event()

        def _heartbeat() -> None:
            interval_seconds = max(1.0, float(_FACEBOOK_MARKETPLACE_JOB_HEARTBEAT_SECONDS))
            while not heartbeat_stop.wait(interval_seconds):
                current = _facebook_marketplace_job_get(job_id)
                if not isinstance(current, Mapping):
                    return
                status = str(current.get("status") or "").lower()
                if status not in {"pending", "running"}:
                    return
                _facebook_marketplace_job_update(
                    job_id,
                    status="running",
                    message=running_message,
                )

        heartbeat_thread = threading.Thread(
            target=_heartbeat,
            daemon=True,
            name=f"fb-marketplace-heartbeat-{job_id[:8]}",
        )
        heartbeat_thread.start()
        try:
            try:
                result_map, mode_label = _facebook_marketplace_run_slack_import_payload(
                    job_id=job_id,
                    payload=payload,
                    running_message=running_message,
                )
            except HTTPException as exc:
                detail = str(getattr(exc, "detail", "") or "Unknown error")
                _facebook_marketplace_job_update(
                    job_id,
                    status="failed",
                    message=f"Facebook Marketplace import failed ({exc.status_code}): {detail}",
                )
                return
            except Exception as exc:
                _facebook_marketplace_job_update(
                    job_id,
                    status="failed",
                    message=f"Facebook Marketplace job crashed: {exc}",
                )
                return

            fetched = int(result_map.get("fetched") or 0)
            prepared = int(result_map.get("prepared") or 0)
            inserted = int(result_map.get("inserted") or 0)
            updated = int(result_map.get("updated") or 0)
            skipped = int(result_map.get("skipped") or 0)
            message = (
                "Facebook Marketplace import finished"
                + (f" {mode_label}" if mode_label else "")
                + ": "
                + f"fetched={fetched}, prepared={prepared}, inserted={inserted}, "
                + f"updated={updated}, skipped={skipped}."
            )
            _facebook_marketplace_job_update(
                job_id,
                status="succeeded",
                message=message,
                result=result_map,
                preview_summary={
                    "fetched": fetched,
                    "prepared": prepared,
                    "normalize_skipped": max(0, fetched - prepared),
                },
                flash_messages=[],
            )
            return
        finally:
            heartbeat_stop.set()
            heartbeat_thread.join(
                timeout=max(1.0, float(_FACEBOOK_MARKETPLACE_JOB_HEARTBEAT_SECONDS))
            )

    csrf_value = _facebook_text(payload.get("session_csrf")) or _facebook_text(
        payload.get("csrf")
    )
    if not csrf_value:
        _facebook_marketplace_job_update(
            job_id,
            status="failed",
            message="Facebook Marketplace job is missing CSRF context.",
        )
        return

    fake_request = SimpleNamespace(
        session={
            "csrf_token": csrf_value,
            "admin_user": _facebook_text(payload.get("admin_user")) or "admin",
            "permissions": ["imports"],
            "is_superadmin": True,
        },
        headers={},
        client=SimpleNamespace(host="127.0.0.1"),
    )
    queue_started_at = time.time()
    queue_timeout_seconds = max(120, _FACEBOOK_MARKETPLACE_JOB_TTL_SECONDS - 30)
    flash_messages: list[dict[str, str]] = []
    status_code = 500
    response: Any = None

    while True:
        if _facebook_marketplace_job_stop_requested(job_id):
            _facebook_marketplace_job_update(
                job_id,
                status="failed",
                message="Facebook Marketplace fetch was stopped by an admin.",
                flash_messages=flash_messages,
            )
            return

        heartbeat_stop = threading.Event()

        def _heartbeat() -> None:
            interval_seconds = max(1.0, float(_FACEBOOK_MARKETPLACE_JOB_HEARTBEAT_SECONDS))
            while not heartbeat_stop.wait(interval_seconds):
                current = _facebook_marketplace_job_get(job_id)
                if not isinstance(current, Mapping):
                    return
                status = str(current.get("status") or "").lower()
                if status not in {"pending", "running"}:
                    return
                _facebook_marketplace_job_update(
                    job_id,
                    status="running",
                    message=running_message,
                )

        heartbeat_thread = threading.Thread(
            target=_heartbeat,
            daemon=True,
            name=f"fb-marketplace-heartbeat-{job_id[:8]}",
        )
        heartbeat_thread.start()
        try:
            response = asyncio.run(
                admin_facebook_marketplace_run(
                    request=fake_request,
                    csrf=csrf_value,
                    query=str(payload.get("query") or ""),
                    preset_query=str(payload.get("preset_query") or ""),
                    category_id=str(payload.get("category_id") or ""),
                    location_state=str(payload.get("location_state") or ""),
                    location_city=str(payload.get("location_city") or ""),
                    latitude=str(payload.get("latitude") or ""),
                    longitude=str(payload.get("longitude") or ""),
                    radius_km=str(payload.get("radius_km") or ""),
                    cursor=str(payload.get("cursor") or ""),
                    facebook_payload_json=str(payload.get("facebook_payload_json") or ""),
                    feed_url=str(payload.get("feed_url") or ""),
                    access_token=str(payload.get("access_token") or ""),
                    request_options_json=str(payload.get("request_options_json") or ""),
                    dealership_id=str(payload.get("dealership_id") or ""),
                    import_name=str(payload.get("import_name") or ""),
                    limit=str(payload.get("limit") or "50"),
                    listings_json=str(payload.get("listings_json") or ""),
                    current=True,
                )
            )
        except Exception as exc:
            _facebook_marketplace_job_update(
                job_id,
                status="failed",
                message=f"Facebook Marketplace job crashed: {exc}",
            )
            return
        finally:
            heartbeat_stop.set()
            heartbeat_thread.join(
                timeout=max(1.0, float(_FACEBOOK_MARKETPLACE_JOB_HEARTBEAT_SECONDS))
            )

        try:
            status_code = int(getattr(response, "status_code", 500))
        except (TypeError, ValueError):
            status_code = 500
        flash_messages = _facebook_marketplace_flash_messages_from_response(response)

        if _facebook_marketplace_job_is_fetch_lock_conflict(status_code, flash_messages):
            waited_seconds = max(0, int(time.time() - queue_started_at))
            if waited_seconds >= queue_timeout_seconds:
                _facebook_marketplace_job_update(
                    job_id,
                    status="failed",
                    message=(
                        "Facebook Marketplace background fetch stayed queued too long "
                        f"({waited_seconds}s). Please run it again."
                    ),
                    flash_messages=flash_messages,
                )
                return
            _facebook_marketplace_job_update(
                job_id,
                status="pending",
                message=(
                    "Queued behind another Facebook Marketplace fetch. "
                    f"Waiting for slot ({waited_seconds}s elapsed)."
                ),
            )
            time.sleep(max(0.2, float(_FACEBOOK_MARKETPLACE_JOB_QUEUE_RETRY_SECONDS)))
            _facebook_marketplace_job_update(
                job_id,
                status="running",
                message=running_message,
            )
            continue
        break

    if _facebook_marketplace_job_stop_requested(job_id):
        _facebook_marketplace_job_update(
            job_id,
            status="failed",
            message="Facebook Marketplace fetch was stopped by an admin.",
            flash_messages=flash_messages,
        )
        return

    preview_token = _facebook_marketplace_preview_token(fake_request)
    if status_code == 200 and preview_token:
        preview_payload = _facebook_marketplace_preview_load(preview_token) or {}
        preview_summary = {
            "fetched": int(preview_payload.get("fetched") or 0),
            "prepared": int(preview_payload.get("prepared") or 0),
            "normalize_skipped": int(preview_payload.get("normalize_skipped") or 0),
            "dealership_id": preview_payload.get("dealership_id"),
        }
        _facebook_marketplace_job_update(
            job_id,
            status="succeeded",
            message=(
                "Fetched Marketplace listings. Review and uncheck any rows you do not "
                "want, then apply import."
            ),
            preview_token=preview_token,
            preview_summary=preview_summary,
            flash_messages=flash_messages,
        )
        return
    if status_code == 200 and not preview_token:
        _facebook_marketplace_job_update(
            job_id,
            status="failed",
            message=(
                "Marketplace fetch finished but preview data was not saved. "
                "Try again; if this repeats, verify Redis connectivity."
            ),
            flash_messages=flash_messages,
        )
        return

    error_message: str | None = None
    for item in flash_messages:
        level = str(item.get("level") or "info").lower()
        if level in {"error", "warning"} and item.get("msg"):
            error_message = str(item["msg"])
            break
    if not error_message and flash_messages:
        error_message = str(flash_messages[-1].get("msg") or "")
    if not error_message:
        error_message = f"Facebook Marketplace job failed with status {status_code}."
    _facebook_marketplace_job_update(
        job_id,
        status="failed",
        message=error_message,
        flash_messages=flash_messages,
    )


def _facebook_marketplace_enqueue_job(job_id: str) -> str:
    backend = str((queue_backend_status() or {}).get("backend") or "").strip().lower()
    if backend == "celery" and not _facebook_marketplace_job_ensure_shared_cache(job_id):
        logger.warning(
            "Facebook Marketplace job is not visible in shared cache; skipping Celery "
            "enqueue and running in local thread instead (job_id=%s)",
            str(job_id or "").strip() or "unknown",
        )
    elif _enqueue_background_job(
        "vinfreak.jobs.facebook_marketplace",
        job_id,
        queue_name=FACEBOOK_MARKETPLACE_CELERY_QUEUE,
    ):
        logger.info(
            "Facebook Marketplace background job enqueued to Celery (job_id=%s)",
            str(job_id or "").strip() or "unknown",
        )
        return "celery"
    logger.warning(
        "Celery enqueue unavailable; running Facebook Marketplace job in local thread "
        "(job_id=%s)",
        str(job_id or "").strip() or "unknown",
    )
    thread = threading.Thread(
        target=_facebook_marketplace_job_worker,
        args=(job_id,),
        daemon=True,
        name=f"fb-marketplace-job-{job_id[:8]}",
    )
    thread.start()
    return "thread"


def _render_admin_facebook_marketplace_page(
    request: Request,
    current: Any,
    *,
    status_code: int = 200,
    form_state: Mapping[str, Any] | None = None,
) -> HTMLResponse:
    state = _facebook_marketplace_default_form_state()
    if isinstance(form_state, Mapping):
        for key in state.keys():
            if key in form_state and form_state.get(key) is not None:
                state[key] = str(form_state.get(key))
    selected_state_code = _facebook_marketplace_state_code(state.get("location_state"))
    if selected_state_code:
        state["location_state"] = selected_state_code
    selected_city_query = state.get("location_city", "")
    city_suggestions = (
        _facebook_marketplace_city_suggestions(
            selected_state_code,
            selected_city_query or None,
            limit=_FACEBOOK_MARKETPLACE_CITY_SUGGESTION_LIMIT,
        )
        if selected_state_code
        else []
    )
    with DBSession(engine) as session:
        dealerships = (
            session.exec(select(Dealership).order_by(func.lower(Dealership.name))).all()
            if Dealership is not None
            else []
        )
    last_result_raw = request.session.get("facebook_marketplace_last_result")
    last_result = last_result_raw if isinstance(last_result_raw, Mapping) else None
    last_picture_fix_raw = request.session.get(
        "facebook_marketplace_last_picture_fix_result"
    )
    last_picture_fix_result = (
        last_picture_fix_raw if isinstance(last_picture_fix_raw, Mapping) else None
    )
    preview = _facebook_marketplace_preview_payload(request)
    custom_query_presets = _facebook_marketplace_load_custom_query_presets()
    query_presets = _facebook_marketplace_merge_query_presets(
        _facebook_marketplace_builtin_query_presets(),
        custom_query_presets,
    )
    custom_query_presets_text = _facebook_marketplace_serialize_query_presets(
        custom_query_presets
    )
    token_configured = bool(
        str(getattr(settings, "FACEBOOK_MARKETPLACE_ACCESS_TOKEN", "") or "").strip()
    )
    session_cookie_configured = bool(_facebook_marketplace_session_cookie())
    owner_key = _facebook_marketplace_job_owner_key(request)
    active_job_id = _facebook_text(
        request.session.get(_FACEBOOK_MARKETPLACE_ACTIVE_JOB_SESSION_KEY)
    )
    if active_job_id:
        active_job = _facebook_marketplace_job_get(active_job_id)
        active_job = _facebook_marketplace_job_expire_if_stale(active_job)
        active_status = str((active_job or {}).get("status") or "").lower()
        if (
            not active_job
            or _facebook_text(active_job.get("owner_key")) != owner_key
            or active_status in {"succeeded", "failed"}
        ):
            active_job_id = None
            request.session.pop(_FACEBOOK_MARKETPLACE_ACTIVE_JOB_SESSION_KEY, None)
    active_picture_fix_job_id = _facebook_text(
        request.session.get(_FACEBOOK_MARKETPLACE_ACTIVE_PICTURE_FIX_JOB_SESSION_KEY)
    )
    if active_picture_fix_job_id:
        active_picture_fix_job = _facebook_marketplace_job_get(active_picture_fix_job_id)
        active_picture_fix_job = _facebook_marketplace_job_expire_if_stale(
            active_picture_fix_job
        )
        active_picture_fix_status = str(
            (active_picture_fix_job or {}).get("status") or ""
        ).lower()
        if (
            not active_picture_fix_job
            or _facebook_text(active_picture_fix_job.get("owner_key")) != owner_key
            or _facebook_marketplace_job_kind(active_picture_fix_job) != "picture_fix"
            or active_picture_fix_status in {"succeeded", "failed"}
        ):
            active_picture_fix_job_id = None
            request.session.pop(
                _FACEBOOK_MARKETPLACE_ACTIVE_PICTURE_FIX_JOB_SESSION_KEY,
                None,
            )
    return templates.TemplateResponse(
        request,
        "admin_facebook_marketplace.html",
        {
            "title": "Facebook Marketplace",
            "csrf": csrf_token(request),
            "flash": pop_flash(request),
            "current_user": current,
            "form_state": state,
            "dealerships": dealerships,
            "last_result": last_result,
            "facebook_marketplace_last_picture_fix_result": last_picture_fix_result,
            "preview": preview,
            "facebook_marketplace_enabled": _facebook_marketplace_import_enabled(),
            "graphql_endpoint": _FACEBOOK_MARKETPLACE_GRAPHQL_ENDPOINT,
            "token_configured": token_configured,
            "session_cookie_configured": session_cookie_configured,
            "facebook_marketplace_states": _facebook_marketplace_state_options(),
            "facebook_marketplace_city_suggestions": city_suggestions,
            "facebook_marketplace_query_presets": query_presets,
            "facebook_marketplace_custom_query_presets_text": custom_query_presets_text,
            "facebook_marketplace_builtin_query_presets_count": len(
                _facebook_marketplace_builtin_query_presets()
            ),
            "facebook_marketplace_custom_query_presets_count": len(
                custom_query_presets
            ),
            "facebook_marketplace_cities_endpoint": "/admin/facebook-marketplace/cities",
            "facebook_marketplace_jobs_endpoint": "/admin/facebook-marketplace/jobs",
            "facebook_marketplace_picture_fix_jobs_endpoint": (
                "/admin/facebook-marketplace/fix-pictures/jobs"
            ),
            "facebook_marketplace_active_job_id": active_job_id,
            "facebook_marketplace_active_picture_fix_job_id": active_picture_fix_job_id,
        },
        status_code=status_code,
    )


def _facebook_parse_admin_json_block(
    raw_json: str,
    *,
    label: str,
) -> tuple[list[dict[str, Any]] | None, dict[str, Any] | None, str | None]:
    text = (raw_json or "").strip()
    if not text:
        return None, None, None
    try:
        parsed = json.loads(text)
    except (TypeError, ValueError):
        return None, None, f"{label} is invalid."
    listings = _facebook_collect_listing_items(parsed)
    if listings:
        return listings, None, None
    if isinstance(parsed, Mapping):
        return None, dict(parsed), None
    return None, None, f"{label} must be a JSON object or array."


