@app.post("/admin/facebook-marketplace/diagnostics")
def admin_facebook_marketplace_diagnostics(
    request: Request,
    csrf: str = Form(...),
    current=Depends(admin_section_required("imports")),
):
    require_csrf(request, csrf)
    session_cookie = _facebook_marketplace_session_cookie()
    cookie_names = sorted(_facebook_cookie_name_set(session_cookie))
    if not session_cookie:
        flash(
            request,
            "FACEBOOK_MARKETPLACE_SESSION_COOKIE is not configured. Set it and restart the backend.",
            "error",
        )
        return RedirectResponse("/admin/facebook-marketplace", status_code=303)

    cookie_error = _facebook_validate_marketplace_session_cookie(session_cookie)
    if cookie_error:
        flash(request, cookie_error, "error")
        return RedirectResponse("/admin/facebook-marketplace", status_code=303)

    flash(
        request,
        (
            "Marketplace session cookie format looks valid "
            f"(required keys present; detected {len(cookie_names)} key(s))."
        ),
        "success",
    )
    return RedirectResponse("/admin/facebook-marketplace", status_code=303)


@app.post("/admin/facebook-marketplace/fix-pictures")
def admin_facebook_marketplace_fix_pictures(
    request: Request,
    csrf: str = Form(...),
    enrich_from_listing_page: str | None = Form(None),
    limit: str = Form("0"),
    target_ids: str = Form(""),
    current=Depends(admin_section_required("imports")),
):
    _ = current
    require_csrf(request, csrf)

    limit_text = _facebook_text(limit) or "0"
    try:
        limit_value = int(limit_text)
    except (TypeError, ValueError):
        flash(request, "Fix Pictures row limit must be a whole number.", "error")
        return RedirectResponse("/admin/facebook-marketplace", status_code=303)
    if limit_value < 0:
        flash(request, "Fix Pictures row limit cannot be negative.", "error")
        return RedirectResponse("/admin/facebook-marketplace", status_code=303)
    target_ids_value, target_ids_error = _facebook_marketplace_parse_target_car_ids(
        target_ids,
        max_ids=10_000,
    )
    if target_ids_error:
        flash(request, target_ids_error, "error")
        return RedirectResponse("/admin/facebook-marketplace", status_code=303)

    enrich_value = _coerce_truthy(enrich_from_listing_page)
    try:
        result = _facebook_marketplace_repair_existing_listing_images(
            enrich_from_listing_page=bool(enrich_value),
            timeout_seconds=5,
            limit=limit_value,
            target_car_ids=target_ids_value or None,
            allow_cookie_retry=False,
            cache_primary_to_cdn=True,
            cdn_category="facebook-market",
        )
    except Exception as exc:
        logger.exception(
            "Facebook Marketplace picture repair failed",
            exc_info=True,
        )
        flash(request, f"Fix Pictures at FBM failed: {exc}", "error")
        return RedirectResponse("/admin/facebook-marketplace", status_code=303)

    _facebook_marketplace_picture_fix_apply_result_to_session(request, result)
    return RedirectResponse("/admin/facebook-marketplace", status_code=303)


