@app.post("/admin/facebook-marketplace/query-presets")
def admin_facebook_marketplace_query_presets(
    request: Request,
    csrf: str = Form(...),
    mode: str = Form("add"),
    preset_make: str = Form(""),
    preset_model: str = Form(""),
    preset_bulk_text: str = Form(""),
    current=Depends(admin_section_required("imports")),
):
    _ = current
    require_csrf(request, csrf)

    mode_value = str(mode or "add").strip().lower() or "add"
    try:
        custom_presets = _facebook_marketplace_load_custom_query_presets()
        builtin_presets = _facebook_marketplace_builtin_query_presets()
        all_presets = _facebook_marketplace_merge_query_presets(
            builtin_presets,
            custom_presets,
        )

        if mode_value == "add":
            make_value = _facebook_text(preset_make) or ""
            model_value = _facebook_text(preset_model) or ""
            if not make_value or not model_value:
                flash(request, "Both Brand and Model are required.", "error")
                return RedirectResponse("/admin/facebook-marketplace", status_code=303)

            entry = _facebook_marketplace_normalize_query_preset_entry(
                make_value,
                model_value,
            )
            if not entry:
                flash(request, "Brand/Model entry is invalid.", "error")
                return RedirectResponse("/admin/facebook-marketplace", status_code=303)

            entry_key = _facebook_marketplace_preset_query_key(entry.get("query"))
            existing_keys = {
                _facebook_marketplace_preset_query_key(item.get("query"))
                for item in all_presets
                if isinstance(item, Mapping)
            }
            if entry_key in existing_keys:
                flash(
                    request,
                    f"Preset already exists: {entry.get('query')}.",
                    "info",
                )
                return RedirectResponse("/admin/facebook-marketplace", status_code=303)

            updated_custom = _facebook_marketplace_merge_query_presets(
                custom_presets,
                [entry],
            )
            _facebook_marketplace_save_custom_query_presets(updated_custom)
            flash(
                request,
                f"Added preset: {entry.get('query')}.",
                "success",
            )
            return RedirectResponse("/admin/facebook-marketplace", status_code=303)

        if mode_value == "replace":
            parsed_custom = _facebook_marketplace_parse_query_presets_text(
                preset_bulk_text
            )
            _facebook_marketplace_save_custom_query_presets(parsed_custom)
            flash(
                request,
                (
                    "Saved custom Facebook Marketplace presets "
                    f"({len(parsed_custom)} line(s))."
                ),
                "success",
            )
            return RedirectResponse("/admin/facebook-marketplace", status_code=303)

        if mode_value == "reset":
            _facebook_marketplace_save_custom_query_presets([])
            flash(
                request,
                "Cleared custom presets. Built-in presets remain available.",
                "success",
            )
            return RedirectResponse("/admin/facebook-marketplace", status_code=303)

        flash(request, f"Unknown presets action: {mode_value}", "error")
        return RedirectResponse("/admin/facebook-marketplace", status_code=303)
    except Exception as exc:
        flash(request, f"Failed to update presets: {exc}", "error")
        return RedirectResponse("/admin/facebook-marketplace", status_code=303)


