@app.post("/admin/freakstats")
async def admin_freakstats_save(
    request: Request,
    csrf: str = Form(...),
    freakstats_system_prompt: str = Form(""),
    freakstats_user_prompt: str = Form(""),
    freakstats_system_prompt_auction: str = Form(""),
    freakstats_user_prompt_auction: str = Form(""),
    freakstats_retail_statuses: str = Form(""),
    freakstats_auction_statuses: str = Form(""),
    freakstats_loader_url: str = Form(""),
    freakstats_loader: UploadFile | None = File(None),
    _=Depends(admin_section_required("freakstats")),
):
    require_csrf(request, csrf)

    retail_system_prompt = (
        freakstats_system_prompt.strip() or DEFAULT_FREAKSTATS_SYSTEM_PROMPT_RETAIL
    )
    retail_user_prompt = (
        freakstats_user_prompt.strip() or DEFAULT_FREAKSTATS_USER_PROMPT_RETAIL
    )
    auction_system_prompt = (
        freakstats_system_prompt_auction.strip()
        or DEFAULT_FREAKSTATS_SYSTEM_PROMPT_AUCTION
    )
    auction_user_prompt = (
        freakstats_user_prompt_auction.strip() or DEFAULT_FREAKSTATS_USER_PROMPT_AUCTION
    )
    retail_status_values = _sanitize_statuses(freakstats_retail_statuses)
    auction_status_values = _sanitize_statuses(freakstats_auction_statuses)
    retail_status_text = "\n".join(retail_status_values)
    auction_status_text = "\n".join(auction_status_values)
    loader_url = freakstats_loader_url.strip()

    uploaded_loader = _data_url_from_upload(freakstats_loader)
    if uploaded_loader:
        loader_url = uploaded_loader

    updates = {
        Setting.FREAKSTATS_PROMPT: retail_system_prompt,
        Setting.FREAKSTATS_SYSTEM_PROMPT: retail_system_prompt,
        Setting.FREAKSTATS_USER_PROMPT: retail_user_prompt,
        Setting.FREAKSTATS_SYSTEM_PROMPT_RETAIL: retail_system_prompt,
        Setting.FREAKSTATS_USER_PROMPT_RETAIL: retail_user_prompt,
        Setting.FREAKSTATS_SYSTEM_PROMPT_AUCTION: auction_system_prompt,
        Setting.FREAKSTATS_USER_PROMPT_AUCTION: auction_user_prompt,
        Setting.FREAKSTATS_LOADER_URL: loader_url,
        Setting.FREAKSTATS_RETAIL_STATUSES: retail_status_text,
        Setting.FREAKSTATS_AUCTION_STATUSES: auction_status_text,
    }

    with DBSession(admin_engine) as s:
        before = {
            r["key"]: r["value"]
            for r in s.exec(text("SELECT key,value FROM settings")).mappings().all()
        }
        for k, v in updates.items():
            s.exec(
                text(
                    "INSERT INTO settings(key,value) VALUES(:k,:v) ON CONFLICT(key) DO UPDATE SET value=:v"
                ).bindparams(k=k, v=v)
            )
        audit(
            request.session.get("admin_user", "admin"),
            "settings",
            "settings",
            "-",
            before,
            updates,
            get_ip(request),
        )
        s.commit()

    invalidate_prompt_cache()
    cleared_entries = _clear_freakstats_insights_cache()
    if cleared_entries > 0:
        flash(
            request,
            f"FreakGPT prompts saved. Cleared {cleared_entries} cached insight entr{'y' if cleared_entries == 1 else 'ies'}.",
            "success",
        )
    else:
        flash(request, "FreakGPT prompts saved", "success")
    return RedirectResponse("/admin/freakstats", status_code=303)


def _clamp_int(value, *, default: int, minimum: int, maximum: int) -> int:
    try:
        parsed = int(str(value).strip())
    except (TypeError, ValueError, AttributeError):
        return default
    return max(minimum, min(parsed, maximum))


def _load_gpt_commenter_settings() -> dict[str, Any]:
    keys = (
        Setting.GPT_COMMENTER_PROMPT,
        Setting.GPT_COMMENTER_STATUSES,
        Setting.GPT_COMMENTER_INITIAL_STATUS,
        Setting.GPT_COMMENTER_MAX_PER_LISTING,
        Setting.GPT_COMMENTER_MAX_PER_RUN,
        Setting.GPT_COMMENTER_TARGET_CAR_IDS,
    )
    with DBSession(admin_engine) as session:
        rows = session.exec(
            text(
                "SELECT key,value FROM settings WHERE key IN (:prompt,:statuses,:initial,:per_listing,:per_run,:car_ids)"
            ).bindparams(
                prompt=keys[0],
                statuses=keys[1],
                initial=keys[2],
                per_listing=keys[3],
                per_run=keys[4],
                car_ids=keys[5],
            )
        ).mappings().all()
    data = {row["key"]: row["value"] for row in rows}
    prompt_value = str(data.get(Setting.GPT_COMMENTER_PROMPT) or "").strip()
    statuses_raw = data.get(Setting.GPT_COMMENTER_STATUSES)
    if statuses_raw:
        parts = re.split(r"[\n,]+", str(statuses_raw))
        selected_statuses = gpt_commenter.normalize_statuses(parts)
    else:
        selected_statuses = []
    initial_status = str(
        data.get(Setting.GPT_COMMENTER_INITIAL_STATUS) or CommentStatus.PENDING.value
    ).strip().lower()
    if initial_status not in {CommentStatus.PENDING.value, CommentStatus.APPROVED.value}:
        initial_status = CommentStatus.PENDING.value
    per_listing = _clamp_int(
        data.get(Setting.GPT_COMMENTER_MAX_PER_LISTING),
        default=gpt_commenter.MAX_PER_LISTING_CAP,
        minimum=1,
        maximum=gpt_commenter.MAX_PER_LISTING_CAP,
    )
    per_run = _clamp_int(
        data.get(Setting.GPT_COMMENTER_MAX_PER_RUN),
        default=10,
        minimum=1,
        maximum=gpt_commenter.MAX_PER_RUN_CAP,
    )
    car_ids_raw = data.get(Setting.GPT_COMMENTER_TARGET_CAR_IDS)
    if car_ids_raw:
        id_parts = re.split(r"[\n\s,]+", str(car_ids_raw))
        target_car_ids = gpt_commenter.normalize_car_ids(id_parts)
    else:
        target_car_ids = []
    target_car_ids_text = "\n".join(str(value) for value in target_car_ids)
    return {
        "prompt": prompt_value,
        "selected_statuses": selected_statuses,
        "initial_status": initial_status,
        "max_per_listing": per_listing,
        "max_per_run": per_run,
        "preview_car_id": "",
        "target_car_ids": target_car_ids,
        "target_car_ids_text": target_car_ids_text,
    }


def _coerce_gpt_commenter_form(
    prompt: str | None,
    statuses: Iterable[str] | None,
    initial_status: str | None,
    max_per_listing: str | None,
    max_per_run: str | None,
    preview_car_id: str | None,
    target_car_ids: str | None,
) -> dict[str, Any]:
    prompt_value = (prompt or "").strip()
    selected_statuses = gpt_commenter.normalize_statuses(statuses or [])
    status_choice = str(initial_status or "").strip().lower()
    if status_choice not in {CommentStatus.PENDING.value, CommentStatus.APPROVED.value}:
        status_choice = CommentStatus.PENDING.value
    per_listing = _clamp_int(
        max_per_listing,
        default=gpt_commenter.MAX_PER_LISTING_CAP,
        minimum=1,
        maximum=gpt_commenter.MAX_PER_LISTING_CAP,
    )
    per_run = _clamp_int(
        max_per_run,
        default=10,
        minimum=1,
        maximum=gpt_commenter.MAX_PER_RUN_CAP,
    )
    preview_value = str(preview_car_id or "").strip()
    car_ids_text = str(target_car_ids or "").replace("\n", ",")
    raw_car_id_tokens = [
        part.strip()
        for part in car_ids_text.split(",")
        if part.strip()
    ]
    normalized_car_ids = gpt_commenter.normalize_car_ids(raw_car_id_tokens)
    normalized_car_ids_text = "\n".join(str(value) for value in normalized_car_ids)
    return {
        "prompt": prompt_value,
        "selected_statuses": selected_statuses,
        "initial_status": status_choice,
        "max_per_listing": per_listing,
        "max_per_run": per_run,
        "preview_car_id": preview_value,
        "target_car_ids": normalized_car_ids,
        "target_car_ids_text": normalized_car_ids_text,
    }


def _persist_gpt_commenter_settings(values: Mapping[str, Any]) -> None:
    selected_statuses = gpt_commenter.normalize_statuses(values.get("selected_statuses", []))
    status_text = "\n".join(selected_statuses)
    target_car_ids = gpt_commenter.normalize_car_ids(values.get("target_car_ids", []))
    target_car_ids_text = "\n".join(str(value) for value in target_car_ids)
    updates = {
        Setting.GPT_COMMENTER_PROMPT: values.get("prompt", ""),
        Setting.GPT_COMMENTER_STATUSES: status_text,
        Setting.GPT_COMMENTER_INITIAL_STATUS: values.get(
            "initial_status", CommentStatus.PENDING.value
        ),
        Setting.GPT_COMMENTER_MAX_PER_LISTING: str(
            values.get("max_per_listing", gpt_commenter.MAX_PER_LISTING_CAP)
        ),
        Setting.GPT_COMMENTER_MAX_PER_RUN: str(values.get("max_per_run", 10)),
        Setting.GPT_COMMENTER_TARGET_CAR_IDS: target_car_ids_text,
    }
    with DBSession(admin_engine) as session:
        for key, value in updates.items():
            session.exec(
                text(
                    "INSERT INTO settings(key,value) VALUES(:k,:v) ON CONFLICT(key) DO UPDATE SET value=:v"
                ).bindparams(k=key, v=value)
            )
        session.commit()


_GPTCOMMENTER_STATUS_LABEL_OVERRIDES: dict[str, str] = {
    "ACTIVE": "Active listing",
    "AUCTION_IN_PROGRESS": "Auction in progress",
}

_GPTCOMMENTER_STATUS_DESCRIPTIONS: dict[str, str] = {
    "ACTIVE": "Active listing that is currently visible to shoppers.",
    "AUCTION_IN_PROGRESS": "Live auction with an active countdown and open bidding.",
}


def _gptcommenter_status_label(value: str | None) -> str:
    canonical = gpt_commenter.canonicalize_status(value)
    if canonical:
        if canonical in _GPTCOMMENTER_STATUS_LABEL_OVERRIDES:
            return _GPTCOMMENTER_STATUS_LABEL_OVERRIDES[canonical]
        cleaned = canonical.replace("_", " ").strip()
        if cleaned:
            return " ".join(part.capitalize() for part in cleaned.split())
    if not value:
        return "Unknown"
    normalized = str(value or "").strip().upper()
    if not normalized:
        return "Unknown"
    cleaned = normalized.replace("_", " ").strip()
    if not cleaned:
        return "Unknown"
    return " ".join(part.capitalize() for part in cleaned.split())


def _gptcommenter_template_context(
    request: Request,
    current,
    *,
    form_override: Mapping[str, Any] | None = None,
    preview: dict | None = None,
    errors: list[str] | None = None,
):
    form_state = _load_gpt_commenter_settings()
    if form_override:
        merged = dict(form_state)
        merged.update({
            "prompt": form_override.get("prompt", form_state["prompt"]),
            "initial_status": form_override.get("initial_status", form_state["initial_status"]),
            "max_per_listing": form_override.get("max_per_listing", form_state["max_per_listing"]),
            "max_per_run": form_override.get("max_per_run", form_state["max_per_run"]),
        })
        if "selected_statuses" in form_override:
            merged["selected_statuses"] = list(form_override["selected_statuses"])
        if "preview_car_id" in form_override:
            merged["preview_car_id"] = str(form_override["preview_car_id"] or "")
        if "target_car_ids" in form_override:
            merged["target_car_ids"] = list(form_override["target_car_ids"])
        if "target_car_ids_text" in form_override:
            merged["target_car_ids_text"] = str(form_override["target_car_ids_text"] or "")
        form_state = merged
    with DBSession(engine) as session:
        status_column = func.upper(
            func.coalesce(Car.auction_status_column(), literal(""))
        )
        count_rows = session.exec(
            select(
                status_column,
                func.count(),
            )
            .select_from(Comment)
            .join(Car, Car.id == Comment.car_id, isouter=True)
            .where(Comment.automation_source == gpt_commenter.AUTOMATION_SOURCE)
            .group_by(status_column)
        ).all()
        counts: dict[str, int] = {
            status: 0 for status in gpt_commenter.ALLOWED_STATUS_CODES
        }
        for status_value, total in count_rows:
            canonical = gpt_commenter.canonicalize_status(status_value)
            if not canonical:
                continue
            counts[canonical] = counts.get(canonical, 0) + int(total or 0)
        selected_statuses = [
            status
            for status in form_state.get("selected_statuses", [])
            if status in gpt_commenter.ALLOWED_STATUS_CODES
        ]
        ordered_statuses: list[str] = []
        seen: set[str] = set()
        for status in selected_statuses:
            if status not in seen:
                seen.add(status)
                ordered_statuses.append(status)
        for status in gpt_commenter.ALLOWED_STATUS_CODES:
            if status not in seen:
                seen.add(status)
                ordered_statuses.append(status)
        status_options = [
            {
                "value": status,
                "label": _gptcommenter_status_label(status),
                "selected": status in selected_statuses,
                "count": counts.get(status, 0),
            }
            for status in ordered_statuses
        ]
        status_guides: list[dict[str, str]] = [
            {
                "value": status,
                "label": _gptcommenter_status_label(status),
                "description": _GPTCOMMENTER_STATUS_DESCRIPTIONS[status],
            }
            for status in gpt_commenter.ALLOWED_STATUS_CODES
            if status in _GPTCOMMENTER_STATUS_DESCRIPTIONS
        ]
        delete_options = [option for option in status_options if option["count"]]
        recent_rows = session.exec(
            select(Comment, Car)
            .select_from(Comment)
            .join(Car, Car.id == Comment.car_id, isouter=True)
            .where(Comment.automation_source == gpt_commenter.AUTOMATION_SOURCE)
            .order_by(Comment.created_at.desc())
            .limit(10)
        ).all()
        recent_comments: list[dict[str, Any]] = []
        for comment, car in recent_rows:
            car_id = getattr(comment, "car_id", None)
            car_title_candidates = [
                getattr(car, "title", None),
                " ".join(
                    str(part)
                    for part in [
                        getattr(car, "year", None),
                        getattr(car, "make", None),
                        getattr(car, "model", None),
                        getattr(car, "trim", None),
                    ]
                    if part
                ),
                f"Listing #{car_id}" if car_id else None,
            ]
            car_title = next((value for value in car_title_candidates if value), None)
            recent_comments.append(
                {
                    "id": getattr(comment, "id", None),
                    "body": getattr(comment, "body", ""),
                    "created_label": _format_admin_timestamp(comment.created_at),
                    "status": _comment_status_to_string(comment.status) or "",
                    "car_id": car_id,
                    "car_title": car_title,
                    "car_status": getattr(car, "auction_status", None),
                    "car_status_label": _gptcommenter_status_label(
                        getattr(car, "auction_status", None)
                    ),
                    "car_url": getattr(car, "url", None),
                    "flagged": bool(getattr(comment, "flagged", False)),
                    "flagged_reason": getattr(comment, "flagged_reason", None),
                }
            )
    total_comments = sum(counts.values())
    counts_with_values = {key: value for key, value in counts.items() if value}
    return {
        "request": request,
        "title": "GPTCommenter",
        "csrf": csrf_token(request),
        "flash": pop_flash(request),
        "form_data": form_state,
        "status_options": status_options,
        "status_guides": status_guides,
        "delete_status_options": delete_options,
        "gpt_comment_counts": counts_with_values,
        "gpt_comment_total": total_comments,
        "recent_comments": recent_comments,
        "preview": preview,
        "form_errors": errors or [],
        "status_label": _gptcommenter_status_label,
        "current_user": current,
    }


