@app.post("/admin/gptcommenter/preview", response_class=HTMLResponse)
async def admin_gptcommenter_preview(
    request: Request,
    csrf: str = Form(...),
    gpt_prompt: str = Form(""),
    statuses: list[str] = Form([]),
    initial_status: str = Form("pending"),
    max_per_listing: str = Form("5"),
    max_per_run: str = Form("10"),
    preview_car_id: str = Form(""),
    target_car_ids: str = Form(""),
    current=Depends(admin_section_required("gptcommenter")),
):
    require_csrf(request, csrf)
    form_state = _coerce_gpt_commenter_form(
        gpt_prompt,
        statuses,
        initial_status,
        max_per_listing,
        max_per_run,
        preview_car_id,
        target_car_ids,
    )
    _persist_gpt_commenter_settings(form_state)
    errors: list[str] = []
    preview_car: int | None = None
    if form_state["preview_car_id"]:
        try:
            preview_car = int(form_state["preview_car_id"])
        except ValueError:
            errors.append("Preview listing ID must be a number")
    if not form_state["selected_statuses"]:
        errors.append("Select at least one listing status to preview")
    preview_payload: dict | None = None
    status_code = 200
    if not errors:
        try:
            preview_payload = await anyio.to_thread.run_sync(
                lambda: gpt_commenter.preview_comment(
                    engine,
                    statuses=form_state["selected_statuses"],
                    prompt=form_state["prompt"],
                    preferred_car_id=preview_car,
                    car_ids=form_state["target_car_ids"],
                )
            )
        except gpt_commenter.GPTCommenterError as exc:
            errors.append(str(exc))
            status_code = 502
    context = _gptcommenter_template_context(
        request,
        current,
        form_override=form_state,
        preview=preview_payload,
        errors=errors,
    )
    if errors and status_code == 200:
        status_code = 400
    return templates.TemplateResponse(
        request,
        "admin_gptcommenter.html",
        context,
        status_code=status_code,
    )


@app.post("/admin/gptcommenter/run")
async def admin_gptcommenter_run(
    request: Request,
    csrf: str = Form(...),
    gpt_prompt: str = Form(""),
    statuses: list[str] = Form([]),
    initial_status: str = Form("pending"),
    max_per_listing: str = Form("5"),
    max_per_run: str = Form("10"),
    preview_car_id: str = Form(""),
    target_car_ids: str = Form(""),
    current=Depends(admin_section_required("gptcommenter")),
):
    require_csrf(request, csrf)
    form_state = _coerce_gpt_commenter_form(
        gpt_prompt,
        statuses,
        initial_status,
        max_per_listing,
        max_per_run,
        preview_car_id,
        target_car_ids,
    )
    _persist_gpt_commenter_settings(form_state)
    if not form_state["selected_statuses"]:
        context = _gptcommenter_template_context(
            request,
            current,
            form_override=form_state,
            errors=["Select at least one listing status before starting GPTCommenter"],
        )
        return templates.TemplateResponse(
            request,
            "admin_gptcommenter.html",
            context,
            status_code=400,
        )
    try:
        summary = await anyio.to_thread.run_sync(
            lambda: gpt_commenter.run_commenter(
                engine,
                statuses=form_state["selected_statuses"],
                prompt=form_state["prompt"],
                initial_status=form_state["initial_status"],
                max_per_listing=form_state["max_per_listing"],
                max_total=form_state["max_per_run"],
                car_ids=form_state["target_car_ids"],
            )
        )
    except gpt_commenter.GPTCommenterError as exc:
        context = _gptcommenter_template_context(
            request,
            current,
            form_override=form_state,
            errors=[str(exc)],
        )
        return templates.TemplateResponse(
            request,
            "admin_gptcommenter.html",
            context,
            status_code=502,
        )
    created_count = int(summary.get("created_count", 0) or 0)
    skipped_count = len(summary.get("skipped", []))
    error_entries = summary.get("errors", [])
    if created_count:
        flash(
            request,
            f"GPTCommenter created {created_count} comment{'s' if created_count != 1 else ''}",
            "success",
        )
    else:
        flash(request, "GPTCommenter did not create new comments this run", "info")
    if skipped_count:
        flash(
            request,
            f"Skipped {skipped_count} listing{'s' if skipped_count != 1 else ''} (already at limit or duplicate)",
            "info",
        )
    if error_entries:
        latest_error = error_entries[-1].get("message") or "Unexpected error"
        flash(
            request,
            f"{len(error_entries)} error{'s' if len(error_entries) != 1 else ''} occurred. Latest: {latest_error}",
            "error",
        )
    return RedirectResponse("/admin/gptcommenter", status_code=303)


@app.post("/admin/gptcommenter/delete")
def admin_gptcommenter_delete(
    request: Request,
    csrf: str = Form(...),
    delete_scope: str = Form("all"),
    delete_statuses: list[str] = Form([]),
    delete_car_ids: str = Form(""),
    current=Depends(admin_section_required("gptcommenter")),
):
    require_csrf(request, csrf)
    normalized_statuses = gpt_commenter.normalize_statuses(delete_statuses)
    raw_delete_car_ids = [
        part.strip()
        for part in str(delete_car_ids or "").replace("\n", ",").split(",")
        if part.strip()
    ]
    normalized_car_ids = gpt_commenter.normalize_car_ids(raw_delete_car_ids)
    try:
        if delete_scope == "status":
            if not normalized_statuses:
                flash(request, "Select at least one status to delete", "error")
                return RedirectResponse("/admin/gptcommenter", status_code=303)
            removed = gpt_commenter.delete_comments(engine, statuses=normalized_statuses)
        elif delete_scope == "car_ids":
            if not normalized_car_ids:
                flash(request, "Enter at least one listing ID to delete", "error")
                return RedirectResponse("/admin/gptcommenter", status_code=303)
            removed = gpt_commenter.delete_comments(engine, car_ids=normalized_car_ids)
        else:
            removed = gpt_commenter.delete_comments(engine)
    except Exception as exc:  # pragma: no cover - defensive logging
        flash(request, f"Unable to delete GPTCommenter comments: {exc}", "error")
        return RedirectResponse("/admin/gptcommenter", status_code=303)
    if removed:
        flash(
            request,
            f"Deleted {removed} GPTCommenter comment{'s' if removed != 1 else ''}",
            "success",
        )
    else:
        flash(request, "No GPTCommenter comments matched the selection", "info")
    return RedirectResponse("/admin/gptcommenter", status_code=303)


